window.HADITH_CACHE["darimi_5"] = {"2501":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ لَا يَتَوَارَثُ مِلَّتَانِ شَتَّى وَلَا يَحْجُبُ مَنْ لَا يَرِثُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Anas bin Sirin] ia berkata; [Umar bin Al Khaththab] berkata; Dua pemeluk agama yang berbeda tidak dapat saling mewarisi dan orang yang tidak dapat mewarisi tidak dapat menghalangi ahli waris lain."},"2502":{"ar":" حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Ali bin Husain] dari [Amr bin Utsman] dari [Usamah bin Zaid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang muslim tidak dapat mewarisi harta orang kafir dan orang kafir tidak dapat mewarisi harta orang muslim.\""},"2503":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ قَالَ إِذَا مَاتَ الْمَيِّتُ وَجَبَتْ الْحُقُوقُ لِأَهْلِهَا وَلَمْ يَجْعَلْ لِمَنْ أَسْلَمَ أَوْ أُعْتِقَ قَبْلَ أَنْ يُقْسَمَ الْمِيرَاثُ شَيْئًا","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Sa'id] dari [Abu Ma'syar] dari [Ibrahim] ia berkata; Jika seseorang meninggal dunia maka hak-hak wajib diberikan kepada orang-orang yang berhak menerimanya. Sedikit pun bagian harta tidak diberikan kepada orang yang masuk Islam atau orang yang dimerdekakan sebelum warisan dibagikan."},"2504":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Amr bin 'Aun] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ali bin Husain] dari [Amr bin Utsman] dari [Usamah bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang muslim tidak dapat mewarisi harta orang kafir dan orang kafir tidak dapat mewarisi harta orang muslim.\""},"2505":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ لَيْسَ لِلْمُكَاتَبِ مِيرَاثٌ مَا بَقِيَ عَلَيْهِ شَيْءٌ مِنْ مُكَاتَبَتِهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Mughirah] dari [Ibrahim] ia berkata; Mukatab tidak memperoleh warisan selama masih ada sisa pembayaran dari mukatabnya yang belum dilunasi. "},"2506":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي رَجُلٍ لَهُ بَنُونَ قَدْ أَعْتَقَ مِنْ بَعْضِهِمْ النِّصْفَ وَمِنْ بَعْضِهِمْ الثُّلُثَ وَمِنْ بَعْضٍ الرُّبُعَ قَالَ لَا يَرِثُونَ حَتَّى يُعْتَقُوا","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] tentang seseorang yang memiliki beberapa budak, sebagian mereka telah ia merdekakan setengah (dari harga budak), sebagian lagi telah ia merdekakan sepertiga (dari harga budak) dan sebagian lainnya telah ia merdekakan seperempat (dari harga budak). Ia berkata; Mereka tidak dapat mewarisi hingga mereka dimerdekakan."},"2507":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ وَسَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ فِي رَجُلٍ اشْتَرَى ابْنَهُ فِي مَرَضِهِ قَالَ إِنْ خَرَجَ مِنْ الثُّلُثِ وَرِثَهُ وَإِنْ وَقَعَتْ عَلَيْهِ السِّعَايَةُ لَمْ يَرِثْ","id":"Telah menceritakan kepada kami [Abdul Ja'far Ar Ruqqi] dan [Sa'ib bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Hammad] dari [Ibrahim] tentang seorang laki-laki yang membeli budaknya pada waktu sakitnya, ia berkata; Jika ia telah membayar sepertiga maka budak itu dapat mewarisinya, namun jika masih melakukan pekerjaan maka ia tidak dapat diwarisi."},"2508":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ أَبِيهِ عَنْ الشَّعْبِيِّ قَالَ حَدُّ الْمُكَاتَبِ حَدُّ الْمَمْلُوكِ حَتَّى يُعْتَقَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [ayahnya] dari [Asy Sya'bi] ia berkata; Hukuman bagi mukatab sama dengan hukuman seorang budak hingga ia telah merdeka."},"2509":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَوْلَى أَخٌ فِي الدِّينِ وَنِعْمَةٌ أَحَقُّ النَّاسِ بِمِيرَاثِهِ أَقْرَبُهُمْ مِنْ الْمُعْتِقِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Sa'id bin Abdurrahman] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Mantan budak adalah saudara dalam agama dan anugerah kenikmatan. Orang yang paling berhak dengan warisannya adalah orang yang memerdekakannya yang paling dekat dengannya.\""},"2510":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبَّادٌ عَنْ عُمَرَ بْنِ عَامِرٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي رَجُلٍ تَرَكَ أَبَاهُ وَابْنَ ابْنِهِ فَقَالَ الْوَلَاءُ لِابْنِ الِابْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami ['Abbad] dari [Umar bin Amir] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Zaid bin Tsabit] tentang seorang anak laki-laki yang meninggalkan ayah dan anak laki-laki dari anak laki-lakinya, ia berkata; Wala` untuk anak laki-laki dari anak laki-laki. "},"2511":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُعَمَّرٌ حَدَّثَنَا خُصَيْفٌ عَنْ زِيَادِ بْنِ أَبِي مَرْيَمَ أَنَّ امْرَأَةً أَعْتَقَتْ عَبْدًا لَهَا ثُمَّ تُوُفِّيَتْ وَتَرَكَتْ ابْنَهَا وَأَخَاهَا ثُمَّ تُوُفِّيَ مَوْلَاهَا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنُ الْمَرْأَةِ وَأَخُوهَا فِي مِيرَاثِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثُهُ لِابْنِ الْمَرْأَةِ فَقَالَ أَخُوهَا يَا رَسُولَ اللَّهِ لَوْ أَنَّهُ جَرَّ جَرِيرَةً عَلَى مَنْ كَانَتْ قَالَ عَلَيْكَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Mu'ammar] telah menceritakan kepada kami [Khushaif] dari [Ziyad bin Abu Maryam] bahwa seorang perempuan memerdekakan budak miliknya kemudian perempuan itu meninggal dunia dan meninggalkan anak laki-laki dan saudara laki-lakinya. Setelah itu mantan budaknya meninggal dunia. Anak laki-laki dan saudara laki-laki perempuan itu menemui Nabi shallallahu 'alaihi wasallam menanyakan tentang warisan mantan budak tersebut. Maka Nabi shallallahu 'alaihi wasallam: \"Warisannya untuk anak laki-laki perempuan itu.\" Saudara laki-laki perempuan itu berkata; Wahai Rasulullah, seandainya mantan budak itu melakukan kejahatan maka siapa yang menanggung diyat kejahatannya? Beliau menjawab: \"kamu.\""},"2512":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا هُشَيْمٌ عَنْ شُعْبَةَ قَالَ سَمِعْتُ الْحَكَمَ وَحَمَّادًا يَقُولَانِ هُوَ لِلِابْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Husyaim] dari [Syu'bah] ia berkata; Aku mendengar [Al Hakam] dan [Hammad] keduanya berkata; Warisan itu diberikan kepada anak laki-laki."},"2513":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ الْحَسَنِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْبَقِيعِ فَرَأَى رَجُلًا يُبَاعُ فَأَتَاهُ فَسَاوَمَ بِهِ ثُمَّ تَرَكَهُ فَرَآهُ رَجُلٌ فَاشْتَرَاهُ فَأَعْتَقَهُ ثُمَّ جَاءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي اشْتَرَيْتُ هَذَا فَأَعْتَقْتُهُ فَمَا تَرَى فِيهِ فَقَالَ هُوَ أَخُوكَ وَمَوْلَاكَ قَالَ مَا تَرَى فِي صُحْبَتِهِ فَقَالَ إِنْ شَكَرَكَ فَهُوَ خَيْرٌ لَهُ وَشَرٌّ لَكَ وَإِنْ كَفَرَكَ فَهُوَ خَيْرٌ لَكَ وَشَرٌّ لَهُ قَالَ مَا تَرَى فِي مَالِهِ قَالَ إِنْ مَاتَ وَلَمْ يَتْرُكْ عَصَبَةً فَأَنْتَ وَارِثُهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Asy'ats] dari [Al Hasan] bahwa Nabi shallallahu 'alaihi wasallam pernah pergi ke Baqi' kemudian beliau melihat seorang budak laki-laki yang dijual. Beliau mendatangi lalu menawarnya kemudian beliau meninggalkannya. Setelah itu ada seseorang melihatnya lalu membeli dan memerdekakannya. Kemudian ia datang membawa mantan budak tersebut kepada Nabi shallallahu 'alaihi wasallam seraya berkata; Sesungguhnya aku telah membeli budak ini lalu memerdekakannya, apa pendapatmu tentangnya? Nabi shallallahu 'alaihi wasallam menjawab: \"Ia adalah saudaramu dan mantan budakmu.\" Ia bertanya lagi; Apa pendapatmu tentang berteman dengannya? Beliau menjawab: \"Jika ia bisa berterima kasih kepadamu maka itu baik baginya namun buruk bagimu dan jika ia ingkar terhadapmu maka itu baik bagimu namun buruk baginya.\" Ia bertanya lagi; Apa pendapatmu tentang hartanya? Beliau menjawab: \"Jika ia meninggal dunia dan tidak meninggalkan ashabah maka engkau adalah ahli warisnya.\""},"2514":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَشْعَثُ عَنْ الْحَكَمِ وَسَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ أَنَّ ابْنَةَ حَمْزَةَ أَعْتَقَتْ عَبْدًا لَهَا فَمَاتَ وَتَرَكَ ابْنَتَهُ وَمَوْلَاتَهُ بِنْتَ حَمْزَةَ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثَهُ بَيْنَ ابْنَتِهِ وَمَوْلَاتِهِ بِنْتِ حَمْزَةَ نِصْفَيْنِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Asy'ats] dari [Al Hakam] dan [Salamah bin Kuhail] dari [Abdullah bin Syaddad] bahwa anak perempuan Hamzah telah memerdekakan seorang budak laki-laki miliknya lalu mantan budaknya meninggal dunia dan meninggalkan anak perempuan dan tuannya, yakni anak perempuan Hamzah. Maka Rasulullah shallallahu 'alaihi wasallam membagi warisan budak yang telah dimerdekakan tersebut kepada anak perempuannya dan tuannya, masing-masing setengah (bagian)."},"2515":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ أَبِي الْكَنُودِ عَنْ عَلِيٍّ أَنَّهُ أُتِيَ بِابْنَةٍ وَمَوْلًى فَأَعْطَى الِابْنَةَ النِّصْفَ وَالْمَوْلَى النِّصْفَ قَالَ الْحَكَمُ فَمَنْزِلِي هَذَا نَصِيبُ الْمَوْلَى الَّذِي وَرِثَهُ عَنْ مَوْلَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Ibnu Abu Laila] dari [Al Hakam] dari [Abu Al Kanud] dari [Ali] bahwa ia pernah ditanya tentang seorang anak perempuan dan mantan budak. Maka ia memberikan kepada anak perempuan dan mantan budak tersebut masing-masing setengah. Al Hakam berkata; Menurutku, ini adalah bagian mantan budak yang diwarisi dari orang yang memerdekakannya."},"2516":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ ابْنِ إِدْرِيسَ عَنْ أَشْعَثَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُدْلِجٍ أَنَّهُ مَاتَ وَتَرَكَ ابْنَتَهُ وَمَوَالِيَهُ فَأَعْطَى عَلِيٌّ ابْنَتَهُ النِّصْفَ وَمَوَالِيَهُ النِّصْفَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] dari [Ibnu Idris] dari [Asy'ats] dari [Al Hakam] dari [Abdurrahman bin Mudlij] bahwa ada seorang budak meninggal dunia dan meninggalkan seorang anak perempuan dan orang yang memerdekakannya, maka [Ali] memberikan kepada anak perempuan itu setengah dan kepada para mantan budak ayahnya itu setengah."},"2517":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ حَدَّثَنَا أَشْعَثُ عَنْ جَهْمِ بْنِ دِينَارٍ عَنْ إِبْرَاهِيمَ أَنَّهُ سُئِلَ عَنْ أُخْتَيْنِ اشْتَرَتْ إِحْدَاهُمَا أَبَاهَا فَأَعْتَقَتْهُ ثُمَّ مَاتَ قَالَ لَهُمَا الثُّلُثَانِ فَرِيضَتُهُمَا فِي كِتَابِ اللَّهِ وَمَا بَقِيَ فَلِلْمُعْتِقَةِ دُونَ الْأُخْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Hafsh bin Ghiyats] telah menceritakan kepada kami [Asy'ats] dari [Jahm bin Dinar] dari [Ibrahim] bahwa ia pernah ditanya tentang salah satu dari dua saudara perempuan yang membeli ayahnya lalu memerdekakannya kemudian ayahnya tersebut meninggal dunia. Ia menjawab; Mereka berdua mendapat dua pertiga sebagai bagian yang telah ditetapkan untuk keduanya dalam kitab Allah dan harta yang tersisa adalah untuk yang memerdekakannya bukan untuk yang lain."},"2518":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا الْأَشْعَثُ عَنْ الشَّعْبِيِّ فِي امْرَأَةٍ أَعْتَقَتْ أَبَاهَا فَمَاتَ الْأَبُ وَتَرَكَ أَرْبَعَ بَنَاتٍ هِيَ إِحْدَاهُنَّ قَالَ لَيْسَ عَلَيْهِ مِنَّةٌ لَهُنَّ الثُّلُثَانِ وَهِيَ مَعَهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Isra`il] telah menceritakan kepada kami [Al Asy'ats] dari [Asy Sya'bi] tentang seorang perempuan yang memerdekakan ayahnya, lalu ayah tersebut meninggal dunia dan meninggalkan empat anak perempuan, salah satu dari mereka adalah yang memerdekakannya. Ia menjawab; Ayah tidak boleh melebihkan (bagian), mereka mendapat dua pertiga termasuk yang memerdekakan."},"2519":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ حَيَّانَ بْنِ سَلْمَانَ قَالَ كُنْتُ عِنْدَ سُوَيْدِ بْنِ غَفَلَةَ فَجَاءَهُ رَجُلٌ فَسَأَلَهُ عَنْ فَرِيضَةِ رَجُلٍ تَرَكَ ابْنَتَهُ وَامْرَأَتَهُ قَالَ أَنَا أُنْبِئُكَ قَضَاءَ عَلِيٍّ قَالَ حَسْبِي قَضَاءُ عَلِيٍّ قَالَ قَضَى عَلِيٌّ لِامْرَأَتِهِ الثُّمُنَ وَلِابْنَتِهِ النِّصْفَ ثُمَّ رَدَّ الْبَقِيَّةَ عَلَى ابْنَتِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Hayyan bin Salman] ia berkata; Ketika aku bersama [Suwaid bin Ghafalah], datang seorang laki-laki dan bertanya kepadanya tentang warisan seseorang yang meninggalkan anak perempuan dan isterinya; Aku beritahukan apakah itu keputusan Ali? Ia menjawab; Menurutku (cukup dengan) keputusan Ali. Ia melanjutkan; [Ali] memutuskan untuk isteri seperdelapan dan anak perempuan setengah kemudian ia mengembalikan sisanya kepada anak perempuan."},"2520":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي الْهَيْثَمِ عَنْ إِبْرَاهِيمَ أَنَّ مَوْلَاةً لِإِبْرَاهِيمَ تُوُفِّيَتْ وَتَرَكَتْ مَالًا فَقُلْتُ لِإِبْرَاهِيمَ فَقَالَ إِنَّ لَهَا ذَا قَرَابَةٍ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Abu Al Haitsam] dari [Ibrahim] bahwa seorang mantan budak perempuan Ibrahim meninggal dunia dan meninggalkan harta. Maka aku menanyakannya kepada Ibrahim, ia pun menjawab; Sesungguhnya ia masih memiliki kekerabatan."},"2521":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا أَشْعَثُ عَنْ الشَّعْبِيِّ عَنْ عُمَرَ وَعَلِيٍّ وَزَيْدٍ قَالَ وَأَحْسَبُهُ قَدْ ذَكَرَ عَبْدَ اللَّهِ أَيْضًا أَنَّهُمْ قَالُوا الْوَلَاءُ لِلْكُبْرِ يَعْنُونَ بِالْكُبْرِ مَا كَانَ أَقْرَبَ بِأَبٍ أَوْ أُمٍّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Asy'ats] dari [Asy Sya'bi] dari [Umar], [Ali] dan [Zaid]. Ia berkata; Dan aku mengira juga dikatakan oleh [Abdullah]. Mereka berkata; Wala` untuk yang lebih tua. Menurut mereka, yang dimaksud lebih tua adalah yang lebih dekat dengan ayah atau ibu."},"2522":{"ar":" حَدَّثَنَا يَزِيدُ حَدَّثَنَا أَشْعَثُ عَنْ ابْنِ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ كُتِبَ إِلَى عُمَرَ فِي شَأْنِ فُكَيْهَةَ بِنْتِ سَمْعَانَ أَنَّهَا مَاتَتْ وَتَرَكَتْ ابْنَ أَخِيهَا لِأَبِيهَا وَأُمِّهَا وَابْنَ أَخِيهَا لِأَبِيهَا فَكَتَبَ عُمَرُ إِنَّ الْوَلَاءَ لِلْكُبْرِ","id":"Telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Asy'ats] dari [Ibnu Sirin] dari [Abdullah bin Utbah] ia berkata; Sebuah surat dikirim kepada Umar tentang perihal Fukaihah binti Sam'an yang meninggal dunia dan meninggalkan seorang anak laki-laki dari saudara laki-laki seayah dan seibu serta seorang anak laki-laki dari saudara laki-laki seayah. Maka [Umar] membalas surat tersebut; Sesungguhnya wala` untuk yang lebih tua."},"2523":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ أَنَّ عَلِيًّا وَزَيْدًا قَالَا الْوَلَاءُ لِلْكُبْرِ و قَالَ عَبْدُ اللَّهِ وَشُرَيْحٌ لِلْوَرَثَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Asy Syaibani] dari [Asy Sya'bi] bahwa [Ali] dan [Zaid] berkata; Wala` untuk yang lebih tua. Sementara [Abdullah] dan [Syuraih] berkata; Untuk ahli waris."},"2524":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ الشَّعْبِيِّ قَالَ قَضَى عُمَرُ وَعَبْدُ اللَّهِ وَعَلِيٌّ وَزَيْدٌ لِلْكُبْرِ بِالْوَلَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Asy Sya'bi] ia berkata; [Umar], [Abdullah], [Ali] dan [Zaid] memutuskan bahwa wala` untuk yang lebih tua."},"2525":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ أَشْعَثَ عَنْ ابْنِ سِيرِينَ قَالَ تُوُفِّيَتْ فُكَيْهَةُ بِنْتُ سَمْعَانَ وَتَرَكَتْ ابْنَ أَخِيهَا لِأَبِيهَا وَبَنِي بَنِي أَخِيهَا لِأَبِيهَا وَأُمِّهَا فَوَرَّثَ عُمَرُ بَنِي أَخِيهَا لِأَبِيهَا ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Asy'ats] dari [Ibnu Sirin] ia berkata; Fukaihah binti Sam'an meninggal dunia dan meninggalkan seorang anak laki-laki dari saudara laki-laki seayah dan anak laki-laki dari anak laki-laki (cucu laki-laki) dari saudara laki-laki seayah dan seibu. Maka [Umar] memberikan warisan kepada anak laki-laki dari saudara laki-laki seayah."},"2526":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عُمَرَ وَعَلِيٍّ وَزَيْدٍ أَنَّهُمْ قَالُوا الْوَلَاءُ لِلْكُبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Al A'masy] dari [Ibrahim] dari [Umar], [Ali] dan [Zaid] bahwa mereka berkata; Wala` untuk yang lebih tua."},"2527":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ فِي أَخَوَيْنِ وَرِثَا مَوْلًى كَانَ أَعْتَقَهُ أَبُوهُمَا فَمَاتَ أَحَدُهُمَا وَتَرَكَ وَلَدًا قَالَ كَانَ عَلِيٌّ وَزَيْدٌ وَعَبْدُ اللَّهِ يَقُولُونَ الْوَلَاءُ لِلْكُبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Ibrahim] tentang dua saudara laki-laki yang mewarisi mantan budak yang telah dimerdekakan ayah mereka. Lalu salah seorang dari dua saudara itu meninggal dunia dan meninggalkan seorang anak laki-laki, ia berkata; [Ali], [Zaid] dan [Abdullah] berkata; Wala` untuk yang lebih tua."},"2528":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ سَمِعْتُ مَطَرًا الْوَرَّاقَ يَقُولُ قَالَ عُمَرُ وَعَلِيٌّ الْوَلَاءُ لِلْكُبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Hammad bin Zaid] ia berkata; Aku mendengar [Mathar Al Warraq] berkata; [Umar] dan [Ali] berkata; Wala` untuk yang lebih tua."},"2529":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى عَنْ رَوْحٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ وَابْنِ جُرَيْجٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ قَالَ الْوَلَاءُ لِلْكُبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] dari [Rauh] dari [Ibnu Juraij] dari ['Atha`] dan Ibnu Juraij juga dari [Ibnu Thawus] dari [ayahnya] ia berkata; Wala` untuk yang lebih tua."},"2530":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ الْوَلَاءُ لِلْكُبْرِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Manshur] dari [Ibrahim] ia berkata; Wala` untuk yang lebih tua."},"2531":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ وَسُفْيَانُ عَنْ يُونُسَ عَنْ الْحَسَنِ فِي الرَّجُلِ يُوَالِي الرَّجُلَ قَالَا هُوَ بَيْنَ الْمُسْلِمِينَ قَالَ سُفْيَانُ وَكَذَلِكَ نَقُولُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Mutharrif] dari [Asy Sya'bi] dan Sufyan dari [Yunus] dari [Al Hasan] tentang seseorang menjadikan wali untuk orang lain, keduanya berkata; Ia sama dengan kaum muslimin lainnya. Sufyan berkata; Kami juga berpendapat seperti itu."},"2532":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ سَمِعْتُ تَمِيمًا الدَّارِيَّ يَقُولُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا السُّنَّةُ فِي الرَّجُلِ مِنْ أَهْلِ الْكُفْرِ يُسْلِمُ عَلَى يَدَيْ رَجُلٍ مِنْ الْمُسْلِمِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdul Aziz bin Umar bin Abdul Aziz] dari [Abdullah bin Mauhab] ia berkata; Aku pernah mendengar [Tamim Ad Dari] berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam; Wahai Rasulullah, apa yang sunnah dilakukan terhadap seorang kafir yang masuk Islam di hadapan seorang muslim? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Seseorang itu (orang kafir yang masuk Islam) lebih berhak dengan hidup dan matinya.\""},"2533":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ سُئِلَ عَنْ رَجُلٍ مِنْ أَهْلِ السَّوَادِ أَسْلَمَ عَلَى يَدَيْ رَجُلٍ قَالَ يَعْقِلُ عَنْهُ وَيَرِثُهُ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] ia berkata; Ia pernah ditanya tentang seorang laki-laki dari ahli kegelapan yang masuk Islam di hadapan seseorang? Ia menjawab; Laki-laki membayar diyat orang tersebut dan ia berhak mewarisinya."},"2534":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ تَرِثُ الْمَرْأَةُ مِنْ دِيَةِ زَوْجِهَا فِي الْعَمْدِ وَالْخَطَإِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Mughirah] dari [Ibrahim] ia berkata; Isteri berhak mewarisi diyat suaminya pada pembunuhan sengaja maupun tidak sengaja."},"2535":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ الدِّيَةُ عَلَى فَرَائِضِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Ibrahim] ia berkata; Diyat dibagikan berdasarkan pembagian yang telah ditetapkan Allah."},"2536":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَ الدِّيَةُ سَبِيلُهَا سَبِيلُ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] ia berkata; Cara pembagian diyat sama dengan cara pembagian harta warisan."},"2537":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ وَدَاوُدَ بْنِ أَبِي هِنْدٍ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ كَتَبَ أَنْ يُوَرَّثَ الْإِخْوَةُ مِنْ الْأُمِّ مِنْ الدِّيَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dan [Dawud bin Abu Hind] bahwa [Umar bin Abdul Aziz] menetapkan bahwa para saudara laki-laki seibu mewarisi diyat."},"2538":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ الْعَقْلُ مِيرَاثٌ بَيْنَ وَرَثَةِ الْقَتِيلِ عَلَى كِتَابِ اللَّهِ وَفَرَائِضِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah bercerita kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; Diyat adalah warisan yang dibagikan di antara ahli waris korban yang terbunuh sesuai dengan kitab Allah dan pembagian yang telah ditetapkanNya."},"2539":{"ar":" حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ بَعْضِ وَلَدِ ابْنِ الْحَنَفِيَّةِ عَنْ عَلِيٍّ قَالَ لَقَدْ ظَلَمَ مَنْ لَمْ يُوَرِّثْ الْإِخْوَةَ مِنْ الْأُمِّ مِنْ الدِّيَةِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Amr bin Dinar] dari [sebagian anak Ibnu Al Hanafiyyah] dari [Ali] ia berkata; Sungguh telah melakukan kezhaliman orang yang tidak memberikan hak waris dari harta diyat kepada para saudara laki-laki seibu."},"2540":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ أَخْبَرَنَا ابْنُ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ ��ُمَرَ وَعَلِيٍّ وَزَيْدٍ قَالُوا الدِّيَةُ تُورَثُ كَمَا يُورَثُ الْمَالُ خَطَؤُهُ وَعَمْدُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] telah mengabarkan kepada kami [Ibnu Salim] dari [Asy Sya'bi] dari [Umar], [Ali] dan [Zaid]. Mereka berkata; Diyat dapat diwarisi sebagaimana harta yang dapat diwarisi, baik diyat pembunuhan yang tidak disengaja maupun yang disengaja."},"2541":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ قَالَ كَانَ عَلِيٌّ لَا يُوَرِّثُ الْإِخْوَةَ مِنْ الْأُمِّ وَلَا الزَّوْجَ وَلَا الْمَرْأَةَ مِنْ الدِّيَةِ شَيْئًا قَالَ عَبْد اللَّهِ بَعْضُهُمْ يُدْخِلُ بَيْنَ إِسْمَعِيلَ وَعَامِرٍ رَجُلًا","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Isma'il] dari [Amir] ia berkata; [Ali] tidak memberikan hak waris sedikitpun kepada para saudara laki-laki seibu, suami dan isteri dari diyat. Abdullah berkata; Sebagian mereka memasukkan seseorang (perawi dalam sanad hadits) di antara Isma'il dan Amir."},"2542":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ زِيَادٍ الْأَعْلَمِ عَنْ الْحَسَنِ قَالَ لَا يُوَرَّثُ الْإِخْوَةُ مِنْ الْأُمِّ مِنْ الدِّيَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dari [Hammad bin Salamah] dari [Ziyad Al A'lam] dari [Al Hasan] ia berkata; Saudara laki-laki seibu tidak dapat mewarisi harta yang berasal dari diyat."},"2543":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ كُلُّ قَوْمٍ مُتَوَارِثِينَ عَمِيَ مَوْتُهُمْ فِي هَدْمٍ أَوْ غَرَقٍ فَإِنَّهُمْ لَا يَتَوَارَثُونَ يَرِثُهُمْ الْأَحْيَاءُ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [ayahnya] dari [Kharijah bin Zaid] dari [Zaid bin Tsabit] ia berkata; Setiap orang yang berhak mewarisi (dari harta) yang meninggal dunia karena tertimpa reruntuhan atau tenggelam, maka mereka tidak dapat saling mewarisi. Tetapi ahli waris yang hidup dapat mewarisi mereka."},"2544":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ عَتِيقٍ قَالَ قَرَأْتُ فِي بَعْضِ كُتُبِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فِي الْقَوْمِ يَقَعُ عَلَيْهِمْ الْبَيْتُ لَا يُدْرَى أَيُّهُمَا مَاتَ قَبْلُ قَالَ لَا يُوَرَّثُ الْأَمْوَاتُ بَعْضُهُمْ مِنْ بَعْضٍ وَيُوَرَّثُ الْأَحْيَاءُ مِنْ الْأَمْوَاتِ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin 'Atiq] ia berkata; Aku pernah membaca sebagian surat untuk [Umar bin Abdul Aziz] tentang beberapa orang yang tertimpa reruntuhan rumah, tidak diketahui siapa di antara mereka yang lebih dahulu meninggal dunia. Ia menjawab; Orang-orang yang meninggal dunia tidak dapat saling mewarisi sebagian dengan sebagian lain namun ahli waris yang masih hidup dapat mewarisi orang-orang yang telah meninggal dunia."},"2545":{"ar":" حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ حَدَّثَنَا جَعْفَرٌ عَنْ أَبِيهِ أَنَّ أُمَّ كُلْثُومٍ وَابْنَهَا زَيْدًا مَاتَا فِي يَوْمٍ وَاحِدٍ فَالْتَقَتْ الصَّائِحَتَانِ فِي الطَّرِيقِ فَلَمْ يَرِثْ كُلُّ وَاحِدٍ مِنْهُمَا مِنْ صَاحِبِهِ وَأَنَّ أَهْلَ الْحَرَّةِ لَمْ يَتَوَارَثُوا وَأَنَّ أَهْلَ صِفِّينَ لَمْ يَتَوَارَثُوا","id":"Telah menceritakan kepada kami [Nu'aim bin Hammad] dari [Abdul Aziz bin Muhammad] telah menceritakan kepada kami [Ja'far] dari [ayahnya] bahwa Ummu Kultsum dan anak laki-lakinya, Zaid, keduanya meninggal dunia pada hari yang sama. Lalu ada dua orang yang berteriak di jalan bertemu, namun masing-masing dari keduanya tidak dapat mewarisi. Orang-orang yang meninggal dunia pada peristiwa Harrah tidak dapat saling mewarisi dan orang-orang yang meninggal dunia pada peristiwa Shiffin juga tidak dapat saling mewarisi."},"2546":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا ابْنُ أَبِي لَيْلَى عَنْ الشَّعْبِيِّ أَنَّ بَيْتًا بِالشَّامِ وَقَعَ عَلَى قَوْمٍ فَوَرَّثَ عُمَرُ بَعْضَهُمْ مِنْ بَعْضٍ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Ibnu Abu Laila] dari [Asy Sya'bi] bahwa di Syam ada sebuah rumah runtuh dan menimpa penghuninya. Maka [Umar] memberikan warisan kepada sebagian mereka dari sebagian lainnya."},"2547":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ حُرَيْشٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ أَنَّهُ وَرَّثَ أَخَوَيْنِ قُتِلَا بِصِفِّينَ أَحَدَهُمَا مِنْ الْآخَرِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Huraisy] dari [ayahnya] dari [Ali] bahwa ia memberikan hak waris kepada dua orang laki-laki bersaudara yang terbunuh pada peristiwa Shiffin. Salah satu dari mereka dapat mewarisi yang lain."},"2548":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ أَنَّ رَجُلًا هَلَكَ وَتَرَكَ عَمَّتَهُ وَخَالَتَهُ فَأَعْطَى عُمَرُ الْعَمَّةَ نَصِيبَ الْأَخِ وَأَعْطَى الْخَالَةَ نَصِيبَ الْأُخْتِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Humaid] dari [Bakr bin Abdullah Al Muzani] bahwa ada seorang laki-laki meninggal dunia dan meninggalkan seorang bibi dari pihak ayah dan bibi dari pihak ibu. Maka [Umar] memberikan bagian kepada bibi dari pihak ayah seperti bagian saudara laki-laki dan memberikan kepada bibi dari pihak ibu seperti bagian saudara perempuan."},"2549":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ مَنْ أَدْلَى بِرَحِمٍ أُعْطِيَ بِرَحِمِهِ الَّتِي يُدْلِي بِهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari [Ibrahim] ia berkata; Barangsiapa yang mempunyai hubungan satu rahim, maka ia diberikan warisan dengan sebab hubungan satu rahim yang menyebabkan ia terhubung."},"2550":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ الشَّيْبَانِيُّ عَنْ الشَّعْبِيِّ فِي رَجُلٍ تَرَكَ عَمَّتَهُ وَابْنَةَ أَخِيهِ قَالَ الْمَالُ لِابْنَةِ أَخِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] ia berkata; telah menceritakan kepadaku [Abu Ishaq Asy Syaibani] dari [Asy Sya'bi] tentang seorang laki-laki yang meninggalkan seorang bibi dari pihak ayah dan anak perempuan dari saudara laki-laki, ia berkata; Harta diberikan kepada anak perempuan dari saudara laki-laki."},"2551":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ لَيْثٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَالُ وَارِثٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Laits] dari [Muhammad bin Munkadir] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, Beliau bersabda: \"Paman dari pihak ibu adalah ahli waris.\""},"2552":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ عُبَيْدَةَ عَنْ إِبْرَاهِيمَ أَنَّ عُمَرَ وَعَبْدَ اللَّهِ رَأَيَا أَنْ يُوَرِّثَا خَالًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Ubaidah] dari [Ibrahim] bahwa [Umar] dan [Abdullah] berpendapat bahwa bibi dari pihak ibu dapat mewarisi."},"2553":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ سُلَيْمَانَ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ فِي عَمَّةٍ وَبِنْتِ أَخٍ قَالَ الْمَالُ لِابْنَةِ الْأَخِ حَدَّثَنَا أَبُو نُعَيْمٍ أَخْبَرَنَا حَسَنٌ عَنْ سُلَيْمَانَ عَنْ بَعْضِهِمْ عَنْ إِبْرَاهِيمَ قَالَ لِلْعَمَّةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Sulaiman Abu Ishaq] dari [Asy Sya'bi] tentang bibi dari pihak ibu dan anak perempuan dari saudara laki-laki, ia berkata; Harta warisan diberikan kepada anak perempuan dari saudara laki-laki. Telah menceritakan kepada kami [Abu Nu'aim] telah mengabarkan kepada kami [Hasan] dari [Sulaiman] dari [sebagian mereka] dari [Ibrahim] ia berkata; Harta tersebut diberikan kepada bibi dari pihak ayah."},"2554":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ فِي بِنْتِ أَخٍ وَعَمَّةٍ قَالَ أَعْطِي الْمَالَ لِابْنَةِ الْأَخِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Asy Syaibani] dari [Asy Sya'bi] tentang anak perempuan dari saudara laki-laki dan bibi dari pihak ayah, ia berkata; Harta diberikan kepada anak perempuan dari saudara laki-laki."},"2555":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا يُونُسُ عَنْ عَامِرٍ قَالَ كَانَ مَسْرُوقٌ يُنَزِّلُ الْعَمَّةَ بِمَنْزِلَةِ الْأَبِ إِذَا لَمْ يَكُنْ أَبٌ وَالْخَالَةَ بِمَنْزِلَةِ الْأُمِّ إِذَا لَمْ تَكُنْ أُمٌّ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Yunus] dari [Amir] ia berkata; [Masruq] menempatkan bibi dari pihak ayah sama pada kedudukan ayah jika mayit tidak memiliki ayah dan bibi dari pihak ibu pada kedudukan ibu jika mayit tidak memiliki ibu."},"2556":{"ar":" حَدَّثَنَا يَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ حَبَّانَ نَسَبَهُ إِلَى جَدِّهِ عَنْ عَمِّهْ وَاسِعِ بْنِ حَبَّانَ قَالَ تُوُفِّيَ ابْنُ الدَّحْدَاحَةِ وَكَانَ أَتِيًّا وَهُوَ الَّذِي لَا يُعْرَفُ لَهُ أَصْلٌ فَكَانَ فِي بَنِي الْعَجْلَانِ وَلَمْ يَتْرُكْ عَقِبًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَاصِمِ بْنِ عَدِيٍّ هَلْ تَعْلَمُونَ لَهُ فِيكُمْ نَسَبًا قَالَ مَا نَعْرِفُهُ يَا رَسُولَ اللَّهِ فَدَعَا ابْنَ أُخْتِهِ فَأَعْطَاهُ مِيرَاثَهُ","id":"Telah menceritakan kepada kami [Ya'la] dari [Muhammad bin Ishaq] dari [Muhammad bin Habban] ia menisbatkan kepada kakeknya dari pamannya [Wasi' bin Habban] ia berkata; Ibnu Ad-Dahdahah meninggal dan ia adalah seorang pendatang yang tidak dikenali asal usul keturunannya, ia tinggal di Bani Al-'Ajlan dan tidak meninggalkan seorang anak. Maka Rasulullah shallallahu 'alaihi wasallam bertanya kepada 'Ashim bin Adi; \"Apakah kalian mengetahui ia memiliki hubungan nasab dengan kalian?\" Ia menjawab; Kami tidak tahu, wahai Rasulullah. Maka beliau memanggil anak laki-laki dari saudara perempuannya dan kepada anak laki-laki dari saudara perempuannya tersebut beliau memberikan harta warisannya."},"2557":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو هَانِئٍ قَالَ سُئِلَ عَامِرٌ عَنْ امْرَأَةٍ أَوْ رَجُلٍ تُوُفِّيَ وَتَرَكَ خَالَةً وَعَمَّةً لَيْسَ لَهُ وَارِثٌ وَلَا رَحِمٌ غَيْرُهُمَا فَقَالَ كَانَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ يُنَزِّلُ الْخَالَةَ بِمَنْزِلَةِ أُمِّهِ وَيُنَزِّلُ الْعَمَّةَ بِمَنْزِلَةِ أَخِيهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Hani`] ia berkata; [Amir] pernah ditanya tentang seorang perempuan atau laki-laki yang meninggal dunia dan meninggalkan seorang bbi dari pihak ibu dan seorang bibi dari pihak ayah. Tidak ada seorang ahli waris dan orang yang satu rahim pun selain mereka berdua. Maka ia berkata; [Abdullah Mas'ud] menempatkan bibi dari pihak ibu pada kedudukan ibu dan bibi dari pihak ayah pada kedudukan saudara laki-laki."},"2558":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَمْرٍو عَنْ الْحَسَنِ فِي رَجُلٍ اعْتَرَفَ عِنْدَ مَوْتِهِ بِأَلْفِ دِرْهَمٍ لِرَجُلٍ وَأَقَامَ آخَرُ بَيِّنَةً بِأَلْفِ دِرْهَمٍ وَتَرَكَ الْمَيِّتُ أَلْفَ دِرْهَمٍ فَقَالَ الْمَالُ بَيْنَهُمَا نِصْفَيْنِ إِلَّا أَنْ يَكُونَ مُفْلِسًا فَلَا يَجُوزُ إِقْرَارُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Amr] dari [Al Hasan] tentang seorang laki-laki ketika meninggal dunia mengaku mempunyai hutang seribu dirham kepada seseorang dan ada orang lain yang memberikan bukti bahwa ia (si mayit) juga mempunyai hutang seribu dirham kepadanya. Sementara si mayit tersebut hanya meninggalkan harta seribu dirham, ia berkata; Harta itu dibagi dua, masing-masing mendapat setengah, kecuali jika si mayit adalah orang yang tidak punya harta maka pengakuannya tidak dibenarkan."},"2559":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ قَالَ قُلْتُ لِشَرِيكٍ كَيْفَ ذَكَرْتَ فِي الْأَخَوَيْنِ يَدَّعِي أَحَدُهُمَا أَخًا قَالَ يَدْخُلُ عَلَيْهِ فِي نَصِيبِهِ قُلْتُ مَنْ ذَكَرَهُ قَالَ جَابِرٌ عَنْ عَامِرٍ عَنْ عَلِيٍّ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] ia berkata; Aku bertanya kepada [Syarik]; Bagaimana riwayat yang engkau sebutkan tentang dua saudara laki-laki yang salah satunya mengaku sebagai saudara? Ia menjawab; Orang yang mengaku ini masuk dalam bagian saudara. Aku bertanya; Siapa yang meriwayatkannya? Ia menjawab; [Jabir] dari [Amir] dari [Ali]."},"2560":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ فِي الْإِخْوَةِ يَدَّعِي بَعْضُهُمْ الْأَخَ وَيُنْكِرُ الْآخَرُونَ قَالَ يَدْخُلُ مَعَهُمْ بِمَنْزِلَةِ عَبْدٍ يَكُونُ بَيْنَ الْإِخْوَةِ فَيَعْتِقَ أَحَدُهُمْ نَصِيبَهُ قَالَ وَكَانَ عَامِرٌ وَالْحَكَمُ وَأَصْحَابُهُمَا يَقُولُونَ لَا يَدْخُلُ إِلَّا فِي نَصِيبِ الَّذِي اعْتَرَفَ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahman bin Muhammad Al Muharibi] dari [Al A'masy] dari [Ibrahim] tentang para saudara laki-laki di mana sebagian mereka mengaku sebagai saudara dan sebagian lainnya tidak mengaku sebagai saudara, ia berkata; Saudara yang tidak mengaku sebagai saudara masuk bersama mereka seperti seorang budak yang dimiliki beberapa saudara, lalu salah seorang dari mereka tersebut memerdekakan bagiannya. Ia berkata lagi; [Amir], [Hakam] dan para sahabat mereka berkata; Ia tidak masuk kecuali dalam bagian saudara yang mengaku sebagai saudaranya."},"2561":{"ar":" حَدَّثَنَا أَبُو بَكْرٍ عَنْ وَكِيعٍ قَالَ إِذَا كَانَا أَخَوَيْنِ فَادَّعَى أَحَدُهُمَا أَخًا وَأَنْكَرَهُ الْآخَرُ قَالَ كَانَ ابْنُ أَبِي لَيْلَى يَقُولُ هِيَ مِنْ سِتَّةٍ لِلَّذِي لَمْ يَدَّعِ ثَلَاثَةٌ وَلِلْمُدَّعِي سَهْمَانِ وَلِلْمُدَّعَى سَهْمٌ","id":"Telah menceritakan kepada kami [Abu Bakr] dari [Waki'] ia berkata; Jika ada dua orang bersaudara, lalu salah satunya mengaku sebagai saudara dan yang lainnya tidak mengaku sebagai saudara, [Ibnu Abu Laila] berkata; Pembagian warisannya dari enam. Orang yang tidak mengaku mendapat tiga bagian, orang yang mengakui mendapat dua bagian dan orang yang diakui mendapatkan satu bagian."},"2562":{"ar":" حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ حَمَّادٍ فِي الرَّجُلِ يَكُونُ لَهُ ثَلَاثَةُ بَنِينَ فَقَالَ ثُلُثِي لِأَصْغَرِ بَنِيَّ فَقَالَ الْأَوْسَطُ أَنَا أُجِيزُ وَقَالَ الْأَكْبَرُ لَا أُجِيزُ قَالَ هِيَ مِنْ تِسْعَةٍ يُخْرِجُ ثُلُثَهُ فَلَهُ سَهْمُهُ وَسَهْمُ الَّذِي أَجَازَ وَقَالَ حَمَّادٌ يَرُدُّ السَّهْمَ عَلَيْهِمْ جَمِيعًا وَقَالَ عَامِرٌ الَّذِي رَدَّ إِنَّمَا رَدَّ عَلَى نَفْسِهِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Hammad] tentang seorang laki-laki yang memiliki tiga orang anak laki-laki. Laki-laki itu pun berkata; Sepertiga hartaku untuk anakku yang bungsu. Anak kedua berkata; Aku membolehkan dan anak yang sulung berkata; Aku tidak membolehkan. Ia menjawab; Pembagian warisan ini dari sembilan. Dikeluarkan sepertiganya, yang tidak membolehkan mendapat bagiannya dan satu bagian untuk yang membolehkan. Hammad berkata; Bagian dikembalikan kepada mereka. Sedangkan [Amir] berkata; Orang yang menolak, sesungguhnya ia menolak atas dirinya sendiri."},"2563":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ شَرِيكٍ عَنْ خَالِدٍ عَنْ ابْنِ سِيرِينَ عَنْ شُرَيْحٍ فِي رَجُلٍ أَقَرَّ بِأَخٍ قَالَ بَيِّنَتُهُ أَنَّهُ أَخُوهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Syarik] dari [Khalid] dari [Ibnu Sirin] dari [Syuraih] tentang seseorang yang mengaku sebagai saudara mayit, ia berkata; Ia harus menunjukkan bukti bahwa ia adalah saudaranya."},"2564":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ الْحَارِثِ الْعُكْلِيِّ فِي رَجُلٍ أَقَرَّ عِنْدَ مَوْتِهِ بِأَلْفِ دِرْهَمٍ مُضَارَبَةً وَأَلْفٍ دَيْنًا وَلَمْ يَدَعْ إِلَّا أَلْفَ دِرْهَمٍ قَالَ يُبْدَأُ بِالدَّيْنِ فَإِنْ فَضَلَ فَضْلٌ كَانَ لِصَاحِبِ الْمُضَارَبَةِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Al Harits Al 'Ukli] tentang seseorang yang mengaku ketika hendak meninggal dunia bahwa ia memiliki pinjaman seribu dirham secara mudlarabah dan hutang seribu dirham. Tetapi ia tidak mengaku kecuali seribu dirham saja, ia berkata; Hutang dilunasi dahulu. Jika ada sisa (dari harta), maka diberikan kepada orang yang memberi pinjaman secara mudlarabah. "},"2565":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ فِي رَجُلٍ مَاتَ وَتَرَكَ ثَلَاثَ مِائَةِ دِرْهَمٍ وَثَلَاثَةَ بَنِينَ فَجَاءَ رَجُلٌ يَدَّعِي مِائَةَ دِرْهَمٍ عَلَى الْمَيِّتِ فَأَقَرَّ لَهُ أَحَدُهُمْ قَالَ يَدْخُلُ عَلَيْهِمْ بِالْحِصَّةِ ثُمَّ قَالَ الشَّعْبِيُّ مَا أُرَى أَنْ يَكُونَ مِيرَاثًا حَتَّى يُقْضَى الدَّيْنُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Mutharrif] dari [Asy Sya'bi] tentang seseorang yang meninggal dunia dan meninggalkan harta senilai tiga ratus dirham dan tiga orang anak laki-laki. Lalu ada seseorang mengakui si mayit berhutang seratus dirham kepadanya. Salah seorang dari anak-anaknya membenarkan pengakuan tersebut. Ia berkata; Hutang itu termasuk dalam bagian mereka yang membenarkan. Kemudian Asy Sya'bi berkata; Aku tidak berpendapat si mayit memiliki warisan hingga hutang dilunasi."},"2566":{"ar":" حَدَّثَنَا أَبُو خَيْثَمَةَ مُصْعَبُ بْنُ سَعِيدٍ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ عَنْ الْأَشْعَثِ عَنْ الْحَسَنِ فِي رَجُلٍ هَلَكَ وَتَرَكَ ابْنَيْنِ وَتَرَكَ أَلْفَيْ دِرْهَمٍ فَاقْتَسَمَا الْأَلْفَيْ دِرْهَمٍ وَغَابَ أَحَدُ الِابْنَيْنِ فَجَاءَ رَجُلٌ فَاسْتَحَقَّ عَلَى الْمَيِّتِ أَلْفَ دِرْهَمٍ قَالَ يَأْخُذُ جَمِيعَ مَا فِي يَدِ هَذَا الشَّاهِدِ وَيُقَالُ لَهُ اتَّبِعْ أَخَاكَ الْغَائِبَ وَخُذْ نِصْفَ مَا فِي يَدِهِ","id":"Telah menceritakan kepada kami [Abu Khaitsamah Mush'ab bin Sa'id Al Harrani] telah menceritakan kepada kami [Muhammad bin Abdullah] dari [Al Asy'ats] dari [Al Hasan] tentang seseorang yang meninggal dunia dan meninggalkan dua anak laki-laki dan harta senilai dua ribu dirham. Keduanya pun sepakat untuk membagi dua ribu dirham dan salah satunya pergi. Lalu ada seseorang datang dan menuntut hutang terhadap si mayit senilai seribu dirham. Ia berkata; Ia boleh mengambil semua yang ada di tangan anak laki-laki yang berada di tempat dan dikatakan kepadanya; Cari saudaramu yang pergi tersebut lalu ambil setengah dari apa yang ada di tangannya."},"2567":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ زِيَادٍ الْأَعْلَمِ عَنْ الْحَسَنِ قَالَ إِذَا أَقَرَّ بَعْضُ الْوَرَثَةِ بِدَيْنٍ فَهُوَ عَلَيْهِ بِحِصَّتِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dari [Hammad bin Salamah] dari [Ziyad Al A'lam] dari [Al Hasan] ia berkata; Jika sebagian ahli waris membenarkan si mayit memiliki hutang maka ahli waris tersebut harus melunasinya."},"2568":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ثَابِتُ بْنُ الْوَلِيدِ بْنِ جُمَيْعٍ قَالَ أَخْبَرَنِي أَبِي عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ كَانَ ابْنُ مَسْعُودٍ يُوَرِّثُ أَهْلَ الْمُرْتَدِّ إِذَا قُتِلَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Tsabit bin Al Walid bin Jumai'] ia berkata; telah mengabarkan kepada kami [ayahku] dari [Al Qasim bin Abdur Rahman] ia berkata; [Ibnu Mas'ud] memberikan hak waris kepada ahli waris orang murtad jika ia terbunuh."},"2569":{"ar":" حَدَّثَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ جَعَلَ مِيرَاثَ الْمُرْتَدِّ لِوَرَثَتِهِ مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Amr Asy Syaibani] bahwa [Ali bin Abu Thalib] menjadikan warisan orang murtad untuk ahli warisnya dari kaum muslimin."},"2570":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْحَجَّاجُ عَنْ الْحَكَمِ أَنَّ عَلِيًّا قَضَى فِي مِيرَاثِ الْمُرْتَدِّ لِأَهْلِهِ مِنْ الْمُسْلِمِينَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Al Hajjaj] dari [Al Hakam] bahwa [Ali] memutuskan warisan orang murtad untuk keluarganya dari kaum muslimin."},"2571":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ هُوَ ابْنُ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ الْحَكَمِ قَالَ إِذَا قَتَلَ الرَّجُلُ أَخَاهُ عَمْدًا لَمْ يُوَرَّثْ مِنْ مِيرَاثِهِ وَلَا مِنْ دِيَتِهِ فَإِذَا قَتَلَهُ خَطَأً وُرِّثَ مِنْ مِيرَاثِهِ وَلَمْ يُوَرَّثْ مِنْ دِيَتِهِ قَالَ وَكَانَ عَطَاءٌ يَقُولُ ذَلِكَ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami [Ubaidullah] ia adalah Ibnu Amr, dari [Abdul Karim] dari [Al Hakam] ia berkata; Jika seseorang membunuh saudaranya secara sengaja maka ia tidak dapat mewarisi harta warisan darinya dan tidak pula dari diyatnya. Namun jika ia membunuhnya secara tidak sengaja maka ia dapat mewarisi harta warisannya. Tetapi tidak dapat mewarisi diyatnya. Ia berkata lagi; [Atha`] berpendapat seperti itu."},"2572":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ عَلِيٍّ قَالَ رَمَى رَجُلٌ أُمَّهُ بِحَجَرٍ فَقَتَلَهَا فَطَلَبَ مِيرَاثَهُ مِنْ إِخْوَتِهِ فَقَالَ لَهُ إِخْوَتُهُ لَا مِيرَاثَ لَكَ فَارْتَفَعُوا إِلَى عَلِيٍّ فَجَعَلَ عَلَيْهِ الدِّيَةَ وَأَخْرَجَهُ مِنْ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Sa'id] dari [Qatadah] dari [Khilas] dari [Ali] ia berkata; Ada seseorang melempar ibunya dengan batu hingga membunuhnya, lalu orang tersebut meminta warisan kepada para saudaranya. Para saudaranya pun berkata kepadanya; Tidak ada warisan bagimu. Lalu mereka mengadukan masalah ini kepada Ali, ia pun memutuskan bahwa orang tersebut wajib membayar diyat dan dikeluarkan dari warisan."},"2573":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ الْحَسَنِ بْنِ الْحُرِّ عَنْ الْحَكَمِ أَنَّ الرَّجُلَ إِذَا قَتَلَ امْرَأَتَهُ خَطَأً أَنَّهُ يُمْنَعُ مِيرَاثَهُ مِنْ الْعَقْلِ وَغَيْرِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Al Hasan bin Al Hurr] dari [Al Hakam] bahwa jika seseorang membunuh isterinya secara tidak sengaja maka ia tidak dapat mewarisi baik dari harta diyat maupun lainnya."},"2574":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَا يَرِثُ الْقَاتِلُ مِنْ الْمَقْتُولِ شَيْئًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Mujahid] dari [Ibnu Abbas] ia berkata; Pembunuh tidak dapat mewarisi sedikit pun dari harta orang yang dibunuh."},"2575":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ فِي رَجُلٍ قَذَفَ امْرَأَتَهُ وَجَاءَ بِشُهُودٍ فَرُجِمَتْ قَالَ يَرِثُهَا","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Qatadah] tentang seorang laki-laki yang menuduh isterinya dan ia mendatangkan beberapa saksi lalu isterinya pun dirajam, ia berkata; Suami dapat mewarisi isterinya."},"2576":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حَمَّادٍ فِي رَجُلٍ جُلِدَ الْحَدَّ أَرَاهُ مَاتَ شَكَّ أَبُو النُّعْمَانِ قَالَ يَتَوَارَثَانِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Hammad] tentang seorang laki-laki yang dijatuhi hukuman dera, menurutku ia meninggal, Abu An Nu'man ragu, ia berkata; Mereka dapat saling waris mewarisi."},"2577":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ عَامِرٍ عَنْ عَلِيٍّ قَالَ الْقَاتِلُ لَا يَرِثُ وَلَا يَحْجُبُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Muhammad bin Salim] dari [Amir] dari [Ali] ia berkata; Pembunuh tidak dapat mewarisi dan tidak dapat menghalangi pembagian warisan."},"2578":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ لَيْثٍ عَنْ أَبِي عَمْرٍو الْعَبْدِيِّ عَنْ عَلِيٍّ قَالَ لَا يُوَرَّثُ الْقَاتِلُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Laits] dari [Abu Amr Al 'Abdi] dari [Ali] ia berkata; Pembunuh tidak dapat mewarisi."},"2579":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا أَبُو بَكْرٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ قَالَ قَالَ عُمَرُ لَا يَرِثُ قَاتِلٌ خَطَأً وَلَا عَمْدًا","id":"Telah menceritakan kepada kami [Zakariya bin Adi] telah menceritakan kepada kami [Abu Bakr] dari [Mutharrif] dari [Asy Sya'bi] ia berkata; [Umar] berkata; Pembunuh tidak berhak mewarisi, baik pembunuhan yang dilakukan secara tidak sengaja maupun secara sengaja."},"2580":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَا يَرِثُ الْقَاتِلُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Laits] dari [Thawus] dari [Ibnu Abbas] ia berkata; Pembunuh tidak dapat mewarisi."},"2581":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ إِذَا اجْتَمَعَ نَسَبَانِ وُرِّثَ بِأَكْبَرِهِمَا يَعْنِي الْمَجُوسَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] ia berkata; Jika dua nasab bergabung maka yang mewarisi adalah nasab yang lebih tua, yakni Majusi."},"2582":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَمَّادِ بْنِ أَبِي سُلَيْمَانَ قَالَ يَرِثُ مِنْ الْجَانِبِ الَّذِي يَصْلُحُ وَلَا يَرِثُ مِنْ الْجَانِبِ الَّذِي لَا يَصْلُحُ","id":"Telah menceritakan kepada kami [Hajjaj bin [Muhammad bin Al Minhal]] telah menceritakan kepada kami [Hammad bin Salamah] dari [Hammad bin Abu Sulaiman] ia berkata; Ia mewarisi dari pihak yang pantas dan tidak mewarisi dari pihak yang tidak pantas."},"2583":{"ar":" حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ رَجُلٍ عَنْ الشَّعْبِيِّ أَنَّ عَلِيًّا وَابْنَ مَسْعُودٍ قَالَا فِي الْمَجُوسِ إِذَا أَسْلَمُوا يَرِثُونَ مِنْ الْقَرَابَتَيْنِ جَمِيعًا","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Sufyan Ats Tsauri] dari [seseorang] dari [Asy Sya'bi] bahwa [Ali] dan [Ibnu Mas'ud] keduanya berkata tentang orang Majusi yang masuk Islam; Mereka berhak mewarisi dari dua kerabat semuanya."},"2584":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فِي امْرَأَةِ الْأَسِيرِ أَنَّهَا تَرِثُهُ وَيَرِثُهَا","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [ayahnya] dari [Umar bin Abdul Aziz] tentang seorang perempuan yang ditawan; Sesungguhnya ia dapat mewarisi suaminya dan suaminya dapat mewarisinya."},"2585":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنِي مَعْمَرٌ عَنْ إِسْحَقَ بْنِ رَاشِدٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فِي الْأَسِيرِ يُوصِي قَالَ أَجِزْ لَهُ وَصِيَّتَهُ مَا دَامَ عَلَى دِينِهِ لَمْ يَتَغَيَّرْ عَنْ دِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadlal] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepadaku [Ma'mar] dari [Ishaq bin Rasyid] dari [Umar bin Abdul Aziz] tentang tawanan yang berwasiat, ia berkata; Aku membolehkan wasiatnya selama ia masih memeluk agamanya dan tidak berubah dari agamanya tersebut."},"2586":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ شُرَيْحٍ قَالَ يُوَرَّثُ الْأَسِيرُ إِذَا كَانَ فِي أَيْدِي الْعَدُوِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Dawud] dari [Asy Sya'bi] dari [Syuraih] ia berkata; Orang yang ditawan berhak mewarisi sekalipun ia berada di tangan musuh."},"2587":{"ar":" حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مَنْ سَمِعَ إِبْرَاهِيمَ يَقُولُ يُوَرَّثُ الْأَسِيرُ","id":"Telah menceritakan kepada kami [Muhammad] ia berkata; Telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [orang yang mendengar] [Ibrahim] ia berkata; Orang yang ditawan berhak mewarisi."},"2588":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ دَاوُدَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ كَانَ لَا يُوَرِّثُ الْأَسِيرَ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Dawud] dari [Sa'id bin Al Musayyab] bahwa ia tidak memberikan hak waris kepada orang yang ditawan."},"2589":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْأَشْعَثُ عَنْ الشَّعْبِيِّ قَالَ كَتَبَ عُمَرُ بْنُ الْخَطَّابِ إِلَى شُرَيْحٍ أَنْ لَا يُوَرِّثَ الْحَمِيلَ إِلَّا بِبَيِّنَةٍ وَإِنْ جَاءَتْ بِهِ فِي خِرَقِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Al Asy'ats] dari [Asy Sya'bi] ia berkata; [Umar bin Al Khaththab] menulis surat kepada Syuraih, agar ia tidak memberikan hak waris kepada orang yang di bawa ke negeri Islam saat masih kecil kecuali ada bukti sekali pun ia datang dengan membawa kain-kain yang digunakannya saat masih kecil."},"2590":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ وَرِّثْ الْحَمِيلَ","id":"Telah mengabarkan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] ia berkata; Warisilah harta orang yang dibawa ke negeri Islam saat masih kecil."},"2591":{"ar":" حَدَّثَنَا أَبُو سَعِيدٍ مِنْ بَنِي أُمَيَّةَ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي مَرْيَمَ عَنْ ضَمْرَةَ وَالْفُضَيْلِ بْنِ فَضَالَةَ وَابْنِ أَبِي عَوْفٍ وَرَاشِدٍ وَعَطِيَّةَ قَالُوا لَا يُوَرَّثُ الْحُمَلَاءُ","id":"Telah menceritakan kepada kami [Abu Sa'id] dari bani Umayah dari [Abu Bakr bin Abdullah bin Abu Maryam] dari [Dlamrah], [Al Fudlail bin Fadlalah], [Ibnu Abu 'Auf], [Rasyid] dan ['Athiyah], mereka berkata; Warisan orang-orang yang dibawa ke negeri Islam saat masih kecil tidak dapat diwarisi."},"2592":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ قَالَ قَالَ ابْنُ الْمُبَارَكِ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ ذُكِرَ عِنْدَهُ قَوْلُ مَنْ يَقُولُ فِي الْحَمِيلِ فَأَنْكَرَ ذَلِكَ وَقَالَ قَدْ تَوَارَثَ الْمُهَاجِرُونَ وَالْأَنْصَارُ بِنَسَبِهِمْ الَّذِي كَانَ فِي الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] ia berkata; [Ibnu Al Mubarak] berkata; Telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] ia berkata; Disebutkan kepadanya ucapan orang yang berkata tentang orang yang dibawa ke negeri Islam saat masih kecil. Maka ia pun mengingkari hal itu dan berkata; Orang-orang Muhajirin dan Anshar saling mewarisi karena nasab keturunan mereka yang lahir pada masa jahiliyah."},"2593":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ عَنْ ابْنِ إِدْرِيسَ عَنْ هِشَامٍ عَنْ الْحَسَنِ وَابْنِ سِيرِينَ قَالَا لَا يُوَرَّثُ الْحَمِيلُ إِلَّا بِبَيِّنَةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dari [Ibnu Idris] dari [Hisyam] dari [Al Hasan] dan [Ibnu Sirin] keduanya berkata; Warisan orang yang dibawa ke negeri Islam saat masih kecil tidak dapat diwarisi kecuali jika ada bukti."},"2594":{"ar":" حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا جَرِيرٌ عَنْ لَيْثٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ لَمْ يَكُنْ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ يُوَرِّثُونَ الْحَمِيلَ","id":"Telah menceritakan kepada kami [Abu Bakr] telah menceritakan kepada kami [Jarir] dari [Laits] dari [Hammad] dari [Ibrahim] ia berkata; Abu Bakr, Umar dan Utsman tidak memberikan hak waris kepada orang yang dibawa ke negeri Islam saat masih kecil."},"2595":{"ar":" حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ الْمُحَارِبِيُّ عَنْ زَائِدَةَ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ قَالَ أَقَرَّتْ امْرَأَةٌ مِنْ مُحَارِبٍ جَلِيبَةٌ بِنَسَبٍ لَهَا جَلِيبٍ فَوَرَّثَهُ عَبْدُ اللَّهِ بْنُ عُتْبَةَ مِنْ أُخْتِهِ","id":"Telah menceritakan kepada kami [Abu Bakr] telah menceritakan kepada kami [Abdurrahim Al Muharibi] dari [Za`idah] dari [Asy'ats bin Abu Asy Sya'tsa`] ia berkata; Seorang perempuan dari Muharib yang dibawa paksa ke suatu negeri mengaku senasab dengan seseorang yang juga dibawa paksa ke negeri tersebut. Maka [Abdullah bin Utbah] memberikan hak waris kepada laki-laki tersebut dari warisan saudara perempuannya."},"2596":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ رَجُلٍ قَالَ عِنْدَ فِرَاقِ الدُّنْيَا أَنَا مَوْلَى فُلَانٍ قَالَ يَرِثُ مِيرَاثَهُ لِمَنْ سَمَّى أَنَّهُ مَوْلَاهُ عِنْدَ فِرَاقِ الدُّنْيَا إِلَّا أَنْ يَأْتُوا عَلَيْهِ بِبَيِّنَةٍ بِغَيْرِ ذَلِكَ يَرُدُّونَ بِهِ قَوْلَهُ فَيُرَدُّ مِيرَاثُهُ إِلَى مَا قَامَتْ بِهِ الْبَيِّنَةُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] tentang seseorang yang berkata ketika hendak meninggal dunia; Aku mantan budak fulan. Ia berkata; Warisannya diwariskan kepada orang yang disebutkan bahwa ia adalah majikannya ketika hendak meninggal kecuali mereka menunjukkan bukti yang membantah hal itu. Maka warisan dikembalikan kepada yang terbukti benar."},"2597":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ قَالَا وَلَدُ الزِّنَا بِمَنْزِلَةِ ابْنِ الْمُلَاعَنَةِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Muhammad bin Salim] dari [Asy Sya'bi] dari [Ali] dan [Abdullah] keduanya berkata; Warisan anak zina menempati kedudukan anak wanita yang terkena li'an."},"2598":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا رَوْحٌ عَنْ مُحَمَّدِ بْنِ أَبِي حَفْصَةَ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ أَنَّهُ كَانَ لَا يُوَرِّثُ وَلَدَ الزِّنَا وَإِنْ ادَّعَاهُ الرَّجُلُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Rauh] dari [Muhammad bin Abu Hafshah] dari [Az Zuhri] dari [Ali bin Husain] bahwa ia tidak memberikan hak waris kepada anak zina sekalipun seseorang mengakuinya sebagai anak."},"2599":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي بَكْرُ بْنُ مُضَرَ عَنْ عَمْرٍو يَعْنِي ابْنَ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ أَيُّمَا رَجُلٍ أَتَى إِلَى غُلَامٍ يَزْعُمُ أَنَّهُ ابْنٌ لَهُ وَأَنَّهُ زَنَى بِأُمِّهِ وَلَمْ يَدَّعِ ذَلِكَ الْغُلَامَ أَحَدٌ فَهُوَ يَرِثُهُ قَالَ بُكَيْرٌ وَسَأَلْتُ عُرْوَةَ عَنْ ذَلِكَ فَقَالَ مِثْلَ قَوْلِ سُلَيْمَانَ بْنِ يَسَارٍ وَقَالَ عُرْوَةُ بَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Bakr bin Mudlar] dari [Amru] yakni Ibnu Al Harits, dari [Bukair] dari [Sulaiman bin Yasar] ia berkata; Siapa pun orangnya yang mendatangi seorang anak lalu mengaku bahwa ia adalah anaknya dan mengaku bahwa ia telah berzina dengan ibunya, sementara tidak ada seorang pun yang mengaku anak tersebut sebagai anaknya, maka anak tersebut dapat mewarisinya. Bukair berkata; Aku pernah bertanya kepada [Urwah] tentang hal itu. Maka ia menjawab seperti perkataan Sulaiman bin Yasar. Urwah juga berkata; Telah sampai berita kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak adalah milik pemilik kasur (istri) dan (balasan) lelaki yang berzina adalah batu (dirajam).\""},"2600":{"ar":" حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ عَمْرٍو عَنْ الْحَسَنِ قَالَ ابْنُ الْمُلَاعَنَةِ مِثْلُ وَلَدِ الزِّنَا تَرِثُهُ أُمُّهُ وَوَرَثَتُهُ وَرَثَةُ أُمِّهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] dari [Hafsh bin Ghiyats] dari [Amr] dari [Al Hasan] ia berkata; Anak seorang wanita yang terkena li'an sama dengan anak zina. Ibunya dapat mewarisinya dan ahli warisnya adalah ahli waris ibunya."},"2601":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ أَوْ يُونُسَ عَنْ الزُّهْرِيِّ فِي أَوْلَادِ الزِّنَا قَالَ يَتَوَارَثُونَ مِنْ قِبَلِ الْأُمَّهَاتِ وَإِنْ وَلَدَتْ تَوْأَمًا فَمَاتَ وَرِثَ السُّدُسَ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ma'mar] atau [Yunus] dari [Az Zuhri] tentang anak-anak zina, ia berkata; Ahli waris dari jalur keturunan ibu dapat saling mewarisi, jika anak zina memperoleh anak lalu ia meninggal dunia maka anaknya mendapat harta warisan seperenam."},"2602":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ شِبَاكٍ عَنْ إِبْرَاهِيمَ قَالَ لَا يَرِثُ وَلَدُ الزِّنَا لَا يَرِثُ مَنْ لَمْ يُقَمْ عَلَى أَبِيهِ الْحَدُّ أَوْ تُمْلَكُ أُمُّهُ بِنِكَاحٍ أَوْ شِرَاءٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] ia berkata; Telah menceritakan kepada kami [Husyaim] dari [Mughirah] dari [Syibak] dari [Ibrahim] ia berkata; Anak zina tidak dapat mewarisi, tidak dapat mewarisi orang yang ayahnya tidak dijatuhi hukuman atau memiliki ibunya dengan cara dinikahi atau dibeli."},"2603":{"ar":" حَدَّثَنَا زَيْدُ بْنُ يَحْيَى عَنْ مُحَمَّدِ بْنِ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ لِكُلِّ مُسْتَلْحَقٍ اسْتُلْحِقَ بَعْدَ أَبِيهِ الَّذِي ادَّعَاهُ وَرَثَتُهُ بَعْدَهُ فَقَضَى إِنْ كَانَ مِنْ أَمَةٍ يَمْلِكُهَا يَوْمَ يَطَؤُهَا فَقَدْ لَحِقَ بِمَنْ اسْتَلْحَقَهُ وَلَيْسَ لَهُ مِمَّا قُسِمَ قَبْلَهُ مِنْ الْمِيرَاثِ شَيْءٌ وَمَا أَدْرَكَ مِنْ مِيرَاثٍ لَمْ يُقْسَمْ فَلَهُ نَصِيبُهُ وَلَا يَلْحَقُ إِذَا كَانَ الَّذِي يُدْعَى لَهُ أَنْكَرَهُ وَإِنْ كَانَ مِنْ أَمَةٍ لَا يَمْلِكُهَا أَوْ حُرَّةٍ عَاهَرَهَا فَإِنَّهُ لَا يَلْحَقُ وَلَا يَرِثُ وَإِنْ كَانَ الَّذِي يُدْعَى لَهُ هُوَ ادَّعَاهُ وَهُوَ وَلَدُ زِنَا لِأَهْلِ أُمِّهِ مَنْ كَانُوا حُرَّةً أَوْ أَمَةً","id":"Telah menceritakan kepada kami [Zaid bin Yahya] dari [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari [Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah memutuskan: \"Bahwa setiap orang yang menasabkan pada dirinya, maka ia dinisbatkan kepada ayahnya yang diakuinya dan ahli warisnya adalah setelahnya.\" Lalu beliau memutuskan: \"Jika ia berasal dari budak wanita yang dimiliki pada hari ia menggaulinya, maka ia mengikuti nasab orang yang diakui sebagai ayahnya dan sedikit pun ia tidak mendapat bagian harta warisan yang telah dibagikan sebelumnya. Sedangkan harta warisan yang belum dibagi, maka ia mendapat bagian darinya. Namun jika orang yang diakui sebagai ayahnya mengingkarinya maka ia tidak berhak mengikuti nasab kepadanya. dan jika ia berasal dari seorang budak yang bukan miliknya atau wanita merdeka yang dizinai maka ia tidak mengikuti nasab dan mendapat warisan. Meskipun orang yang diakui sebagai ayah itu mengakuinya. Ia tetap berstatus anak zina yang mengikuti keluarga ibunya, baik wanita merdeka maupun budak.\""},"2604":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ الْحَسَنِ عَنْ عُمَيْرِ بْنِ يَزِيدَ قَالَ سَأَلْتُ الشَّعْبِيَّ عَنْ مَمْلُوكٍ لِي وَلَدُ زِنًا قَالَ لَا تَبِعْهُ وَلَا تَأْكُلْ ثَمَنَهُ وَاسْتَخْدِمْهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] dari [Al Hasan] dari [Umair bin Yazid] ia berkata; Aku pernah bertanya kepada [Asy Sya'bi] tentang budakku yang terlahir dari hasil perzinaan. Ia menjawab; Jangan engkau jual dirinya dan makan uang hasil penjualannya tetapi perbantukanlah ia."},"2605":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ عَنْ سَعِيدٍ عَنْ الزُّهْرِيِّ سُئِلَ عَنْ وَلَدِ زِنَا يَمُوتُ قَالَ إِنْ كَانَ ابْنَ عَرَبِيَّةٍ وَرِثَتْ أُمُّهُ الثُّلُثَ وَجُعِلَ بَقِيَّةُ مَالِهِ فِي بَيْتِ الْمَالِ وَإِنْ كَانَ ابْنَ مَوْلَاةٍ وَرِثَتْ أُمُّهُ الثُّلُثَ وَوَرِثَ مَوَالِيهَا الَّذِينَ أَعْتَقُوهَا مَا بَقِيَ قَالَ مَرْوَانُ سَمِعْتُ مَالِكًا يَقُولُ ذَلِكَ","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] dari [Sa'id] dari [Az Zuhri] ia ditanya tentang anak zina yang meninggal, ia menjawab; Jika ia adalah anak Arab maka ibunya mendapat sepertiga harta warisan, sedangkan sisanya diserahkan ke Baitul Mal. Jika ia adalah anak budak maka ibunya mendapat sepertiga harta warisan, sedangkan sisa harta tersebut diberikan kepada majikannya yang telah memerdekakan ibunya. Marwan berkata; Aku telah mendengar [Malik] berpendapat seperti itu."},"2606":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ عَنْ مُوسَى بْنِ مُحَمَّدٍ الْأَنْصَارِيِّ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ حَصِيرَةَ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَلِيٍّ أَنَّهُ قَالَ فِي وَلَدِ الزِّنَا لِأَوْلِيَاءِ أُمِّهِ خُذُوا ابْنَكُمْ تَرِثُونَهُ وَتَعْقِلُونَهُ وَلَا يَرِثُكُمْ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] dari [Musa bin Muhammad Al Anshari] ia berkata; Telah menceritakan kepadaku [Al Harits bin Hashirah] dari [Zaid bin Wahb] dari [Ali] bahwa ia pernah berkata tentang warisan anak zina kepada wali-wali ibunya; Ambillah anak kalian. Kalian memperoleh warisannya dan membayar diyatnya tetapi ia tidak memperoleh warisan dari kalian."},"2607":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ وَعَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ قَالَ قَالَ عَبْدُ اللَّهِ السَّائِبَةُ يَضَعُ مَالَهُ حَيْثُ شَاءَ قَالَ عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ شُعْ��َةُ لَمْ يَسْمَعْ هَذَا مِنْ سَلَمَةَ أَحَدٌ غَيْرِي","id":"Telah mengabarkan kepada kami [Abu Nu'aim] dan [Abdullah bin Zaid] keduanya berkata; Telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] dari [Abu Amr Asy Syaibani] ia berkata; [Abdullah] berkata; Budak Sa`ibah menyerahkan hartanya ke mana pun ia mau. Abdullah bin Yazid berkata; Syu'bah berkata; Belum ada satu orang pun yang mendengar hal ini dari Salamah selain diriku. "},"2608":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ عَنْ يُونُسَ عَنْ الْحَسَنِ سُئِلَ عَنْ مِيرَاثِ السَّائِبَةِ فَقَالَ كُلُّ عَتِيقٍ سَائِبَةٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Hatim bin Wardan] dari [Yunus] dari [Al Hasan] ketika ia ditanya tentang warisan Sa`ibah, ia pun menjawab; Semua budak yang dimerdekakan adalah sa`ibah. "},"2609":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُلَيْمَانُ عَنْ أَبِي عُثْمَانَ قَالَ قَالَ عُمَرُ الصَّدَقَةُ وَالسَّائِبَةُ لِيَوْمِهِمَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Sulaiman] dari [Abu Utsman] ia berkata; [Umar] berkata; Sedekah dan sa`ibah diberikan pada harinya."},"2610":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ قَالَ سُئِلَ عَامِرٌ عَنْ الْمَمْلُوكِ يُعْتَقُ سَائِبَةً لِمَنْ وَلَاؤُهُ قَالَ لِلَّذِي أَعْتَقَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari [Amir] ia berkata; Ketika Amir ditanya tentang budak yang dimerdekakan dengan status Sa`ibah, kepada siapakah perwaliannya? Ia menjawab; Untuk orang yang memerdekakannya."},"2611":{"ar":" حَدَّثَنَا أَبُو حَاتِمٍ الْبَصْرِيُّ هُوَ رَوْحُ بْنُ أَسْلَمَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو قَالَ مَاتَ مَوْلًى عَلَى عَهْدِ عُثْمَانَ وَلَيْسَ لَهُ وَالٍ فَأَمَرَ بِمَالِهِ فَأُدْخِلَ بَيْتَ الْمَالِ","id":"Telah menceritakan kepada kami [Abu Hatim Al Bashri] ia adalah Rauh bin Aslam, telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [ayahnya] dari [Abdurrahman bin Amr] ia berkata; Pada masa pemerintahan [Utsman] ada seorang budak yang tidak memiliki wali meninggal dunia, lalu ia memerintahkan untuk mengambil hartanya dan diserahkan ke Baitul Mal."},"2612":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ فِي رَجُلٍ مَاتَ وَلَمْ يَكُنْ لَهُ مَوْلَى عَتَاقَةٍ قَالَ مَالُهُ حَيْثُ أَوْصَى بِهِ فَإِنْ لَمْ يَكُنْ أَوْصَى فَهُوَ فِي بَيْتِ الْمَالِ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari [Amir] dari [Masruq] tentang seseorang yang meninggal dunia namun tidak memiliki majikan yang memerdekakan, ia menjawab; Hartanya tergantung dengan wasiatnya, jika ia tidak berwasiat maka harta itu diserahkan ke Baitul Mal."},"2613":{"ar":" حَدَّثَنَا أَبُو سَعِيدِ بْنُ عَمْرٍو عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ ضَمْرَةَ وَرَاشِدِ بْنِ سَعْدٍ وَغَيْرِهِمَا قَالُوا فِيمَنْ أُعْتِقَ سَائِبَةً إِنَّ وَلَاءَهُ لِمَنْ أَعْتَقَهُ إِنَّمَا سَيَّبَهُ مِنْ الرِّقِّ وَلَمْ يُسَيِّبْهُ مِنْ الْوَلَاءِ","id":"Telah menceritakan kepada kami [Abu Sa'id bin Amr] dari [Abu Abu Bakr bin Abu Maryam] dari [Dlamrah], [Rasyid bin Sa'd] dan selain keduanya, mereka berkata tentang budak yang dimerdekakan dengan status sa`ibah; Sesungguhnya hak perwaliannya diberikan kepada orang yang memerdekakannya. Karena sesungguhnya ia hanya dibebaskan dari perbudakan namun tidak dibebaskan dari hak perwalian."},"2614":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مَنْصُورٌ عَنْ إِبْرَاهِيمَ وَالشَّعْبِيِّ قَالَا لَا بَأْسَ بِبَيْعِ وَلَاءِ السَّائِبَةِ وَهِبَتِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] ia berkata; Telah mengabarkan kepadaku [Manshur] dari [Ibrahim] dan [Asy Sya'bi] keduanya berkata; Tidak apa-apa untuk menjual perwalian budak sa`ibah dan pemberiannya."},"2615":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ الْقَاسِمِ قَالَ أَعْتَقَ رَجُلٌ غُلَامًا سَائِبَةً فَأَتَى عَبْدَ اللَّهِ وَقَالَ إِنِّي أَعْتَقْتُ غُلَامًا لِي سَائِبَةً وَهَذِهِ تَرِكَتُهُ قَالَ هِيَ لَكَ قَالَ لَا حَاجَةَ لِي فِيهَا قَالَ فَضَعْهَا فَإِنَّ هَا هُنَا وَارِثًا كَثِيرًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Mas'udi] dari [Al Qasim] ia berkata; Ada seseorang yang memerdekakan seorang anak dengan status Sa`ibah, lalu ia mendatangi [Abdullah] dan berkata; Sesungguhnya aku telah memerdekakan seorang anak milikku dengan status sa`ibah dan ini adalah harta yang ditinggalkannya. Ia berkata; Ia menjadi milikmu. Orang itu berkata lagi; Namun aku tidak membutuhkannya. Ia berkata; Kalau begitu biarkanlah ia, karena di sini masih banyak ahli warisnya."},"2616":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ إِذَا اسْتَهَلَّ الصَّبِيُّ وُرِّثَ وَصُلِّيَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Asy'ats] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata; Jika seorang terlahir dalam keadaan menangis, maka ia mendapat warisan dan dishalati."},"2617":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِذَا اسْتَهَلَّ الصَّبِيُّ وَرِثَ وَوُرِثَ وَصُلِّيَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari ['Atha`] dari [Ibnu Abbas] ia berkata; Jika seorang terlahir dalam keadaan menangis maka ia mewarisi, mewariskan dan dishalati."},"2618":{"ar":" حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ لَيْسَ مِنْ مَوْلُودٍ إِلَّا يَسْتَهِلُّ وَاسْتِهْلَالُهُ يَعْصِرُ الشَّيْطَانُ بَطْنَهُ فَيَصِيحُ إِلَّا عِيسَى ابْنَ مَرْيَمَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Tidaklah seorang anak yang lahir kecuali dalam keadaan menangis, dan tangisannya itu karena setan menekan (mencubit) perutnya sehingga ia menangis dengan berteriak kecuali Isa bin Maryam."},"2619":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ حَمْزَةَ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ مَكْحُولٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرِثُ الْمَوْلُودُ حَتَّى يَسْتَهِلَّ صَارِخًا وَإِنْ وَقَعَ حَيًّا","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Yahya] ia adalah Ibnu Hamzah, dari [Zaid bin Waqid] dari [Makhul] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang anak yang lahir tidak mendapat warisan hingga ia menangis dengan berteriak (menjerit) dan jika ia lahir dalam keadaan hidup.\""},"2620":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَ إِذَا اسْتَهَلَّ الْمَوْلُودُ صُلِّيَ عَلَيْهِ وَوُرِثَ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Muhammad bin Ishaq] dari ['Atha`] dari [Jabir] ia berkata; Jika seorang anak terlahir dalam keadaan menangis, maka ia berhak dishalati dan mendapat warisan."},"2621":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مَعْنٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ قَالَ أَرَى الْعُطَاسَ اسْتِهْلَالًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Ma'an] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] ia berkata; Aku berpendapat bahwa bersin sebagai tanda anak terlahir dalam keadaan menangis."},"2622":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ لَا يُوَرَّثُ الْمَوْلُودُ حَتَّى يَسْتَهِلَّ وَلَا يُصَلَّى عَلَيْهِ حَتَّى يَسْتَهِلَّ فَإِذَا اسْتَهَلَّ صُلِّيَ عَلَيْهِ وَوُرِّثَ وَكُمِّلَتْ الدِّيَةُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Ibrahim] ia berkata; Anak yang terlahir tidak mendapat warisan hingga ia terlahir dalam keadaan menangis, tidak dishalati hingga ia terlahir dalam keadaan menangis. Maka, jika ia terlahir dalam keadaan menangis, ia berhak dishalati, mendapat warisan, dan diyatnya diberikan secara sempurna."},"2623":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ وَسَأَلْنَاهُ عَنْ السِّقْطِ فَقَالَ لَا يُصَلَّى عَلَيْهِ وَلَا يُصَلَّى عَلَى مَوْلُودٍ حَتَّى يَسْتَهِلَّ صَارِخًا","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dan kami juga bertanya kepadanya tentang anak yang lahir prematur (keguguran), ia menjawab; Anak itu tidak dishalati, anak yang lahir tidak wajib dishalati hingga ia menangis dengan berteriak."},"2624":{"ar":" حَدَّثَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ أَبِي سُفْيَانَ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ قَالَ إِذَا ابْتَاعَ الْمُكَاتَبَانِ أَحَدُهُمَا الْآخَرَ هَذَا هَذَا مِنْ سَيِّدِهِ وَهَذَا هَذَا مِنْ سَيِّدِهِ فَالْبَيْعُ لِلْأَوَّلِ وَيَقُولُ أَهْلُ الْمَدِينَةِ الْوَلَاءُ لِسَيِّدِ الْبَائِعِ وَيَقُولُونَ إِنَّمَا ابْتَاعَ هَذَا مَا عَلَى الْمُكَاتَبِ فَالْوَلَاءُ لِلسَّيِّدِ","id":"Telah menceritakan kepada kami [Harun bin Mu'awiyah] dari [Abu Sufyan] dari [Ma'mar] dari [Qatadah] ia berkata; Jika dua orang budak mukatab saling membeli satu sama lain, budak ini membeli budak itu dari tuannya dan budak itu membeli budak ini dari tuannya maka jual beli adalah yang pertama. Penduduk Madinah berkata; Wala` tetap untuk majikan yang menjual. Mereka berkata; Sesungguhnya budak ini membeli apa yang wajib dilunasi oleh mukatab. Oleh karena itu wala` tetap untuk majikan. "},"2625":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى عَنْ سَعِيدٍ أَنَّ عُمَرَ قَالَ أَيُّمَا حُرٍّ تَزَوَّجَ أَمَةً فَقَدْ أَرَقَّ نِصْفَهُ وَأَيُّمَا عَبْدٍ تَزَوَّجَ حُرَّةً فَقَدْ أَعْتَقَ نِصْفَهُ قَالَ أَبُو مُحَمَّد يَعْنِي الْوَلَدَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya] dari [Sa'id] bahwa [Umar] berkata; Laki-laki merdeka manapun yang menikahi budak perempuan maka ia telah memerdekakannya setengah. Dan budak manapun yang menikahi perempuan merdeka maka ia telah memerdekakannya setengah. Abu Muhammad berkata; Yakni pada status anaknya."},"2626":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ فِي الْعَبْدِ يَتَزَوَّجُ الْمَرْأَةَ ثُمَّ يُطَلِّقُهَا وَلَهُ مِنْهَا وَلَدٌ قَالَ إِنْ كَانَتْ حُرَّةً فَالنَّفَقَةُ عَلَى أُمِّهِ وَإِنْ كَانَ عَبْدًا يَعْنِي الصَّبِيَّ فَعَلَى مُوَالِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Asy Syaibani] dari [Asy Sya'bi] tentang seorang budak yang menikahi seorang perempuan kemudian menceraikannya sedangkan ia melahirkan anak untuknya. Ia berkata; Jika anak itu perempuan merdeka maka nafkah atas ibunya, dan jika anak itu seorang budak maksudnya budak kecil maka nafkah atas para majikannya."},"2627":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ ح و حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ أَنَّهُمَا قَالَا وَلَاؤُهُ لِمَنْ بَدَأَ بِالْعِتْقِ أَوَّلَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Zakariya] dari [Amir], dalam riwayat hadits lain; Telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Ibrahim] bahwa mereka berdua berkata; Wala`nya jatuh pada orang yang pertama kali memerdekakan."},"2628":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ عَنْ الْحَسَنِ ح و حَدَّثَنَا جَرِيرٌ عَنْ أَبَانَ بْنِ تَغْلِبَ عَنْ الْحَكَمِ عَنْ إِب��رَاهِيمَ أَنَّهُمَا قَالَا إِنْ ضَمِنَ كَانَ الْوَلَاءُ لَهُ وَإِنْ اسْتَسْعَى الْعَبْدُ كَانَ الْوَلَاءُ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Yunus] dari [Al Hasan], dalam riwayat hadits lain; Telah menceritakan kepada kami [Jarir] dari [Aban bin Taghlib] dari [Al Hakam] dari [Ibrahim] bahwa mereka berdua berkata; Jika ia menjamin maka wala` untuknya, dan jika ia mempekerjakan budak itu maka wala` dibagi di antara mereka."},"2629":{"ar":" حَدَّثَنَا يَعْلَى وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ فِي عَبْدٍ بَيْنَ رَجُلَيْنِ أَعْتَقَ أَحَدُهُمَا نَصِيبَهُ قَالَ يُتَمَّمُ عِتْقُهُ فَإِنْ لَمْ يَكُنْ لَهُ مَالٌ اسْتُسْعِيَ الْعَبْدُ فِي النِّصْفِ بِقِيمَةِ عَدْلٍ وَالْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Ya'la] dan [Abu Nu'aim] keduanya berkata; Telah menceritakan kepada kami [Zakariya] dari [Amir] tentang seorang budak yang dimiliki dua orang di mana salah satunya memerdekakan bagiannya, ia berkata; Ia harus menyempurnakan kemerdekaannya. Jika ia tidak memiliki harta maka budak itu harus berusaha untuk menyempurnakan setengahnya dengan nilai (harga) yang adil. Sedangkan wala` untuk orang yang memerdekakan."},"2630":{"ar":" حَدَّثَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ أَبِي سُفْيَانَ الْمَعْمَرِيِّ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ فِي عَبْدٍ بَيْنَ رَجُلَيْنِ أَعْتَقَ أَحَدَهُمَا نَصِيبَهُ وَأَمْسَكَهُ الْآخَرُ قَالَ مِيرَاثُهُ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Harun bin Mu'awiyah] dari [Abu Sufyan Al Ma'mari] dari [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] tentang seorang budak yang dimliki oleh dua orang, lalu salah satunya memerdekakan bagiannya dan yang lain tidak, ia berkata; Warisan budak itu dibagi untuk mereka berdua."},"2631":{"ar":" حَدَّثَنَا هَارُونُ عَنْ أَبِي سُفْيَانَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ مِيرَاثُهُ لِلَّذِي أَمْسَكَهُ و قَالَ قَتَادَةُ هُوَ لِلْمُعْتِقِ كُلُّهُ وَثَمَنُهُ عَلَيْهِ وَيَقُولُهُ أَهْلُ الْكُوفَةِ","id":"Telah menceritakan kepada kami [Harun] dari [Abu Sufyan] dari [Ma'mar] dari [Az Zuhri] ia berkata; Warisannya untuk orang yang tidak memerdekakan. [Qatadah] berkata; Seluruh warisan untuk orang yang memerdekakan dan biaya untuk memerdekakannya. Demikian pula yang dikatakan oleh penduduk Kufah."},"2632":{"ar":" حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الرَّجُلِ يَمُوتُ وَيَتْرُكُ مُكَاتَبًا وَلَهُ بَنُونَ وَبَنَاتٌ أَيَكُونُ لِلنِّسَاءِ مِنْ الْوَلَاءِ شَيْءٌ قَالَ تَرِثُ النِّسَاءُ مِمَّا عَلَى ظَهْرِهِ مِنْ مُكَاتَبَتِهِ وَيَكُونُ الْوَلَاءُ لِلرِّجَالِ دُونَ النِّسَاءِ إِلَّا مَا كَاتَبْنَ أَوْ أَعْتَقْنَ","id":"Telah menceritakan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] tentang seseorang yang meninggal dunia dan meninggalkan seorang budak mukatab, ia juga memiliki beberapa anak laki-laki dan perempuan, adakah kaum perempuan mendapat wala`, ia menjawab; Kaum perempuan hanya dapat mewarisi apa yang wajib dilunasi budak dari syarat pemerdekaannya. Sementara wala' hanya untuk kaum laki-laki tidak untuk kaum perempuan, kecuali mereka yang memberikan janji pemerdekaan bersyarat atau mereka yang memerdekakan."},"2633":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو سُفْيَانَ عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ تُوُفِّيَ رَجُلٌ وَتَرَكَ مُكَاتَبًا ثُمَّ مَاتَ الْمُكَاتَبُ وَتَرَكَ مَالًا فَجَعَلَ ابْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ مَا بَقِيَ مِنْ مُكَاتَبَتِهِ بَيْنَ بَنِي مَوْلَاهُ الرِّجَالُ وَالنِّسَاءُ عَلَى مِيرَاثِهِمْ وَمَا فَضَلَ مِنْ الْمَالِ بَعْدَ كِتَابَتِهِ فَلِلرِّجَالِ مِنْهُمْ مِنْ بَنِي مَوْلَاهُ دُونَ النِّسَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Sufyan] dari [Ma'mar] dari [Yahya bin Abu Katsir] ia berkata; Seorang laki-laki meninggal dunia dan meninggalkan seorang budak mukatab, kemudian budak mukatab itu meninggal dunia dan meninggalkan harta. Ibnu Al Musayyab dan Abu Salamah bin Abdurrahman memberikan apa yang tersisa dari syarat pemerdekaannya kepada anak-anak majikannya. Kaum laki-laki dan kaum perempuan berhak atas warisan tersebut, sedangkan apa yang tersisa dari harta setelah pelunasannya, diberikan kepada kaum laki-laki dari anak-anak majikannya dan tidak untuk kaum perempuan dari anak-anak majikannya."},"2634":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عُمَرَ وَعَلِيٍّ وَزَيْدٍ أَنَّهُمْ قَالُوا الْوَلَاءُ لِلْكُبْرِ وَلَا يَرِثُونَ النِّسَاءَ مِنْ الْوَلَاءِ إِلَّا مَا أَعْتَقْنَ أَوْ كَاتَبْنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Al A'masy] dari [Ibrahim] dari [Umar], [Ali] dan [Zaid] bahwa mereka berkata; Wala` untuk yang lebih tua. Mereka tidak mewariskan wala` kepada kaum perempuan kecuali jika mereka memerdekakan atau memberi janji pemerdekaan."},"2635":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُعَاذٌ عَنْ أَشْعَثَ عَنْ الْحَسَنِ قَالَ لَا تَرِثُ النِّسَاءُ مِنْ الْوَلَاءِ إِلَّا مَا أَعْتَقْنَ أَوْ أَعْتَقَ مَنْ أَعْتَقْنَ إِلَّا الْمُلَاعَنَةُ فَإِنَّهَا تَرِثُ مَنْ أَعْتَقَ ابْنُهَا وَالَّذِي انْتَفَى مِنْهُ أَبُوهُ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Mu'adz] dari [Asy'ats] dari [Al Hasan] ia berkata; Kaum perempuan tidak dapat mewarisi wala` kecuali jika mereka yang memerdekakan atau ia memerdekakan siapa yang mereka merdekakan kecuali anak seorang wanita yang terkena li'an, maka perempuan itu dapat mewarisi orang yang memerdekakan anaknya dan orang yang tidak diakui oleh ayahnya."},"2636":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّهُ كَانَ يَرِثُ مَوَالِيَ عُمَرَ دُونَ بَنَاتِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa ia pernah memberikan warisan kepada para mantan budak Umar dan tidak diberikan kepada anak-anak perempuan Umar."},"2637":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَ��ْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ فِي امْرَأَةٍ مَاتَتْ وَتَرَكَتْ بَنِيهَا فَوَرِثُوهَا مَالًا وَمَوَالِيَ ثُمَّ مَاتَ بَنُوهَا قَالَ يَرْجِعُ الْوَلَاءُ إِلَى عَصَبَةِ الْمَرْأَةِ","id":"Telah mengabarkan kepada kami [Amr bin 'Aun] dari [Khalid bin Abdullah] dari [Khalid Al Hadza`] dari [Abu Qilabah] tentang seorang perempuan yang meninggal dunia dan meninggalkan beberapa anak laki-laki, maka mereka mewarisi hartanya dan para budak ibunya, kemudian anak-anaknya meninggal dunia. Ia berkata; Wala` kembali kepada ashabah perempuan tersebut."},"2638":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ أَنَّهُ كَانَ يَقُولُ فِي امْرَأَةٍ مَاتَتْ وَتَرَكَتْ مَوْلًى قَالَ الْوَلَاءُ لِبَنِيهَا فَإِذَا مَاتُوا رَجَعَ إِلَى عَصَبَتِهَا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritaan kepada kami [Wuhaib] telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa ia pernah berkata tentang seorang perempuan yang meninggal dunia dan meninggalkan mantan budaknya, ia berkata; Wala` untuk anak laki-lakinya, namun jika mereka meninggal dunia maka wala` kembali kepada ashabah perempuan tersebut."},"2639":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ أَخْبَرَنَا شُعْبَةُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ لَيْسَ لِلنِّسَاءِ مِنْ الْوَلَاءِ شَيْءٌ إِلَّا مَا أَعْتَقَتْ هِيَ بِنَفْسِهَا","id":"Telah menceritakan kepada kami [Sa'id bin Amir] telah mengabarkan kepada kami [Syu'bah] dari [Mughirah] dari [Ibrahim] ia berkata; Kaum perempuan tidak mendapatkan hak wala` sedikit pun kecuali yang dimerdekakannya sendiri."},"2640":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ قَالَ يُحْرِزُ الْوَلَاءَ مَنْ يُحْرِزُ الْمِيرَاثَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya] ia berkata; Wala` berhak dimiliki orang yang mendapat hak waris."},"2641":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ حَدَّثَنَا يَحْيَى عَنْ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنَّ امْرَأَةً مِنْ مُحَارِبٍ وَهَبَتْ وَلَاءَ عَبْدِهَا لِنَفْسِهِ فَأَعْتَقَتْهُ فَوَهَبَ وَلَاءَ نَفْسِهِ لِعَبْدِ الرَّحْمَنِ بْنِ عَمْرِو بْنِ حَزْمٍ وَمَاتَتْ فَخَاصَمَتْ الْمَوَالِي إِلَى عُثْمَانَ فَدَعَا عُثْمَانُ الْبَيِّنَةَ عَلَى مَا قَالَ قَالَ فَأَتَى الْبَيِّنَةُ فَقَالَ لَهُ عُثْمَانُ اذْهَبْ فَوَالِ مَنْ شِئْتَ قَالَ أَبُو بَكْرٍ فَوَالَى عَبْدَ الرَّحْمَنِ بْنَ عَمْرِو بْنِ حَزْمٍ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] telah menceritakan kepada kami [Yahya] dari [Abu Bakr bin Amr bin Hazm] bahwa seorang perempuan dari Muharib memberikan wala` budaknya kepada diri budak tersebut. Lalu perempuan itu memerdekakannya dan budak itu pun memberikan wala` dirinya kepada Abdurrahman bin Amr bin Hazm, sementara perempuan itu meninggal dunia. Para budak lain mengadukan masalah ini kepada Utsman. Maka Utsman meminta bukti atas apa yang ia katakan. (Abu Bakr) berkata; Lalu budak itu menghadirkan bukti. Maka [Utsman] berkata kepadanya; Pergilah dan berikan wala`mu kepada orang yang kamu kehendaki. Abu Bakr berkata; Maka ia menjadikan Abdurrahman bin Amr bin Hazm sebagai wala`nya."},"2642":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang menjual wala` dan menghibahkannya."},"2643":{"ar":" حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang menjual wala` dan menghibahkannya."},"2644":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ لَا يُبَاعُ الْوَلَاءُ وَلَا يُوهَبُ وَالْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] ia berkata; Aku mendengar [Ibnu Abbas] berkata; Wala` tidak boleh dijual dan tidak boleh juga dihibahkan, tetapi wala` itu diberikan kepada orang yang memerdekakan."},"2645":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عَبْدُ اللَّهِ الْوَلَاءُ لُحْمَةٌ كَلُحْمَةِ النَّسَبِ لَا يُبَاعُ وَلَا يُوهَبُ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Sa'id] dari [Abu Ma'syar] dari [Ibrahim] ia berkata; [Abdullah] berkata; Wala` seperti satu keturunan, tidak boleh dijual atau dihibahkan."},"2646":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُمَا كَرِهَا بَيْعَ الْوَلَاءِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dan [Sa'ib bin Al Musayyab] bahwa keduanya memakruhkan menjual wala`."},"2647":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ قَالَ ابْنُ عَبَّاسٍ لَا يُبَاعُ الْوَلَاءُ أَيُؤْكَلُ بِرَقَبَةِ رَجُلٍ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Ibnu Idris] dari [Ibnu Juraij] dari ['Atha`] ia berkata; [Ibnu Abbas] berkata; Wala` tidak boleh dijual. Apakah layak seseorang diberi makan budak dua kali? "},"2648":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ الْفَرَائِضُ مِنْ سِتَّةٍ لَا نُعِيلُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha`] dari [Ibnu Abbas] ia berkata; Pembagian harta waris dari enam tidak kami jadikan sebagai 'aul. "},"2649":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِمْرَانَ عَنْ مُعَاوِيَةَ بْنِ مَيْسَرَةَ بْنِ شُرَيْحٍ عَنْ أَيُّوبَ بْنِ الْحَارِثِ قَالَ اخْتُصِمَ إِلَى شُرَيْحٍ فِي بِنْتَيْنِ وَأَبَوَيْنِ وَزَوْجٍ فَقَضَى فِيهَا فَأَقْبَلَ الزَّوْجُ يَشْكُوهُ فِي الْمَسْجِدِ فَأَرْسَلَ إِلَيْهِ عَبْدَ اللَّهِ بْنَ رَبَاحٍ فَأَخَذَهُ وَبَعَثَ إِلَى شُرَيْحٍ فَقَالَ مَا يَقُولُ هَذَا قَالَ هَذَا يَخَالُنِي امْرَأً جَائِرًا وَأَنَا إِخَالُهُ امْرَأً فَاجِرًا يُظْهِرُ الشَّكْوَى وَيَكْتُمُ قَضَاءً سَائِرًا فَقَالَ لَهُ الرَّجُلُ مَا تَقُولُ فِي بِنْتَيْنِ وَأَبَوَيْنِ وَزَوْجٍ فَقَالَ لِلزَّوْجِ الرُّبُعُ مِنْ جَمِيعِ الْمَالِ وَلِلْأَبَوَيْنِ السُّدُسَانِ وَمَا بَقِيَ فَلِلِابْنَتَيْنِ قَالَ فَلِأَيِّ شَيْءٍ نَقَصْتَنِي قَالَ لَيْسَ أَنَا نَقَصْتُكَ اللَّهُ نَقَصَكَ لِلِابْنَتَيْنِ الثُّلُثَانِ وَلِلْأَبَوَيْنِ السُّدُسَانِ وَلِلزَّوْجِ الرُّبُعُ فَهِيَ مِنْ سَبْعَةٍ وَنِصْفٍ فَرِيضَةً فَرِيضَتُكَ عَائِلَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Imran] dari [Mu'awiyah bin Maisarah bin Syuraih] dari [Ayyub bin Al Harits] ia berkata; Syuraih pernah mendapat pengaduan tentang dua anak perempuan, dua orang tua dan suami. Maka ia memutuskan dalam masalah ini. Lalu sang suami datang dan mengadukannya di dalam masjid. Maka ia mengutus Abdullah bin Rabah, ia pun segera menjemput dan mengantarkan kepada Syuraih. (Syuraih) pun bertanya; Apa yang dikatakan orang ini? ' Syuraih berkata, 'Dia menyangka aku adalah orang yang zhalim, sedangkan aku menyangkanya seorang yang jahat. Dia mengumbar ketidakpuasan dan menyembunyikan keputusan yang berlaku.' Lalu laki-laki itu (suami) berkata kepada Syuraih, 'Apa yang kamu katakan tentang dua anak perempuan.' Laki-laki itu berkata, 'Kenapa kamu mengurangi bagianmu. Allah yang mengurangi bagianmu. Untuk dua anak perempuan dua pertiga, untuk kedua orang tua dua perenam dan untuk suami seperempat. Masalah ini dari tujuh setengah sebagai bagian wajib dan bagiannya dikalikan sebagai Aul.\""},"2650":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ وَعُمَرَ وَزَيْدٍ قَالُوا الْوَالِدُ يَجُرُّ وَلَاءَ وَلَدِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Asy Sya'bi] dari [Ali], [Umar] dan [Zaid], mereka berkata, Bapak berhak mengambil wala` anaknya."},"2651":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ الشَّعْبِيِّ قَالَ الْجَدُّ يَجُرُّ الْوَلَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Asy Sya'bi] ia berkata; Kakek berhak mengambil wala`."},"2652":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ ابْنِ سِيرِينَ عَنْ شُرَيْحٍ قَالَ الْوَالِدُ يَجُرُّ وَلَاءَ وَلَدِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Ibnu Sirin] dari [Syuraih] ia berkata; Bapak berhak mengambil wala` anaknya."},"2653":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ فِي مَمْلُوكٍ تُوُفِّيَ وَلَهُ أَبٌ حُرٌّ وَلَهُ بَنُونَ مِنْ امْرَأَةٍ حُرَّةٍ لِمَنْ وَلَاءُ وَلَدِهِ قَالَ لِمَوَالِي الْجَدِّ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari [Amir] tentang seorang budak yang meninggal dunia dan meninggalkan ayah yang merdeka dan beberapa anak laki-laki dari isteri yang merdeka, Untuk siapakah wala` anaknya? Ia menjawab; Untuk para mantan budak kakek."},"2654":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ فِي مُكَاتَبٍ مَاتَ وَقَدْ أَدَّى نِصْفَ مُكَاتَبَتِهِ وَلَهُ وَلَدٌ مِنْ امْرَأَةٍ أَحْرَارٌ قَالَ مَا أُرَاهُ إِلَّا قَدْ جَرَّ وَلَاءَ وَلَدِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra`il] dari [Mughirah] dari [Ibrahim] tentang budak mukatab yang meninggal dunia dan meninggalkan seorang anak dari isteri yang merdeka, ia berkata; Tidaklah aku berpendapat kecuali ia berhak mengambil wala` anaknya."},"2655":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ قَالَ كَانَ شُرَيْحٌ لَا يَرْجِعُ عَنْ قَضَاءٍ يَقْضِي بِهِ فَحَدَّثَهُ الْأَسْوَدُ أَنَّ عُمَرَ قَالَ إِذَا تَزَوَّجَ الْمَمْلُوكُ الْحُرَّةَ فَوَلَدَتْ أَوْلَادًا أَحْرَارًا ثُمَّ عُتِقَ بَعْدَ ذَلِكَ رَجَعَ الْوَلَاءُ لِمَوَالِي أَبِيهِمْ فَأَخَذَ بِهِ شُرَيْحٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] ia berkata; [Syuraih] tidak pernah menarik keputusannya yang telah dia putuskan. Lalu [Al Aswad] menceritakan kepadanya bahwa Umar pernah berkata; Jika seorang budak menikah dengan seorang perempuan yang merdeka lalu melahirkan anak-anak dalam keadaan merdeka kemudian setelah itu ia dimerdekakan, maka wala` kembali kepada orang yang memerdekakan ayah mereka. Lalu Syuraih pun memegang riwayat ini."},"2656":{"ar":" حَدَّثَنَا يَعْلَى عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عُمَرُ فِي الْمَمْلُوكِ يَكُونُ تَحْتَهُ الْحُرَّةُ يُعْتَقُ الْوَلَدُ بِعِتْقِ أُمِّهِ فَإِذَا عُتِقَ الْأَبُ جَرَّ الْوَلَاءَ","id":"Telah menceritakan kepada kami [Ya'la] dari [Al A'masy] dari [Ibrahim] ia berkata; [Umar] berkata tentang seorang budak yang memiliki isteri yang merdeka; Anaknya dimerdekakan karena status ibunya yang merdeka. Jika ayah dimerdekakan, maka wala` berhak diambil oleh orang yang memerdekakannya."},"2657":{"ar":" حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ كَثِيرِ بْنِ شِنْظِيرٍ عَنْ عَطَاءٍ فِي الْحُرَّةِ تَحْتَ الْعَبْدِ قَالَ أَمَّا مَا وَلَدَتْ مِنْهُ وَهُوَ عَبْدٌ فَوَلَاؤُهُمْ لِأَهْلِ نِعْمَتِهَا وَمَا وَلَدَتْ مِنْهُ وَهُوَ حُرٌّ فَوَلَاؤُهُمْ لِأَهْلِ نِعْمَتِهِ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Abdul Warits] dari [Katsir bin Syinzhir] dari ['Atha`] tentang seorang perempuan merdeka yang menjadi isteri seorang budak, ia berkata; Jika yang dilahirkan adalah seorang budak maka wala` mereka jatuh kepada para wali dari ibunya, sedangkan jika yang dilahirkan adalah anak yang merdeka maka wala` mereka jatuh kepada orang-orang yang memerdekakan ayahnya."},"2658":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عُمَرُ إِذَا كَانَتْ الْحُرَّةُ تَحْتَ الْمَمْلُوكِ فَوَلَدَتْ لَهُ غُلَامًا فَإِنَّهُ يُعْتَقُ بِعِتْقِ أُمِّهِ وَوَلَاؤُهُ لِمَوَالِي أُمِّهِ فَإِذَا أُعْتِقَ الْأَبُ جَرَّ الْوَلَاءَ إِلَى مَوَالِي أَبِيهِ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Al A'masy] dari [Ibrahim] ia berkata; [Umar] berkata; Jika seorang perempuan merdeka menjadi isteri seorang budak, lalu melahirkan seorang anak maka anaknya dimerdekakan karena status ibunya yang merdeka dan wala'nya jatuh kepada para wali dari ibunya dan jika sang ayah telah dimerdekakan maka wala`nya jatuh kepada para wali dari ayahnya."},"2659":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَ كَانَتْ أُمِّي مَوْلَاةً لِلْحُرَقَةِ وَكَانَ أَبِي يَعْقُوبُ مُكَاتَبًا لِمَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيِّ ثُمَّ إِنَّ أَبِي أَدَّى كِتَابَتَهُ فَدَخَلَ الْحُرَقِيُّ عَلَى عُثْمَانَ يَسْأَلُ الْحَقَّ يَعْنِي الْعَطَاءَ وَعِنْدَهُ مَالِكُ بْنُ أَوْسٍ فَقَالَ ذَاكَ مَوْلَايَ فَاخْتَصَمَا إِلَى عُثْمَانَ فَقَضَى بِهِ لِلْحُرَقِيِّ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] ia berkata; Ibuku adalah mantan budak milik Huraqah sedangkan ayahku, Ya'qub adalah seorang budak mukatab milik Malik bin Aus bin Al Hadatsan An Nashri, kemudian ayahku telah melunasi mukatabahnya. Maka Al Huraqi menemui Utsman untuk memintakan hak, yakni pemberian, saat itu Malik bin Aus ada di sampingnya, ia berkata; Ia adalah mantan budakku. Lalu keduanya mengadukan hal itu kepada Utsman, lalu [Utsman] pun memutuskan wala`ku untuk Al Huraqi."},"2660":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ أَخْبَرَنِي سَهْمُ بْنُ يَزِيدَ الْحَمْرَاوِيُّ أَنَّ رَجُلًا تُوُفِّيَ وَلَيْسَ لَهُ وَارِثٌ فَكُتِبَ فِيهِ إِلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِ وَهُوَ خَلِيفَةٌ فَكَتَبَ أَنْ اقْتَسِمُوا مِيرَاثَهُ عَلَى مَنْ كَانَ يَأْخُذُ مَعَهُمْ الْعَطَاءَ فَقُسِمَ مِيرَاثُهُ عَلَى مَنْ كَانَ يَأْخُذُ مَعَهُمْ الْعَطَاءَ فِي عِرَافَتِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] telah mengabarkan kepadaku [Sahm bin Yazid Al Hamrawi] bahwa seseorang telah meninggal dunia namun ia tidak memiliki seorang ahli waris pun. Maka dikirimkan surat kepada [Umar bin Abdul Aziz], saat itu ia menjabat sebagai khalifah, lalu ia membalas surat itu; Hendaklah kalian membagikan warisannya kepada orang yang berhak mengambil pemberian bersama mereka. Maka warisan itu pun dibagikan kepada orang-orang yang berhak mengambil pemberian bersama mereka dalam pekerjaannya."},"2661":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ يَبِيتُ لَيْلَتَيْنِ وَلَهُ شَيْءٌ يُوصِي فِيهِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] telah mengabarkan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak selayaknya bagi seorang muslim yang melewati dua malam sedangkan ia memiliki sesuatu yang harus diwasiatkan kecuali wasiatnya tertulis di sisinya.\""},"2662":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا الْحَسَنُ قَالَ الْمُؤْمِنُ لَا يَأْكُلُ فِي كُلِّ بَطْنِهِ وَلَا تَزَالُ وَصِيَّتُهُ تَحْتَ جَنْبِهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abu Al Asyhab] telah menceritakan kepada kami [Al Hasan] ia berkata; Seorang mukmin adalah orang yang tidak makan sepenuh perutnya dan wasiatnya selalu berada di bawah pundaknya."},"2663":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الْقَاسِمِ بْنِ عُمَرَ قَالَ قَالَ لِي ثُمَامَةُ بْنُ حَزْنٍ مَا فَعَلَ أَبُوكَ قُلْتُ مَاتَ قَالَ فَهَلْ أَوْصَى فَإِنَّهُ كَانَ يُقَالُ إِذَا أَوْصَى الرَّجُلُ كَانَ وَصِيَّتُهُ تَمَامًا لِمَا ضَيَّعَ مِنْ زَكَاتِهِ قَالَ أَبُو مُحَمَّد و قَالَ غَيْرُهُ الْقَاسِمُ بْنُ عَمْرٍو","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud bin Abu Hind] dari [Al Qasim bin Umar] ia berkata; [Tsumamah bin Hazn] berkata kepadaku; Apa yang dilakukan ayahmu? Aku menjawab; Ia telah meninggal dunia. Ia bertanya; Apakah ia telah berwasiat? Sebab dikatakan; Jika seseorang telah berwasiat dengan wasiat yang sempurna niscaya zakatnya tidak sia-sia. Abu Muhammad berkata, ada juga orang selainnya berkata; ia adalah Al Qasim bin Amr."},"2664":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ قَالَ كَانَ يُقَالُ مَنْ أَوْصَى بِوَصِيَّةٍ فَلَمْ يَجُرْ وَلَمْ يَحِفْ كَانَ لَهُ مِنْ الْأَجْرِ مِثْلُ مَا أَنْ لَوْ تَصَدَّقَ بِهِ فِي حَيَاتِهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] ia berkata; Pernah dikatakan; Barangsiapa yang menyampaikan sebuah wasiat lalu ia tidak berbuat zhalim dan aniaya, maka ia mendapatkan pahala seperti pahala yang diperolehnya seandainya ia menyedekahkan selama hidupnya."},"2665":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي يُونُسَ عَنْ قَزَعَةَ قَالَ قِيلَ لِهَرِمِ بْنِ حَيَّانَ أَوْصِهْ قَالَ أُوصِيكُمْ بِالْآيَاتِ الْأَوَاخِرِ مِنْ سُورَةِ النَّحْلِ وَقَرَأَ ابْنُ حَيَّانَ { ادْعُ إِلَى سَبِيلِ رَبِّكَ بِالْحِكْمَةِ - إِلَى قَوْلِهِ - وَالَّذِينَ هُمْ مُحْسِنُونَ }","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Abu Yunus] dari [Qaza'ah] ia berkata; Dikatakan kepada [Harim bin Hayyan]; Berwasiatlah. Ia berkata; Aku wasiatkan kepada kalian ayat-ayat terakhir dari surah An Nahl. Lalu Ibnu Hayyan membaca, UD'UU ILA RABBIKA BIL HIKMATI… WALLADZI HUM MUHSININ (Serulah (manusia) kepada jalan Tuhanmu dengan yang baik…. dan orang-orang yang berbuat kebaikan)."},"2666":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ الْيَامِيِّ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى أَوْصَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قُلْتُ فَكَيْفَ كُتِبَ عَلَى النَّاسِ الْوَصِيَّةُ أَوْ أُمِرُوا بِالْوَصِيَّةِ فَقَالَ أَوْصَى بِكِتَابِ اللَّهِ و قَالَ هُزَيْلُ بْنُ شُرَحْبِيلَ أَبُو بَكْرٍ كَانَ يَتَأَمَّرُ عَلَى وَصِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَّ أَبُو بَكْرٍ أَنَّهُ وَجَدَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدًا فَخَزَمَ أَنْفَهُ بِخِزَامَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Malik bin Mighwal] dari [Thalhah bin Musharrif Al Yami] ia berkata; Aku pernah bertanya kepada [Abdullah bin Abu Aufa]; Apakah Rasulullah shallallahu 'alaihi wasallam berwasiat? Ia menjawab; Tidak. Aku bertanya lagi; Lalu bagaimana wasiat itu diwajibkan atas manusia atau mereka diperintahkan untuk berwasiat? Ia menjawab; Beliau berwasiat dengan Kitabullah. Huzail bin Syurahbil berkata; Abu Bakar mendasarkan perintah wasiat kepada orang yang diberi wasiat dari Rasulullah shallallahu 'alaihi wasallam. Seandainya, ia menemukan sebuah wasiat dari Rasulullah shallallahu 'alaihi wasallam tentu ia akan mengaitkan hidungnya dengan kait itu (menaatinya)."},"2667":{"ar":" أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ { إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ } قَالَ الْخَيْرُ الْمَالُ كَانَ يُقَالُ أَلْفًا فَمَا فَوْقَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Hammam] dari [Qatadah] tentang ayat: IN TARAKA KHAIRANIL WASHIYYAH (Jika dia meninggalkan harta yang banyak, berwasiat), ia berkata; Al Khair adalah harta. Dikatakan; Seribu atau lebih."},"2668":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ أَنَّهُ أَوْصَى ذِكْرُ مَا أَوْصَى بِهِ أَوْ هَذَا ذِكْرُ مَا أَوْصَى بِهِ مُحَمَّدُ بْنُ أَبِي عَمْرَةَ بَنِيهِ وَأَهْلَ بَيْتِهِ أَنْ { اتَّقُوا اللَّهَ وَأَصْلِحُوا ذَاتَ بَيْنِكُمْ وَأَطِيعُوا اللَّهَ وَرَسُولَهُ إِنْ كُنْتُمْ مُؤْمِنِينَ } وَأَوْصَاهُمْ بِمَا أَوْصَى بِهِ إِبْرَاهِيمُ بَنِيهِ وَيَعْقُوبُ { يَا بَنِيَّ إِنَّ اللَّهَ اصْطَفَى لَكُمْ الدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ } وَأَوْصَاهُمْ أَنْ لَا يَرْغَبُوا أَنْ يَكُونُوا مَوَالِيَ الْأَنْصَارِ وَإِخْوَانَهُمْ فِي الدِّينِ وَأَنَّ الْعِفَّةَ وَالصِّدْقَ خَيْرٌ وَأَتْقَى مِنْ الزِّنَا وَالْكَذِبِ إِنْ حَدَثَ بِهِ حَدَثٌ فِي مَرَضِي هَذَا قَبْلَ أَنْ أُغَيِّرَ وَصِيَّتِي هَذِهِ ثُمَّ ذَكَرَ حَاجَتَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Muhammad bin Sirin] bahwa ia pernah berwasiat. Berikut ini apa yang diwasiatkan atau inilah yang diwasiatkan oleh Muhammad bin Abu 'Amrah kepada anak-anak dan keluarganya; (Bertaqwalah kepada Allah dan perbaikilah hubungan di antara sesama kalian dan taatlah kepada Allah juga RasulNya jika kalian adalah orang-orang yang beriman). Lalu ia berwasiat kepada mereka seperti wasiat yang disampaikan oleh Nabi Ibrahim dan Ya'qub kepada anak-anaknya, (Hai anak-anakku! Sesungguhnya Allah telah memilih agama ini bagimu maka janganlah kamu mati kecuali dalam memeluk agama Islam). Ia juga berwasiat kepada mereka agar tidak keberatan menjadi penolong kaum Anshar dan menjadi saudara mereka dalam agama. Sesungguhnya sikap menjaga kehormatan diri dan kejujuran itu lebih baik dan lebih abadi dari pada zina dan dusta. Jika sesuatu terjadi pada diriku dalam sakitku ini sebelum aku mengubah wasiatku ini, kemudian ia menyebutkan keinginannya."},"2669":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسٍ قَالَ هَكَذَا كَانُوا يُوصُونَ هَذَا مَا أَوْصَى بِهِ فُلَانُ بْنُ فُلَانٍ أَنَّهُ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ { وَأَنَّ السَّاعَةَ آتِيَةٌ لَا رَيْبَ فِيهَا وَأَنَّ اللَّهَ يَبْعَثُ مَنْ فِي الْقُبُورِ } وَأَوْصَى مَنْ تَرَكَ بَعْدَهُ مِنْ أَهْلِهِ أَنْ يَتَّقُوا اللَّهَ وَيُصْلِحُوا ذَاتَ بَيْنِهِمْ وَأَنْ يُطِيعُوا اللَّهَ وَرَسُولَهُ إِنْ كَانُوا مُؤْمِنِينَ وَأَوْصَاهُمْ بِمَا أَوْصَى بِهِ إِبْرَاهِيمُ بَنِيهِ وَيَعْقُوبُ { يَا بَنِيَّ إِنَّ اللَّهَ اصْطَفَى لَكُمْ الدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ } وَأَوْصَى إِنْ حَدَثَ بِهِ حَدَثٌ مِنْ وَجَعِهِ هَذَا أَنَّ حَاجَتَهُ كَذَا وَكَذَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Bakr] telah menceritakan kepada kami [Hisyam bin Hassan] dari [Ibnu Sirin] dari [Anas] ia berkata; Seperti inilah mereka berwasiat; Ini adalah wasiat yang disampaikan oleh Fulan bin Fulan; Bahwa ia bersaksi tidak ada Tuhan yang berhak disembah selain Allah saja tiada sekutu bagiNya dan bahwa Muhammad adalah hamba dan utusanNya. Sesungguhnya hari kiamat pasti datang tanpa ada keraguan padanya. Dan sesungguhnya Allah akan membangkitkan orang-orang yang berada di dalam kubur. Ia juga berwasiat kepada keluarga yang ditinggalkannya agar bertaqwa kepada Allah dan memperbaiki hubungan di antara sesama mereka dan mentaati Allah dan RasulNya jika mereka adalah orang-orang yang beriman. Ia juga berwasiat kepada mereka seperti wasiat yang disampaikan oleh Nabi Ibrahim dan Ya'qub kepada anak-anaknya; (Hai anak-anakku! Sesungguhnya Allah telah memilih agama ini bagimu, maka janganlah kamu mati kecuali dalam memeluk agama Islam). Lalu ia berwasiat jika terjadi sesuatu pada dirinya akibat sakitnya ini, maka keinginannya adalah ini dan itu."},"2670":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا الْوَلِيدُ عَنْ حَفْصِ بْنِ غَيْلَانَ عَنْ مَكْحُولٍ حِينَ أَوْصَى قَالَ تَشَهُّدُ هَذَا مَا شَهِدَ بِهِ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَيُؤْمِنُ بِاللَّهِ وَيَكْفُرُ بِالطَّاغُوتِ عَلَى ذَلِكَ يَحْيَا إِنْ شَاءَ اللَّهُ وَيَمُوتُ وَيُبْعَثُ وَأَوْصَى فِيمَا رَزَقَهُ اللَّهُ فِيمَا تَرَكَ إِنْ حَدَثَ بِهِ حَدَثٌ وَهُوَ كَذَا وَكَذَا إِنْ لَمْ يُغَيِّرْ شَيْئًا مِمَّا فِي هَذِهِ الْوَصِيَّةِ حَدَّثَنَا الْحَكَمُ حَدَّثَنَا الْوَلِيدُ قَالَ أَخْبَرَنِي ابْنُ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ قَالَ هَذِهِ وَصِيَّةُ أَبِي الدَّرْدَاءِ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Al Walid] dari [Hafsh bin Ghailan] dari [Makhul] tatkala berwasiat ia berkata; ia berkata; Kesaksian ini adalah apa yang telah ia saksikan; Ia bersaksi bahwa tidak ada Tuhan yang berhak di sembah selain Allah saja, tiada sekutu bagiNya dan Muhammad adalah hamba Allah dan utusanNya, beriman kepada Allah dan kafir terhadap thaghut. Atas kesaksian ini ia hidup jika Allah menghendaki, ia mati dan dibangkitkan. Ia juga berwasiat kepda apa yang telah Allah rezkikan kepadanya terhadap apa yang ia tinggalkan. Jika terjadi sesuatu pada dirinya, maka seperti ini dan itu, jika ia tidak merubah sedikit pun dari apa yang telah tersebut dalam wasiat ini. Telah menceritakan kepada kami [Al Hakam] telah menceritakan kepada kami [Al Walid] ia berkata; Telah mengabarkan kepadaku [Ibnu Tsauban] dari [ayahnya] dari [Makhul] ia berkata; Ini adalah wasiat [Abu Ad Darda`]."},"2671":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِيهِ قَالَ كَتَبَ الرَّبِيعُ بْنُ خُثَيْمٍ وَصِيَّتَهُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا مَا أَوْصَى بِهِ الرَّبِيعُ بْنُ خُثَيْمٍ وَأَشْهَدَ اللَّهَ عَلَيْهِ وَكَفَى بِاللَّهِ شَهِيدًا وَجَازِيًا لِعِبَادِهِ الصَّالِحِينَ وَمُثِيبًا بِأَنِّي رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا وَإِنِّي آمُرُ نَفْسِي وَمَنْ أَطَاعَنِي أَنْ نَعْبُدَ اللَّهَ فِي الْعَابِدِينَ وَنَحْمَدَهُ فِي الْحَامِدِينَ وَأَنْ نَنْصَحَ لِجَمَاعَةِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Abu Hayyan At Taimi] dari [ayahnya] ia berkata; [Rabi' bin Khutsaim] pernah menulis wasiatnya sebagai berikut; Dengan nama Allah yang Maha Pengasih lagi Maha Penyayang, Ini adalah wasiat yang disampaikan oleh Rabi' bin Khutsaim, semoga Allah menyaksikan wasiat ini. Cukuplah Allah sebagai saksi dan pemberi balasan kepada orang-orang shalih dan pemberi pahala, karena sesungguhnya aku rela Allah sebagai Rabb, Islam sebagai agama dan Muhammad shallallahu 'alaihi wasallam sebagai nabi. Sesungguhnya aku memerintahkan kepada diriku dan orang yang taat kepadaku; Hendaklah kita beribadah kepada Allah bersama orang-orang yang beribadah dan memujiNya bersama orang-orang yang memuji serta selalu memberi nasehat kepada seluruh kaum muslimin."},"2672":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ عَنْ أَبِيهِ أَنَّ عَلِيًّا دَخَلَ عَلَى مَرِيضٍ فَذَكَرُوا لَهُ الْوَصِيَّةَ فَقَالَ عَلِيٌّ قَالَ اللَّهُ { إِنْ تَرَكَ خَيْرًا } وَلَا أُرَاهُ تَرَكَ خَيْرًا قَالَ حَمَّادٌ فَحَفِظْتُ أَنَّهُ تَرَكَ أَكْثَرَ مِنْ سَبْعِ مِائَةٍ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam] dari [ayahnya] bahwa Ali pernah menjenguk orang sakit, lalu mereka menyebutkan wasiatnya kepada Ali, maka [Ali] pun berkata; Allah berfirman: IN TARAKA KHAIRAN (Jika dia meninggalkan harta), namun aku tidak melihatnya meninggalkan khair (harta). Hammad berkata; Seingatku, ia meninggalkan harta lebih dari tujuh ratus."},"2673":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كُنَاسَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ قَالَ دَخَلَ عَلِيُّ بْنُ أَبِي طَالِبٍ عَلَى رَجُلٍ مِنْ قَوْمِهِ يَعُودُهُ فَقَالَ أُوصِي قَالَ لَا لَمْ تَدَعْ مَالًا فَدَعْ مَالَكَ لِوَلَدِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Kunasah] telah menceritakan kepada kami [Hisyam] dari [ayahnya] ia berkata; [Ali bin Abu Thalib] pernah menjenguk seorang laki-laki dari kaumnya. Lalu ia bertanya; Apakah aku berwasiat? Ia menjawab; Tidak. Ia bertanya; Engkau belum meninggalkan harta? Tinggalkanlah hartamu untuk anakmu."},"2674":{"ar":" حَدَّثَنَا أَبُو زَيْدٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ فِي رَجُلٍ أَوْصَى وَالْوَرَثَةُ شُهُودٌ مُقِرُّونَ فَقَالَ لَا يَجُوزُ قَالَ أَبُو مُحَمَّد يَعْنِي إِذَا أَنْكَرُوا بَعْدُ","id":"Telah menceritakan kepada kami [Abu Zaid] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] tentang seseorang yang berwasiat sementara para ahli waris menyaksikan dan menyutujui, ia pun berkata; Tidak boleh. Abu Muhammad berkata; Yakni, jika setelah itu mereka mengingkarinya."},"2675":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ قَالَ سَأَلْتُ الْحَكَمَ وَحَمَّادًا عَنْ الْأَوْلِيَاءِ يُجِيزُونَ الْوَصِيَّةَ فَإِذَا مَاتَ لَمْ يُجِيزُوا قَالَا لَا يَجُوزُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] ia berkata; Aku pernah bertanya kepada [Al Hakam] dan [Hammad] tentang para wali yang menyetujui wasiat, namun ketika ia meninggal dunia mereka tidak menyetujui? Maka keduanya menjawab; Tidak boleh."},"2676":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ شُرَيْحٍ فِي الرَّجُلِ يُوصِي بِأَكْثَرَ مِنْ ثُلُثِهِ قَالَ إِنْ أَجَازَتْهُ الْوَرَثَةُ أَجَزْنَاهُ وَإِنْ قَالَتْ الْوَرَثَةُ أَجَزْنَاهُ فَهُمْ بِالْخِيَارِ إِذَا نَفَضُوا أَيْدِيَهُمْ مِنْ الْقَبْرِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] dari [Dawud bin Abu Hind] dari [Amir] dari [Syuraih] tentang seseorang yang berwasiat lebih dari sepertiga hartanya, ia berkata; Jika para ahli waris menyetujuinya maka kami membolehkannya dan jika para ahli waris telah berkata; Kami menyetujuinya, maka mereka boleh memilih jika mereka telah mengibaskan tangan mereka dari kuburan."},"2677":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ أَبِي عَوْنٍ عَنْ الْقَاسِمِ أَنَّ رَجُلًا اسْتَأْذَنَ وَرَثَتَهُ أَنْ يُوصِيَ بِأَكْثَرَ مِنْ الثُّلُثِ فَأَذِنُوا لَهُ ثُمَّ رَجَعُوا فِيهِ بَعْدَ مَا مَاتَ فَسُئِلَ عَبْدُ اللَّهِ عَنْ ذَلِكَ فَقَالَ هَذَا التَّكَرُّهُ لَا يَجُوزُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Mas'udi] dari [Abu 'Aun] dari [Al Qasim] bahwa seorang laki-laki meminta izin kepada para ahli warisnya untuk berwasiat lebih dari sepertiga hartanya. Mereka pun mengizinkannya kemudian mereka membatalkan persetujuan mereka setelah laki-laki tersebut meninggal dunia. Maka ketika [Abdullah] ditanya tentang hal itu, ia menjawab; Pembatalan persetujuan ini tidak boleh."},"2678":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ فِي الرَّجُلِ يُوصِي بِأَكْثَرَ مِنْ الثُّلُثِ فَرَضِيَ الْوَرَثَةُ قَالَ هُوَ جَائِزٌ قَالَ أَبُو مُحَمَّد أَجَزْنَاهُ يَعْنِي فِي الْحَيَاةِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam] dari [Al Hasan] tentang seorang laki-laki yang berwasiat lebih dari sepertiga harta, namun para ahli warisnya setuju, ia berkata; Boleh. Abu Muhammad berkata; Kami membolehkannya, yakni selama masih hidup."},"2679":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهِ وَهُوَ بِمَكَّةَ وَلَيْسَ لَهُ إِلَّا ابْنَةٌ فَقُلْتُ لَهُ إِنَّهُ لَيْسَ لِي إِلَّا ابْنَةٌ وَاحِدَةٌ فَأُوصِي بِمَالِي كُلِّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قُلْتُ فَأُوصِي بِالنِّصْفِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ فَأُوصِي بِالثُّلُثِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Yunus bin Jubair] dari [Muhammad bin Sa'd] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam menemuinya saat beliau berada di Makkah dan ia hanya memiliki seorang anak perempuan. Aku pun bertanya kepada beliau; Sesungguhnya aku hanya memiliki seorang anak perempuan, bolehkah aku mewasiatkan seluruh hartaku kepadanya? Nabi shallallahu 'alaihi wasallam menjawab: \"Tidak.\" Aku bertanya lagi; Bolehkah aku mewasiatkan setengah? Beliau mengatakan kepadanya: \"Tidak.\" Aku bertanya; Bolehkah aku mewasiatkan sepertiga? Ia mengatakan; Rasulullah shallallahu 'alaihi wasallam menjawab: \"Boleh sepertiga dan sepertiga itu banyak.\""},"2680":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَ اشْتَكَيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ حَتَّى أُدْنِفْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أُرَانِي إِلَّا لِمَا بِي وَأَنَا ذُو مَالٍ كَثِيرٍ وَإِنَّمَا يَرِثُنِي ابْنَةٌ لِي أَفَأَتَصَدَّقُ بِمَالِي كُلِّهِ قَالَ لَا قُلْتُ فَبِنِصْفِهِ قَالَ لَا قُلْتُ فَالثُّلُثِ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ إِنَّكَ إِنْ تَتْرُكْ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَتْرُكَهُمْ فُقَرَاءَ يَتَكَفَّفُونَ النَّاسَ بِأَيْدِيهِمْ وَإِنَّكَ لَا تُنْفِقُ نَفَقَةً إِلَّا آجَرَكَ اللَّهُ فِيهَا حَتَّى مَا تَجْعَلُ فِي فِي امْرَأَتِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Amir bin Sa'd] dari [ayahnya] ia berkata; Aku mengadukan sakitku kepada Nabi shallallahu 'alaihi wasallam pada saat haji wada' hingga ketika sakitku semakin parah, Rasulullah shallallahu 'alaihi wasallam datang menjengukku. Aku katakan; Wahai Rasulullah, aku kira sakitku semakin parah sementara aku memiliki banyak harta dan ahli warisku hanya anak perempuanku. Apakah aku boleh menyedekahkan seluruh hartaku? Beliau menjawab: \"Tidak.\" Aku berkata; Bagaimana setengahnya? Beliau menjawab; \"Tidak.\" Aku berkata; Sepertiga? Beliau menjawab: \"Sepertiga dan sepertiga itu sudah banyak. Sesungguhnya engkau jika meninggalkan para ahli warismu dalam keadaan kaya adalah lebih baik dari pada engkau meninggalkan mereka dalam keadaan fakir, meminta-minta kepada manusia dengan tangan mereka. Sesungguhnya tidaklah engkau menafkahkan suatu nafkah kecuali Allah akan memberi balasan di dalamnya untukmu hingga sesuatu yang engkau letakkan di mulut istrimu.\""},"2681":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ إِسْحَقَ بْنِ سُوَيْدٍ عَنْ الْعَلَاءِ بْنِ زِيَادٍ أَنَّ أَبَاهُ زِيَادَ بْنَ مَطَرٍ أَوْصَى فَقَالَ وَصِيَّتِي مَا اتَّفَقَ عَلَيْهِ فُقَهَاءُ أَهْلِ الْبَصْرَةِ فَسَأَلْتُ فَاتَّفَقُوا عَلَى الْخُمُسِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ishaq bin Suwaid] dari [Al 'Ala` bin Ziyad] bahwa ayahnya [Ziyad bin Mathar] pernah berwasiat seraya berkata; Wasiatku adalah apa yang disepakati oleh para fuqaha` Bashrah. Maka ketika aku tanyakan, mereka sepakat atas seperlima."},"2682":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ إِسْحَقَ بْنِ سُوَيْدٍ عَنْ الْعَلَاءِ بْنِ زِيَادٍ أَنَّ رَجُلًا سَأَلَ عُمَرَ بْنَ الْخَطَّابِ فَقَالَ إِنَّ وَارِثِي كَلَالَةٌ فَأُوصِي بِالنِّصْفِ قَالَ لَا قَالَ فَالثُّلُثِ قَالَ لَا قَالَ فَالرُّبُعِ قَالَ لَا قَالَ فَالْخُمُسِ قَالَ لَا حَتَّى صَارَ إِلَى الْعُشْرِ فَقَالَ أَوْصِ بِالْعُشْرِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ishaq bin Suwaid] dari [Al 'Ala` bin Ziyad] bahwa seorang laki-laki pernah bertanya kepada [Umar bin Al Khaththab], ia berkata; Sesungguhnya ahli warisku adalah kalalah, apakah aku boleh berwasiat dengan setengah harta? Ia menjawab; Tidak. Ia bertanya lagi; Sepertiga? Ia menjawab; Tidak. Ia bertanya lagi; Seperempat? Ia menjawab; Tidak. Ia bertanya; Seperlima? Ia menjawab; Tidak. Hingga ketika sampai sepersepuluh, ia menjawab; Berwasiatlah dengan sepersepuluh. "},"2683":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ قَالَ إِنَّمَا كَانُوا يُوصُونَ بِالْخُمُسِ وَالرُّبُعِ وَكَانَ الثُّلُثُ مُنْتَهَى الْجَامِحِ قَالَ أَبُو مُحَمَّد يَعْنِي بِالْجَامِحِ الْفَرَسَ الْجَمُوحَ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari [Amir] ia berkata; Sesungguhnya mereka berwasiat dengan seperlima dan seperempat. Sedangkan sepertiga sangat jamih. Abu Muhammad berkata; Al Jamih adalah kuda liar yang tidak patuh kepada pemiliknya."},"2684":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ بَكْرٍ قَالَ أَوْصَيْتُ إِلَى حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ فَقَالَ مَا كُنْتُ لِأَقْبَلَ وَصِيَّةَ رَجُلٍ لَهُ وَلَدٌ يُوصِي بِالثُّلُثِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Bakr] ia berkata; Aku pernah berwasiat kepada [Humaid bin Abdurrahman], lalu ia berkata; Aku tidak mau menerima wasiat orang memiliki anak berwasiat dengan sepertiga harta."},"2685":{"ar":" حَدَّثَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ شُرَيْحٍ قَالَ الثُّلُثُ جَهْدٌ وَهُوَ جَائِزٌ","id":"Telah menceritakan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Hisyam] dari [Muhammad bin Sirin] dari [Syuraih] ia berkata; Sepertiga sangat berat namun itu boleh."},"2686":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ كَانَ السُّدُسُ أَحَبَّ إِلَيْهِمْ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] ia berkata; Seperenam lebih mereka sukai dari pada sepertiga."},"2687":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شَرِيكٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ الْوَصِيُّ أَمِينٌ فِيمَا أُوصِيَ إِلَيْهِ بِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syarik] dari [Mughirah] dari [Ibrahim] ia berkata; Orang yang diberi wasiat harus amanah terhadap apa yang diwasiatkan kepadanya."},"2688":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ ابْنِ وَهْبٍ عَنْ مَكْحُولٍ قَالَ أَمْرُ الْوَصِيِّ جَائِزٌ فِي كُلِّ شَيْءٍ إِلَّا فِي الِابْتِيَاعِ وَإِذَا بَاعَ بَيْعًا لَمْ يُقِلْ وَهُوَ رَأْيُ يَحْيَى بْنِ حَمْزَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Ibnu Wahb] dari [Makhul] ia berkata; Tindakan orang yang diberi wasiat boleh pada segala hal kecuali dalam hal membeli dirinya sendiri. Jika ia menjual suatu barang maka tidak boleh dibatalkan. Ini adalah pendapat Yahya bin Hamzah."},"2689":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ الْوَصِيُّ أَمِينٌ فِي كُلِّ شَيْءٍ إِلَّا فِي الْعِتْقِ فَإِنَّ عَلَيْهِ أَنْ يُقِيمَ الْوَلَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya bin Abu Katsir] ia berkata; Orang yang diberi wasiat berhak atas segala sesuatu kecuali memerdekakan, sebab kewajibannya adalah memelihara kepemilikan budak."},"2690":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ فِي مَالِ الْيَتِيمِ يَعْمَلُ بِهِ الْوَصِيُّ إِذَا أَوْصَى إِلَى الرَّجُلِ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] tentang harta anak yatim; Orang yang diberi wasiat berhak mengelolanya jika ia mewasiatkan kepada seseorang."},"2691":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا مُوسَى بْنُ مُحَمَّدٍ عَنْ إِسْمَعِيلَ عَنْ الْحَسَنِ قَالَ وَصِيُّ الْيَتِيمِ يَأْخُذُ لَهُ بِالشُّفْعَةِ وَالْغَائِبُ عَلَى شُفْعَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Musa bin Muhammad] dari [Isma'il] dari [Al Hasan] ia berkata; Hak wasiat untuk mengurusi anak yatim diambil secara syuf'ah, Orang yang tidak ada di tempat juga memiliki hak syuf'ah. "},"2692":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عِكْرِمَةَ عَنْ شَيْخٍ مِنْ أَهْلِ دِمَشْقَ قَالَ كُنْتُ عِنْدَ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ وَعِنْدَهُ سُلَيْمَانُ بْنُ حَبِيبٍ وَأَبُو قِلَابَةَ إِذْ دَخَلَ غُلَامٌ فَقَالَ أَرْضُنَا بِمَكَانِ كَذَا وَكَذَا بَاعَكُمْ الْوَصِيُّ وَنَحْنُ أَطْفَالٌ فَالْتَفَتَ إِلَى سُلَيْمَانَ بْنِ حَبِيبٍ فَقَالَ مَا تَقُولُ فَأَضْجَعَ فِي الْقَوْلِ فَالْتَفَتَ إِلَى أَبِي قِلَابَةَ فَقَالَ مَا تَقُولُ قَالَ رُدَّ عَلَى الْغُلَامِ أَرْضَهُ قَالَ إِذًا يَهْلِكُ مَالُنَا قَالَ أَنْتَ أَهْلَكْتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Ikrimah] dari [seorang syaikh penduduk Damsyiq] ia berkata; Aku pernah berada di sisi Umar bin Abdul Aziz, saat itu di sebelahnya ada Sulaiman bin Habib dan Abu Qilabah. Ketika itu ada seorang anak muda masuk seraya berkata; Lahan kami yang ada di tempat ini dan itu dijual oleh orang yang diberi wasiat kepada kalian saat kami masih kecil. Maka (Umar) menoleh kepada Sulaiman bin Habib dan bertanya; Apa yang akan engkau katakan? Ia menjawab dengan singkat, ia pun menoleh ke arah [Abu Qilabah] dan bertanya; Apa yang akan engkau katakan? Ia menjawab; Kembalikan lahan tersebut kepada anak muda ini. (Sulaiman) berkata; Kalau begitu hilanglah harta kita. Ia menjawab; Engkaulah yang menghilangkannya."},"2693":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ عَنْ أَشْعَثَ عَنْ الْحَسَنِ فِي رَجُلٍ أَوْصَى لِرَجُلٍ بِنِصْفِ مَالِهِ وَلِآخَرَ بِثُلُثِ مَالِهِ قَالَ يَضْرِبَانِ بِذَلِكَ فِي الثُّلُثِ هَذَا بِالنِّصْفِ وَهَذَا بِالثُّلُثِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] dari [Muhammad bin Abdullah] dari [Asy'ats] dari [Al Hasan] tentang seseorang yang mewasiatkan setengah hartanya kepada seseorang dan sepertiga hartanya kepada orang lain, ia berkata; Bagian mereka itu diambil dari sepertiga harta. Untuk orang ini setengahnya dan orang itu sepertiganya."},"2694":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زَائِدَةُ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ قَالَ يُغَيِّرُ صَاحِبُ الْوَصِيَّةِ مِنْهَا مَا شَاءَ غَيْرَ الْعَتَاقَةِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Za`idah] dari [Asy Syaibani] dari [Asy Sya'bi] ia berkata; Orang yang memberi wasiat boleh merubah sesukanya kecuali pemerdekaan."},"2695":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ يُحْدِثُ الرَّجُلُ فِي وَصِيَّتِهِ مَا شَاءَ وَمِلَاكُ الْوَصِيَّةِ آخِرُهَا","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Amr bin Syu'aib] dari [Abdullah bin Abu Rabi'ah] bahwa [Umar bin Al Khaththab] berkata; Seseorang boleh melakukan apa saja pada wasiatnya. Sandaran wasiat adalah yang diwasiatkan terakhir."},"2696":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنِي قَتَادَةُ قَالَ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ أَبَاهُ أَعْتَقَ رَقِيقًا لَهُ فِي مَرَضِهِ ثُمَّ بَدَا لَهُ أَنْ يَرُدَّهُمْ وَيُعْتِقَ غَيْرَهُمْ قَالَ فَخَاصَمُونِي إِلَى عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ فَأَجَازَ عِتْقَ الْآخِرِينَ وَأَبْطَلَ عِتْقَ الْأَوَّلِينَ","id":"Telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Hammam] ia berkata; Telah menceritakan kepadaku [Qatadah] ia berkata; Telah menceritakan kepadaku [Amr bin Dinar] bahwa ayahnya memerdekakan seorang budak miliknya pada waktu ia sakit. Kemudian ia ingin membatalkan pemerdekaannya itu dan memerdekakan budak yang lain. Ia berkata; Mereka mengadukanku kepada [Abdul Malik bin Marwan], maka ia membolehkan kemerdekaan yang terakhir dan membatalkan kemerdekaan yang pertama."},"2697":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا هَمَّامٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ عَنْ الشَّرِيدِ بْنِ سُوَيْدٍ قَالَ قَالَ عُمَرُ يُحْدِثُ الرَّجُلُ فِي وَصِيَّتِهِ مَا شَاءَ وَمِلَاكُ الْوَصِيَّةِ آخِرُهَا قَالَ أَبُو مُحَمَّد هَمَّامٌ لَمْ يَسْمَعْ مِنْ عَمْرٍو وَبَيْنَهُمَا قَتَادَةُ","id":"Telah menceritakan kepada kami [Sahal bin Hammad] telah menceritakan kepada kami [Hammam] dari [Amr bin Syu'aib] dari [Abdullah bin Abu Rabi'ah] dari [Asy Syarid bin Suwaid] ia berkata; [Umar] berkata; Seseorang boleh melakukan apa saja pada wasiatnya. Sandaran wasiat adalah yang terakhir. Abu Muhammad berkata; Hammam tidak mendengar dari Amr dan Qatadah berada di antara keduanya."},"2698":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ قَالَ ابْنُ الْمُبَارَكِ حَدَّثَنَا عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ فِي الرَّجُلِ يُوصِي بِوَصِيَّةٍ ثُمَّ يُوصِي بِأُخْرَى قَالَ هُمَا جَائِزَتَانِ فِي مَالِهِ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah], [Ibnu Al Mubarak] berkata; Telah menceritakan kepada kami dari [Ma'mar] dari [Az Zuhri] tentang seseorang yang mewasiatkan sebuah wasiat kemudian mewasiatkan wasiat lain, ia berkata; Keduanya boleh dilakukan pada hartanya sendiri."},"2699":{"ar":" حَدَّثَنَا سَعِيدٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ مِلَاكُ الْوَصِيَّةِ آخِرُهَا","id":"Telah menceritakan kepada kami [Sa'id] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Qatadah] ia berkata; [Umar bin Al Khaththab] berkata; Sandaran wasiat adalah yang diwasiatkan terakhir."},"2700":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى قَالَ إِذَا اتَّهَمَ الْقَاضِي الْوَصِيَّ لَمْ يَعْزِلْهُ وَلَكِنْ يُوَكِّلُ مَعَهُ غَيْرَهُ وَهُوَ رَأْيُ الْأَوْزَاعِيِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya] ia berkata; Jika hakim menuduh orang yang diberi wasiat maka ia tidak dibebaskan dari wasiatnya namun hakim menugaskan orang lain bersamanya dalam mengurusi wasiat. Ini adalah pendapat Al Auza'i."},"2701":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شَرِيكٌ عَنْ الشَّيْبَانِيِّ عَنْ عَامِرٍ قَالَ يَجُوزُ بَيْعُ الْمَرِيضِ وَشِرَاؤُهُ وَنِكَاحُهُ وَلَا يَكُونُ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syarik] dari [Asy Syaibani] dari [Amir] ia berkata; Orang sakit boleh melakukan transaksi jual beli dan menikah, namun hal itu tidak termasuk dari sepertiga."},"2702":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُطَرِّفٍ عَنْ الْحَارِثِ الْعُكْلِيِّ قَالَ مَا حَابَى بِهِ الْمَرِيضُ فِي مَرَضِهِ مِنْ بَيْعٍ أَوْ شِرَاءٍ فَهُوَ فِي ثُلُثِهِ قِيمَةُ عَدْلٍ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Abu 'Awanah] dari [Mutharrif] dari [Al Harits Al 'Ukli] ia berkata; Apa yang dibawa oleh orang sakit pada waktu sakitnya dari penjualan atau pembelian maka hak itu termasuk dalam sepertiga berdasarkan hitungan yang adil."},"2703":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى هُوَ ابْنُ سَعِيدٍ قَالَ أَعْطَتْ امْرَأَةٌ مِنْ أَهْلِنَا وَهِيَ حَامِلٌ فَسُئِلَ الْقَاسِمُ فَقَالَ هُوَ مِنْ جَمِيعِ الْمَالِ قَالَ يَحْيَى وَنَحْنُ نَقُولُ إِذَا ضَرَبَهَا الْمَخَاضُ فَمَا أَعْطَتْ فَمِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya] ia adalah Ibnu Sa'id, ia berkata; Seorang wanita hamil dalam keluarga kami memberikan hartanya, maka hal itu ditanyakan kepada [Al Qasim] ia pun menjawab; Diberikan dari seluruh harta. Yahya berkata; Sedangkan pendapat kami adalah jika kehamilannya telah berumur satu kali haidl, ia tidak boleh memberikan namun ia memberinya dari sepertiga harta."},"2704":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَمْرٍو عَنْ الْحَسَنِ فِي رَجُلٍ قَالَ لِغُلَامِهِ إِنْ دَخَلْتُ دَارَ فُلَانٍ فَغُلَامِي حُرٌّ ثُمَّ دَخَلَهَا وَهُوَ مَرِيضٌ قَالَ يُعْتَقُ مِنْ الثُّلُثِ وَإِنْ دَخَلَ فِي صِحَّتِهِ عُتِقَ مِنْ جَمِيعِ الْمَالِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Amr] dari [Al Hasan] tentang seseorang yang berkata kepada budaknya; Jika aku masuk rumah Fulan maka budakku merdeka. Kemudian ia memasukinya ketika sakit, ia berkata; Ia dimerdekakan dari sepertiga harta namun jika ia masuk rumah itu ketika sehatnya, ia dimerdekakan dari seluruh harta."},"2705":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا النُّعْمَانُ بْنُ الْمُنْذِرِ عَنْ مَكْحُولٍ قَالَ إِذَا كَانَ الْوَرَثَةُ مَحَاوِيجَ فَلَا أَرَى بَأْسًا أَنْ يُرَدَّ عَلَيْهِمْ مِنْ الثُّلُثِ قَالَ يَحْيَى فَذَكَرْتُ ذَلِكَ لِلْأَوْزَاعِيِّ فَأَعْجَبَهُ","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [An Nu'man bin Al Mundzir] dari [Makhul] ia berkata; Jika ahli waris adalah orang-orang yang membutuhkan maka aku berpendapat tidak apa-apa jika sepertiga harta tersebut dikembalikan kepada mereka. [Yahya] berkata; Kemudian aku menyebut hal itu kepada [Al Auza'i] dan ia menjadi heran."},"2706":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ ح و أَخْبَرَنَا مُغِيرَةُ عَنْ إِبْرَاهِيمَ قَالَا إِذَا شَهِدَ شَاهِدَانِ مِنْ الْوَرَثَةِ جَازَ عَلَى جَمِيعِهِمْ وَإِذَا شَهِدَ وَاحِدٌ فَفِي نَصِيبِهِ بِحِصَّتِهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Yunus] dari [Al Hasan], dalam riwayat lain; Dan telah mengabarkan kepada kami [Mughirah] dari [Ibrahim] keduanya berkata; Jika ada dua orang ahli waris bersaksi atas wasiat maka hal itu boleh mewakili untuk semuanya dan jika hanya satu orang yang bersaksi maka hitungannya sesuai dengan bagiannya."},"2707":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا مُطَرِّفٌ أَنَّهُ سَمِعَ الشَّعْبِيَّ يَقُولُ إِذَا شَهِدَ رَجُلٌ مِنْ الْوَرَثَةِ فَفِي نَصِيبِهِ بِحِصَّتِهِ ثُمَّ قَالَ بَعْدَ ذَلِكَ فِي جَمِيعِ حِصَّتِهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Mutharrif] bahwa ia pernah mendengar [Asy Sya'bi] berkata; Jika salah seorang dari ahli waris bersaksi maka bagiannya sesuai dengan perhitungannya. Kemudian setelah itu ia mengatakan; Untuk semuanya sesuai dengan bagiannya."},"2708":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا أَبُو شِهَابٍ عَبْدُ رَبِّهِ بْنُ نَافِعٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ إِذَا أَوْصَى الرَّجُلُ بِالثُّلُثِ وَالرُّبُعِ فَفِي الْعَيْنِ وَالدَّيْنِ وَإِذَا أَوْصَى بِخَمْسِينَ أَوْ سِتِّينَ إِلَى الْمِائَةِ فَفِي الْعَيْنِ حَتَّى يَبْلُغَ الثُّلُثَ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Abu Syihab Abdu Rabbihi bin Nafi'] dari [Al A'masy] dari [Ibrahim] ia berkata; Jika seseorang berwasiat dengan sepertiga atau seperempat hartanya maka diambil dari barang dan hutang, namun jika ia berwasiat dengan lima puluh atau enam puluh hingga seratus maka hanya dari barang hingga mencapai sepertiga."},"2709":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْءُ أَحَقُّ بِثُلُثِ مَالِهِ يَضَعُهُ فِي أَيِّ مَالِهِ شَاءَ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami [Ja'far bin Muhammad] dari [Yazid bin Abdullah bin Qusaith] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang lebih berhak terhadap sepertiga hartanya di mana saja akan ia tempatkan.\" Yakni, dari harta manapun yang ia kehendaki."},"2710":{"ar":" حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ أَبِي حَبِيبَةَ قَالَ سَأَلْتُ أَبَا الدَّرْدَاءِ عَنْ رَجُلٍ جَعَلَ دَرَاهِمَ فِي سَبِيلِ اللَّهِ فَقَالَ أَبُو الدَّرْدَاءِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَتَصَدَّقُ عِنْدَ مَوْتِهِ أَوْ يُعْتِقُ كَالَّذِي يُهْدِي بَعْدَ مَا شَبِعَ","id":"Telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Ishaq] dari [Abu Habibah] ia berkata; Aku bertanya kepada Abu Ad Darda` tentang seseorang yang menyedekahkan dirham (harta) nya fi sabilillah, [Abu Ad Darda`] pun menjawab; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang bersedekah atau membebaskan budak menjelang kematiannya bagaikan orang yang memberi hadiah setelah ia kenyang.\""},"2711":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ يُونُسَ عَنْ الْحَسَنِ فِي الرَّجُلِ يُوصِي بِأَشْيَاءَ وَفِيهَا الْعِتْقُ فَيُجَاوِزُ الثُّلُثَ قَالَ يُبْدَأُ بِالْعِتْقِ حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ بِالْحِصَصِ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Yunus] dari [Al Hasan] tentang seseorang mewasiatkan sesuatu yang terdapat hal pemerdekaan budak di dalamnya lalu wasiat itu melebihi sepertiga hartanya, ia berkata; Didahulukan pemerdekaan. Telah menceritakan kepada kami [Al Mu'alla bin Asad] ia berkata; Telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Muhammad] ia berkata; Didahulukan hitungan."},"2712":{"ar":" حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ حَدَّثَنَا الْمُعَافَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ عَطَاءٍ قَالَ مَنْ أَوْصَى أَوْ أَعْتَقَ فَكَانَ فِي وَصِيَّتِهِ عَوْلٌ دَخَلَ الْعَوْلُ عَلَى أَهْلِ الْعَتَاقَةِ وَأَهْلِ الْوَصِيَّةِ قَالَ وَقَالَ عَطَاءٌ إِنَّ أَهْلَ الْمَدِينَةِ غَلَبُونَا يَبْدَءُونَ بِالْعَتَاقَةِ قَبْلُ","id":"Telah menceritakan kepada kami [Al Hasan bin Bisyr] telah menceritakan kepada kami [Al Mu'afa] dari [Utsman bin Al Aswad] dari ['Atha`] ia berkata; Barangsiapa yang berwasiat atau memerdekakan budak sedangkan dalam wasiatnya itu terdapat 'aul, maka 'aul tersebut mengambil bagian dari orang yang memerdekakan budak dan orang yang berwasiat. Ia melanjutkan; ['Atha`] berkata; Sesungguhnya penduduk Madinah menyelisihi kami, mereka mendahulukan pemerdekaan. "},"2713":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ قَالَ عَمْرُو بْنُ دِينَارٍ فِي الَّذِي يُوصِي بِعِتْقٍ وَغَيْرِهِ فَيَزِيدُ عَلَى الثُّلُثِ قَالَ بِالْحِصَصِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] ia berkata; [Amr bin Dinar] berkata tentang orang yang berwasiat untuk pemerdekaan budak dan hal lainnya lalu melebihi sepertiga harta, ia berkata; Didahulukan hitungan."},"2714":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ كَثِيرِ بْنِ شِنْظِيرٍ عَنْ الْحَسَنِ فِي رَجُلٍ أَوْصَى بِأَكْثَرَ مِنْ الثُّلُثِ وَفِيهِ عِتْقٌ قَالَ يُبْدَأُ بِالْعِتْقِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Katsir bin Syinzhir] dari [Al Hasan] tentang seseorang yang berwasiat melebihi sepertiga harta dan termasuk di dalamnya pemerdekaan budak, ia berkata; Didahulukan pemerdekaan budak."},"2715":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ يُبْدَأُ بِالْعَتَاقَةِ قَبْلَ الْوَصِيَّةِ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] ia berkata; Didahulukan pemerdekaan budak sebelum wasiat."},"2716":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ يُونُسَ عَنْ الْحَسَنِ فِي الرَّجُلِ يُوصِي لِبَنِي فُلَانٍ قَالَ غَنِيُّهُمْ وَفَقِيرُهُمْ وَذَكَرُهُمْ وَأُنْثَاهُمْ سَوَاءٌ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] ia berkata; telah menceritakan kepada kami [Wuhaib] dari [Yunus] dari [Al Hasan] tentang seorang laki-laki yang berwasiat untuk anak orang lain, ia katakan, \"Kaya dan miskin, laki-laki dan perempuan mereka semua sama.\""},"2717":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَمْرٍو عَنْ الْحَسَنِ قَالَ إِذَا أَوْصَى لِبَنِي فُلَانٍ فَالذَّكَرُ وَالْأُنْثَى فِيهِ سَوَاءٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Amru] dari [Al Hasan] ia berkata, \"Jika seseorang berwasiat untuk anak orang lain maka laki-laki dan perempuan adalah sama.\""},"2718":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَائِدَةُ بْنُ مُوسَى الْهَمْدَانِيُّ حَدَّثَنِي سَيَّارُ بْنُ أَبِي كَرِبٍ أَنَّ آتِيًا أَتَى شُرَيْحًا فَسَأَلَهُ عَنْ رَجُلٍ أَوْصَى بِسَهْمٍ مِنْ مَالِهِ قَالَ تُحْسَبُ الْفَرِيضَةُ فَمَا بَلَغَ سِهَامَهَا أُعْطِيَ الْمُوصَى لَهُ سَهْمًا كَأَحَدِهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Za`idah bin Musa Al Hamdani] telah menceritakan kepadaku [Sayyar bin Abu Karb], bahwa ada seseorang mendatangi [Syuraih] dan bertanya kepadanya tentang seorang laki-laki yang berwasiat dari sebagian hartanya. Syuraih menjawab, \"Dihitung yang menjadi kewajibannya, jika melampaui bagian wasiat maka orang yang mendapatkan wasiat diberikan bagiannya seperti yang lainnya.\""},"2719":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَعِيدٌ عَنْ مَكْحُولٍ قَالَ إِذَا تَصَدَّقَ الرَّجُلُ عَلَى بَعْضِ وَرَثَتِهِ وَهُوَ صَحِيحٌ بِأَكْثَرَ مِنْ النِّصْفِ رُدَّ إِلَى الثُّلُثِ وَإِذَا أَعْطَى النِّصْفَ جَازَ لَهُ ذَلِكَ قَالَ سَعِيدٌ وَكَانَ قُضَاةُ أَهْلِ دِمَشْقَ يَقْضُونَ بِذَلِكَ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id] dari [Makhul] ia berkata, \"Jika seorang laki-laki bersedekah kepada sebagian ahli warisnya -sedangkan ia masih dalam keadaan sehat- lebih dari setengah hartanya, maka harus kurangi hingga hanya sepertiga. Dan jika ia memberikan setengah hartanya maka hal itu diperbolehkan baginya.\" Sa'id berkata, \"Para hakim Damaskus memutuskan hukum seperti itu.\""},"2720":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ قَالَ الْكَفَنُ مِنْ جَمِيعِ الْمَالِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Hafsh] dari [Isma'il bin Abu Khalid] dari [Al Hakam] dari [Ibrahim] ia berkata, \"Kafan diambil dari seluruh harta.\""},"2721":{"ar":" حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ مُعَاذٍ عَنْ أَشْعَثَ عَنْ الْحَسَنِ فِي رَجُلٍ مَاتَ وَتَرَكَ قِيمَةَ أَلْفَيْ دِرْهَمٍ وَعَلَيْهِ مِثْلُهَا أَوْ أَكْثَرُ قَالَ يُكَفَّنُ مِنْهَا وَلَا يُعْطَى دَيْنُهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] dari [Mu'adz] dari [Asy'ats] dari [Al Hasan] tentang seorang laki-laki yang meninggal dan ia meninggalkan harta senilai dua ratus dirham dan ia juga memiliki hutang sebanyak itu atau bahkan lebih, ia berkata, \"Kain kafan harus diambilkan dari harta tersebut meskipun hutangnya tidak lunas.\" "},"2722":{"ar":" حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَمَّنْ سَمِعَ إِبْرَاهِيمَ قَالَ يُبْدَأُ بِالْكَفَنِ ثُمَّ الدَّيْنِ ثُمَّ الْوَصِيَّةِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [seseorang] yang mendengar [Ibrahim] ia berkata, \"Yang harus didahulukan itu adalah pengkafanan, kemudian pelunasan hutang, kemudian wasiat.\""},"2723":{"ar":" حَدَّثَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ فِي الْمَرْأَةِ تَمُوتُ قَالَ تُكَفَّنُ مِنْ مَالِهَا لَيْسَ عَلَى الزَّوْجِ شَيْءٌ","id":"Telah menceritakan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Firas] dari [Asy Sya'bi] tentang seorang wanita yang meninggal, ia berkata, \"Ia harus dikafani dari hartanya tersebut, dan suaminya tidak mendapatkan apapun.\" "},"2724":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ الْحَنُوطُ وَالْكَفَنُ مِنْ رَأْسِ الْمَالِ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ibnu Juraij] dari ['Atha] ia berkata, \"Wewangian dan kafan diambil dari pokok harta.\""},"2725":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ إِسْمَعِيلَ عَنْ الْحَسَنِ قَالَ الْكَفَنُ مِنْ وَسَطِ الْمَالِ يُكَفَّنُ عَلَى قَدْرِ مَا كَانَ يَلْبَسُ فِي حَيَاتِهِ ثُمَّ يُخْرَجُ الدَّيْنُ ثُمَّ الثُّلُثُ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Isma'il] dari [Al Hasan] ia berkata, \"Kafan diambil dari kain yang biasa, ia dikafani sekedar apa yang ia kenakan pada masa hidupnya, kemudian harta dikeluarkan untuk membayar hutang kemudian sepertiga untuk wasiat.\""},"2726":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ عَنْ الْحَسَنِ أَنَّهُ كَانَ يَقُولُ إِذَا أَوْصَى الرَّجُلُ إِلَى الرَّجُلِ وَهُوَ غَائِبٌ فَلْيَقْبَلْ وَصِيَّتَهُ وَإِنْ كَانَ حَاضِرًا فَهُوَ بِالْخِيَارِ إِنْ شَاءَ قَبِلَ وَإِنْ شَاءَ تَرَكَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur] dari [Al Hasan] bahwa ia pernah berkata, \"Jika seorang laki-laki berwasiat kepada seseorang yang tidak ada di tempat hendaklah ia menerima wasiatnya, jika berada di tempat maka ia boleh memilih, jika mau ia bisa menerima dan jika mau ia bisa menolaknya.\" "},"2727":{"ar":" حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ سَأَلْتُ الْحَسَنَ وَمُحَمَّدًا عَنْ الرَّجُلِ يُوصِي إِلَى الرَّجُلِ قَالَا نَخْتَارُ أَنْ يَقْبَلَ","id":"Telah menceritakan kepada kami [Shalih bin Abdullah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] ia berkata, \"Aku bertanya kepada [Al Hasan] dan [Muhammad] tentang seseorang yang berwasiat kepada orang lain, keduanya berkata, \"Menurut kami hendaklah ia menerimanya.\""},"2728":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ أَسْعَدَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ إِذَا أَوْصَى الرَّجُلُ إِلَى الرَّجُلِ وَهُوَ غَائِبٌ فَإِذَا قَدِمَ فَإِنْ شَاءَ قَبِلَ فَإِذَا قَبِلَ لَمْ يَكُنْ لَهُ أَنْ يَرُدَّ","id":"Telah menceritakan kepada kami [Muhammad bin Asad] telah menceritakan kepada kami [Abu Bakar] dari [Hisyam] dari [Al Hasan] ia berkata, \"Jika seorang laki-laki berwasiat kepada orang lain yang tidak berada di tempat maka ketika datang, jika mau boleh menerimanya, dan jika ia telah menerima maka tidak boleh lagi menolaknya.\""},"2729":{"ar":" حَدَّثَنَا الْوَضَّاحُ بْنُ يَحْيَى حَدَّثَنَا أَبُو بَكْرٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ إِذَا أَوْصَى الرَّجُلُ إِلَى الرَّجُلِ فَعُرِضَتْ عَلَيْهِ الْوَصِيَّةُ وَكَانَ غَائِبًا فَقَبِلَ لَمْ يَكُنْ لَهُ أَنْ يَرْجِعَ","id":"Telah menceritakan kepada kami [Al Wadldlah bin Yahya] telah menceritakan kepada kami [Abu Bakar] dari [Hisyam] dari [Al Hasan] ia berkata, \"Jika seseorang berwasiat kepada orang lain lalu wasiat tersebut ditawarkan kepadanya, saat itu ia tidak berada di tempat dan ia menerima, maka tidak boleh baginya untuk menolak.\""},"2730":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ قَالَ إِذَا أَوْصَى الرَّجُلُ لِإِنْسَانٍ وَهُوَ غَائِبٌ وَكَانَ مَيِّتًا وَهُوَ لَا يَدْرِي فَهِيَ رَاجِعَةٌ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Sa'id] dari [Abu Ma'syar] dari [Ibrahim] ia berkata, \"Jika seseorang berwasiat kepada orang lain yang tidak berada di tempat dan ternyata ia telah meninggal, sedangkan orang yang berwasiat tidak tahu maka wasiat tersebut tidak berlaku.\""},"2731":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ قَالَ إِذَا أَوْصَى لِعَبْدِهِ ثُلُثَ مَالِهِ رُبُعَ مَالِهِ خُمُسَ مَالِهِ فَهُوَ مِنْ مَالِهِ دَخَلَتْهُ عَتَاقَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Yunus] dari [Al Hasan] ia berkata, \"Jika seseorang berwasiat kepada budaknya sepertiga, seperempat atau seperlima hartanya, maka harta itu termasuk harta budak. Pembebasannya yang memasukkannya.\""},"2732":{"ar":" حَدَّثَنَا يَعْلَى عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ قَالَ كَانَ يُقَالُ إِنَّ الرَّجُلَ لَيُحْرَمُ بَرَكَةَ مَالِهِ فِي حَيَاتِهِ فَإِذَا كَانَ عِنْدَ الْمَوْتِ تَزَوَّدَ بِفَجْرَةٍ","id":"Telah menceritakan kepada kami [Ya'la] dari [Isma'il] dari [Qais] ia berkata, \"Dikatakan, 'Sungguh, seorang laki-laki itu terhalang dari keberkahan hartanya semasa hidupnya jika pada saat kematiannya ia membawa kezhaliman terhadap ahli warisnya'.\""},"2733":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو زُبَيْدٍ حَدَّثَنَا حُصَيْنٌ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَ قَالَ عَبْدُ اللَّهِ الْمُرَّانِ الْإِمْسَاكُ فِي الْحَيَاةِ وَالتَّبْذِيرُ عِنْدَ الْمَوْتِ قَالَ أَبُو مُحَمَّد يُقَالُ مُرٌّ فِي الْحَيَاةِ وَمُرٌّ عِنْدَ الْمَوْتِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Zubaid] telah menceritakan kepada kami [Hushain] dari [Ibrahim At Taimi] dari [Ayahnya] ia berkata; [Abdullah] berkata, \"Ada dua kepahitan; kikir saat masih hidup dan foya-toya saat kematian.\" Abu Muhammad berkata, \"Dikatakan kepahitan ketika hidup dan kepahitan ketika meninggal dunia.\""},"2734":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ إِذَا أَوْصَى الرَّجُلُ لِآخَرَ بِمِثْلِ نَصِيبِ ابْنِهِ فَلَا يَتِمُّ لَهُ مِثْلُ نَصِيبِهِ حَتَّى يَنْقُصَ مِنْهُ","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Israil] dari [Manshur] dari [Ibrahim] ia berkata, \"Jika seseorang memberi wasiat untuk orang lain dengan jumlah seperti bagian anaknya, maka wasiat tidak diberikan seperti bagian anaknya tersebut hingga kurang dari itu.\""},"2735":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ فِي رَجُلٍ كَانَ لَهُ ثَلَاثَةُ بَنِينَ فَأَوْصَى لِرَجُلٍ مِثْلَ نَصِيبِ أَحَدِهِمْ لَوْ كَانُوا أَرْبَعَةً قَالَ الشَّعْبِيُّ يُعْطَى الْخُمُسَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] tentang seseorang yang memiliki tiga anak laki-laki lalu ia memberikan wasiat untuk orang lain dengan jumlah seperti bagian salah seorang dari mereka seandainya anaknya berjumlah empat orang.\" Asy Sya'bi berkata, \"Ia diberi seperlima.\""},"2736":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ قَالَ سَأَلْنَا عَامِرًا عَنْ رَجُلٍ تَرَكَ ابْنَيْنِ وَأَوْصَى بِمِثْلِ نَصِيبِ أَحَدِهِمْ لَوْ كَانُوا ثَلَاثَةً قَالَ أَوْصَى بِالرُّبُعِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Dawud bin Abu Hind] ia berkata, \"Kami bertanya kepada [Amir] tentang seseorang yang meninggalkan dua anak laki-laki dan berwasiat dengan jumlah seperti bagian salah seorang dari mereka seandainya anaknya berjumlah tiga orang.\" Amir lalu menjawab, \"Hendaklah ia berwasiat dengan seperempat.\""},"2737":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ فِي رَجُلٍ أَوْصَى بِمِثْلِ نَصِيبِ بَعْضِ الْوَرَثَةِ قَالَ لَا يَجُوزُ وَإِنْ كَانَ أَقَلَّ مِنْ الثُّلُثِ قَالَ أَبُو مُحَمَّد هُوَ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Ibrahim], ia berkata tentang seorang laki-laki yang memberi wasiat untuk orang lain sejumlah dengan bagian ahli waris, ia berkata, \"Tidak boleh sekalipun kurang dari sepertiga.\" Abu Muhammad berkata, \"Ini bagus.\""},"2738":{"ar":" حَدَّثَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ فِي رَجُلٍ أَوْصَى فِي غَلَّةِ عَبْدِهِ بِدِرْهَمٍ وَغَلَّتُهُ سِتَّةٌ قَالَ لَهُ سُدُسُهُ","id":"Telah menceritakan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Ibnu Abu As Safar] dari [Asy Sya'bi] tentang seorang laki-laki yang memberikan wasiat untuk budaknya senilai satu dirham, sementara budaknya berjumlah enam orang, maka bagian setiap mereka adalah seperenam.\" "},"2739":{"ar":" حَدَّثَنَا قَبِيصَةُ قَالَ سَمِعْتُ سُفْيَانَ يَقُولُ إِذَا أَقَرَّ لِوَارِثٍ وَلِغَيْرِ وَارِثٍ بِمِائَةِ دِرْهَمٍ أَرَى أَنْ أُبْطِلَهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Qabishah] ia berkata; Aku pernah mendengar [Sufyan] berkata, \"Jika seseorang menetapkan untuk ahli waris atau untuk yang bukan ahli waris dengan seratus dirham, maka menurutku wasiat untuk keduanya itu batal.\""},"2740":{"ar":" حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ ابْنِ سِيرِينَ عَنْ شُرَيْحٍ قَالَ لَا يَجُوزُ إِقْرَارٌ لِوَارِثٍ قَالَ و قَالَ الْحَسَنُ أَحَقُّ مَا جَازَ عَلَيْهِ عِنْدَ مَوْتِهِ أَوَّلَ يَوْمٍ مِنْ أَيَّامِ الْآخِرَةِ وَآخِرَ يَوْمٍ مِنْ أَيَّامِ الدُّنْيَا","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Ibnu Sirin] dari [Syuraih] ia berkata, \"Tidak boleh menetapkan wasiat untuk ahli waris.\" Ia berkata; [Al Hasan] berkata, \"Apa yang ia dapatkan pada saat kematian adalah, hari pertama dari hari-hari akhirat, dan hari terakhir dari hari-hari di dunia.\" "},"2741":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ قَالَ لَا يَجُوزُ لِوَارِثٍ وَصِيَّةٌ","id":"Telah menceritakan kepada kami [Amru bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Khalid] dari [Abu Qilabah] ia berkata, \"Tidak boleh bagi ahli waris menerima wasiat.\""},"2742":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ حُمَيْدٍ أَنَّ رَجُلًا يُكْنَى أَبَا ثَابِتٍ أَقَرَّ لِامْرَأَتِهِ عِنْدَ مَوْتِهِ أَنَّ لَهَا عَلَيْهِ أَرْبَعَ مِائَةِ دِرْهَمٍ مِنْ صَدَاقِهَا فَأَجَازَهُ الْحَسَنُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Humaid], bahwa seorang laki-laki yang bernama Abu Tsabit menetapkan untuk isterinya ketika ia hendak meninggal dunia, bahwa isterinya tersebut mendapat empat ratus dirham dari mas kawinnya. Dan [Al Hasan] membolehkannya.\""},"2743":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ عَمْرِو بْنِ خَارِجَةَ قَالَ كُنْتُ تَحْتَ نَاقَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ تَقْصَعُ بِجِرَّتِهَا وَلُعَابُهَا يَنُوصُ بَيْنَ كَتِفَيَّ سَمِعْتُهُ يَقُولُ أَلَا إِنَّ اللَّهَ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ فَلَا يَجُوزُ وَصِيَّةٌ لِوَارِثٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam Ad Dastawa`i] telah menceritakan kepada kami [Qatadah] dari [Syahr bin Hausyab] dari [Abdurrahman bin Ghanm] dari [Amru bin Kharijah] ia berkata, \"Aku pernah berada di bawah unta milik Nabi shallallahu 'alaihi wasallam yang sedang mengunyah makanan hingga air liurnya mengalir antara dua pundakku, aku mendengar beliau bersabda: \"Ketahuilah, sesungguhnya Allah telah memberikan kepada setiap orang apa yang telah menjadi haknya. Maka tidak boleh berwasiat kepada ahli waris.\""},"2744":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ { إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } فَأَمَرَ أَنْ يُوصِيَ لِوَالِدَيْهِ وَأَقَارِبِهِ ثُمَّ نُسِخَ بَعْدَ ذَلِكَ فِي سُورَةِ النِّسَاءِ فَجَعَلَ لِلْوَالِدَيْنِ نَصِيبًا مَعْلُومًا وَأَلْحَقَ لِكُلِّ ذِي مِيرَاثٍ نَصِيبَهُ مِنْهُ وَلَيْسَتْ لَهُمْ وَصِيَّةٌ فَصَارَتْ الْوَصِيَّةُ لِمَنْ لَا يَرِثُ مِنْ قَرِيبٍ وَغَيْرِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dari [Qatadah] ia berkata tentang firman-Nya: '(Apabila seorang di antara kamu kedatangan (tanda-tanda) maut, jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) '. (Qs. Al Baqarah: 180), Allah memerintahkan agar berwasiat kepada kedua orang tua dan karib kerabatnya. Kemudian hukum ini dihapus dengan ayat di dalam surat An Nisaa`. Dia menetapkan bahwa kedua orang tua telah mendapatkan bagian yang telah ditentukan, dan memberikan warisan kepada setiap orang yang berhak mendapat warisan dari harta warisannya, dan tidak ada lagi wasiat bagi mereka. Wasiat hanya diberikan kepada orang-orang yang tidak berhak mewarisi baik dari kerabat maupun lainnya.\""},"2745":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ الْمَالُ لِلْوَلَدِ وَكَانَتْ الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ فَنَسَخَ اللَّهُ مِنْ ذَلِكَ مَا أَحَبَّ فَجَعَلَ لِلذَّكَرِ مِثْلَ حَظِّ الْأُنْثَيَيْنِ وَجَعَلَ لِلْأَبَوَيْنِ لِكُلِّ وَاحِدٍ مِنْهُمَا السُّدُسَ وَالثُّلُثَ وَجَعَلَ لِلْمَرْأَةِ الثُّمُنَ وَالرُّبُعَ وَلِلزَّوْجِ الشَّطْرَ وَالرُّبُعَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Warqa`] dari [Ibnu Abu Najih] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Harta adalah untuk anak sedangkan wasiat untuk kedua orang tua dan kerabat, lalu Allah menghapus dari hal itu apa yang Dia kehendaki. Allah menjadikan bagian untuk laki-laki seperti bagian dua perempuan, kedua orang tua masing-masing seperenam dan sepertiga, untuk isteri seperdelapan dan seperempat, dan untuk suami setengah dan seperempat.\""},"2746":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ يَزِيدَ عَنْ عِكْرِمَةَ وَالْحَسَنِ { إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } وَكَانَتْ الْوَصِيَّةُ كَذَلِكَ حَتَّى نَسَخَتْهَا آيَةُ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Ahmad bin Isma'il] telah menceritakan kepada kami [Abu Tumailah] dari [Al Husain bin Waqid] dari [Yazid] dari [Ikrimah] dan [Al Hasan] tentang ayat: '(Jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) ' (Qs. Al Baqarah: 180), begitulah wasiat dahulu hingga dihapus oleh ayat tentang harta warisan.\""},"2747":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ سُئِلَ عَنْ رَجُلٍ أَوْصَى وَلَهُ أَخٌ مُوسِرٌ أَيُوصِ لَهُ قَالَ نَعَمْ وَإِنْ كَانَ رَبَّ عِشْرِينَ أَلْفًا ثُمَّ قَالَ وَإِنْ كَانَ رَبَّ مِائَةِ أَلْفٍ فَإِنَّ غِنَاهُ لَا يَمْنَعُهُ الْحَقَّ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Al Hasan], ia ditanya tentang seseorang yang berwasiat sedangkan ia memiliki saudara yang kaya, apakah ia boleh berwasiat kepadanya?\" Ia menjawab, 'Ya, sekalipun ia memiliki dua puluh ribu.\" Kemudian ia berkata, \"Dan sekalipun ia memiliki seratus ribu, sebab kekayaannya tidak menghalanginya untuk memperoleh hak.\""},"2748":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ وَسَعِيدُ بْنُ الْمُسَيَّبِ فِي رَجُلٍ قَالَ سَيْفِي لِفُلَانٍ فَإِنْ مَاتَ فُلَانٌ فَلِفُلَانٍ فَإِنْ مَاتَ فُلَانٌ فَمَرْجِعُهُ إِلَيَّ قَالَا هُوَ لِلْأَوَّلِ قَالَ وَقَالَ حُمَيْدُ ابْنُ عَبْدِ الرَّحْمَنِ يُمْضَى كَمَا قَالَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dan [Sa'id bin Al Musayyab] tentang seseorang yang berkata, 'Pedangku untuk Fulan, jika ia meninggal maka untuk Fulan (orang kedua) dan jika ia meninggal maka kembali kepadaku.' Mereka berdua menjawab, \"Pedang itu untuk yang pertama.\" [Humaid bin Abdurrahman] berkata, \"Berlaku seperti apa yang ia katakan.\""},"2749":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ أَنَّ عُرْوَةَ قَالَ فِي الرَّجُلِ يُعْطِي الرَّجُلَ الْعَطَاءَ فَيَقُولُ هُوَ لَكَ فَإِذَا مُتَّ فَلِفُلَانٍ فَإِذَا مَاتَ فُلَانٌ فَلِفُلَانٍ وَإِذَا مَاتَ فُلَانٌ فَمَرْجِعُهُ إِلَيَّ قَالَ يُمْضَى كَمَا قَالَ وَإِنْ كَانُوا مِائَةً","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Hisyam bin Urwah] ia berkata tentang seorang laki-laki yang memberikan kepada orang lain suatu pemberian, ia katakan, \"Itu untukmu, jika engkau meninggal maka ia untuk Fulan dan jika Fulan tersebut meninggal maka untuk fulan, jika fulan itu juga meninggal maka ia kembali kepadaku.\" [Urwah] berkata, \"Berlaku seperti apa yang ia katakan, sekalipun jumlah mereka seratus orang.\""},"2750":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا شَيْبَةُ بْنُ هِشَامٍ الرَّاسِبِيُّ وَكَثِيرُ بْنُ مَعْدَانَ قَالَا سَأَلْنَا سَالِمَ بْنَ عَبْدِ اللَّهِ عَنْ الرَّجُلِ يُوصِي فِي غَيْرِ قَرَابَتِهِ فَقَالَ سَالِمٌ هِيَ حَيْثُ جَعَلَهَا قَالَ فَقُلْنَا إِنَّ الْحَسَنَ يَقُولُ يُرَدُّ عَلَى الْأَقْرَبِينَ فَأَنْكَرَ ذَلِكَ وَقَالَ قَوْلًا شَدِيدًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Syaibah bin Hisyam Ar Rasibi] dan [Katsir bin Ma'dan] keduanya berkata, \"Kami bertanya kepada [Salim bin Abdullah] tentang seseorang yang berwasiat kepada selain kerabatnya. Salim menjawab, \"Wasiat itu dilakukan sesuai yang diwasiatkan.\" Katsir melanjutkan, \"Kami katakan, \"Sesungguhnya [Al Hasan] berkata, 'Dikembalikan kepada para kerabat.' Namun Salim mengingkari hal itu dan ia mengucapkan kata-kata yang keras.\""},"2751":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَمْرٍو عَنْ الْحَسَنِ قَالَ إِذَا أَوْصَى الرَّجُلُ فِي قَرَابَتِهِ فَهُوَ لِأَقْرَبِهِمْ بِبَطْنٍ الذَّكَرُ وَالْأُنْثَى فِيهِ سَوَاءٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Amru] dari [Al Hasan] ia berkata, \"Jika seseorang berwasiat untuk kerabatnya maka wasiat itu untuk kerabat yang terdekat, laki-laki dan perempuan sama.\""},"2752":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو بَكْرٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ فِي رَجُلٍ قَالَ أَحَدُ غُلَامَيَّ حُرٌّ ثُمَّ مَاتَ وَلَمْ يُبَيِّنْ قَالَ الْوَرَثَةُ بِمَنْزِلَتِهِ يُعْتِقُونَ أَيَّهُمَا أَحَبُّوا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Bakar] dari [Mutharrif] dari [Asy Sya'bi] tentang seorang laki-laki yang berkata, 'Salah satu budakku merdeka.' Kemudian laki-laki itu meninggal sebelum menjelaskan budak yang dimaksud. Asy Sya'bi berkata, \"Ahli waris sama kedudukannya dengan mayit, mereka boleh memerdekakan siapa yang lebih baik dimerdekakan.\""},"2753":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يُونُسَ عَنْ الْحَسَنِ أَنَّ رَجُلًا قَالَ فِي مَرَضِهِ لِفُلَانٍ كَذَا وَلِفُلَانٍ كَذَا وَعَبْدِي فُلَانٌ حُرٌّ وَلَمْ يَقُلْ إِنْ حَدَثَ بِي حَدَثٌ فَبَرَأَ قَالَ هُوَ مَمْلُوكٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Yunus] dari [Al Hasan] tentang seseorang yang berkata ketika sakit, 'Untuk fulan sekian, untuk fulan sekian dan budakku si fulan merdeka, ' tanpa mengatakan 'jika terjadi sesuatu padaku', lalu ia sembuh. Al Hasan berkata, \"Budak itu tetap menjadi budak.\""},"2754":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو بَكْرٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ فِي رَجُلٍ أَعْتَقَ غُلَامَهُ عِنْدَ الْمَوْتِ وَلَيْسَ لَهُ غَيْرُهُ وَعَلَيْهِ دَيْنٌ قَالَ يَسْعَى لِلْغُرَمَاءِ فِي ثَمَنِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Bakar] dari [Mutharrif] dari [Asy Sya'bi] tentang seseorang yang memerdekakan budaknya ketika menjelang kematiannya dan ia tidak memiliki harta selain budak tersebut sedangkan ia memiliki hutang, ia (Asy Sya'bi) berkata, \"Budak tersebut harus berusaha melunasi hutang tersebut dengan harga dirinya.\""},"2755":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ أَنَّ رَجُلًا اشْتَرَى عَبْدًا بِتِسْعِ مِائَةِ دِرْهَمٍ فَأَعْتَقَهُ وَلَمْ يَقْضِ ثَمَنَ الْعَبْدِ وَلَمْ يَتْرُكْ شَيْئًا فَقَالَ عَلِيٌّ يَسْعَى الْعَبْدُ فِي ثَمَنِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan], bahwa seseorang membeli budak dengan harga sembilan ratus dirham, lalu ia memerdekakannya namun uang pembayarannya belum selesai, sementara ia tidak meninggalkan sedikit pun harta. Maka Ali berkata, \"Budak itu harus berusaha untuk membayar dirinya.\""},"2756":{"ar":" حَدَّثَنَا مَنْصُورُ بْنُ سَلَمَةَ عَنْ شَرِيكٍ عَنْ الْأَشْعَثِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ الْمُدَبَّرُ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Manshur bin Salamah] dari [Syarik] dari [Al Asy'ats] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Al Mudabbar termasuk sepertiga wasiat.\" "},"2757":{"ar":" حَدَّثَنَا مَنْصُورُ بْنُ سَلَمَةَ عَنْ شَرِيكٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ الْمُدَبَّرُ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Manshur bin Salamah] dari [Syarik] dari [Manshur] dari [Ibrahim] ia berkata, \"Al Mudabbar termasuk dalam sepertiga wasiat.\" "},"2758":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ كَثِيرٍ عَنْ الْحَسَنِ قَالَ الْمُعْتَقُ عَنْ دُبُرٍ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Katsir] dari [Al Hasan] ia berkata, \"Budak yang dimerdekakan sepeninggal tuannya termasuk dalam sepertiga harta (yang boleh diwasiatkan).\""},"2759":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ قَالَ الْمُعْتَقَةُ عَنْ دُبُرٍ وَوَلَدُهَا مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Al Hasan] ia berkata, \"Budak wanita dan anak laki-lakinyanya yang dimerdekakan sepeninggal tuannya termasuk dalam sepertiga harta (yang boleh diwasiatkan).\""},"2760":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ مَنْصُورٌ أَخْبَرَنِي عَنْ إِبْرَاهِيمَ قَالَ الْمُعْتَقُ عَنْ دُبُرٍ مِنْ الثُّلُثِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], [Manshur] berkata; telah mengabarkan kepadaku dari [Ibrahim] ia berkata, \"Budak yang dimerdekakan sepeninggal tuannya termasuk dalam sepertiga harta (yang bisa diwasiatkan).\""},"2761":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي عَبْدِ اللَّهِ الشَّقَرِيِّ وَأَبِي هَاشِمٍ عَنْ إِبْرَاهِيمَ قَالَ الْمُدَبَّرُ مِنْ جَمِيعِ الْمَالِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Abdullah Asy Syaqari] dan [Abu Hasyim] dari [Ibrahim] ia berkata, \"Al Mudabbar termasuk dari keseluruhan harta.\" "},"2762":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ الْمُعْتَقُ عَنْ دُبُرٍ مِنْ جَمِيعِ الْمَالِ سُئِلَ أَبُو مُحَمَّد بِأَيِّهِمَا تَقُولُ قَالَ مِنْ الثُّلُثِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata, \"Budak yang dimerdekakan sepeninggal tuannya termasuk dalam keseluruhan harta.\" Ketika Abu Muhammad ditanya, \"Manakah pendapat yang engkau ambil dari keduanya?\" Ia menjawab, \"Termasuk dari sepertiga harta.\""},"2763":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الْمُغِيرَةِ حَدَّثَنَا مَخْلَدٌ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ لَا تَشْهَدْ عَلَى وَصِيَّةٍ حَتَّى تُقْرَأَ عَلَيْكَ وَلَا تَشْهَدْ عَلَى مَنْ لَا تَعْرِفُ","id":"Telah mengabarkan kepada kami [Sa'id bin Al Mughirah] telah menceritakan kepada kami [Makhlad] dari [Hisyam] dari [Al Hasan] ia berkata, \"Janganlah engkau bersaksi atas suatu wasiat hingga dibacakan kepadamu dan jangan bersaksi atas orang yang tidak engkau kenal.\""},"2764":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ أَوْصَى لِأُمَّهَاتِ أَوْلَادِهِ بِأَرْبَعَةِ آلَافٍ أَرْبَعَةِ آلَافٍ لِكُلِّ امْرَأَةٍ مِنْهُنَّ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Al Hasan] bahwa [Umar bin Al Khaththab] pernah berwasiat kepada para ibu dari anak-anaknya sebanyak empat ribu, masing-masing orang mendapat empat ribu.\""},"2765":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ أَنَّهُ أَجَازَ وَصِيَّةَ ابْنِ ثَلَاثَ عَشْرَةَ سَنَةً","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah mengabarkan kepada kami [Ibnu Abu Az Zinad] dari [Ayahnya] dari [Umar bin Abdul Aziz], bahwa ia membolehkan wasiat anak berumur tiga belas tahun.\""},"2766":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ قَالَ أَوْصَى غُلَامٌ مِنْ الْحَيِّ ابْنُ سَبْعِ سِنِينَ فَقَالَ شُرَيْحٌ إِذَا أَصَابَ الْغُلَامُ فِي وَصِيَّتِهِ جَازَتْ قَالَ أَبُو مُحَمَّد يُعْجِبُنِي وَالْقُضَاةُ لَا يُجِيزُونَ ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] ia berkata, \"Seorang anak berumur tujuh tahun dari suatu kampung pernah berwasiat.\" Maka [Syuraih] berkata, \"Jika anak itu dalam wasiatnya benar maka wasiat itu dibolehkan.\" Abu Muhammad berkata, \"Hal itu membuatku kagum namun para hakim tidak membolehkannya.\""},"2767":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا يُونُسُ حَدَّثَنَا أَبُو إِسْحَقَ أَنَّهُ شَهِدَ شُرَيْحًا أَجَازَ وَصِيَّةَ عَبَّاسِ بْنِ إِسْمَعِيلَ بْنِ مَرْثَدٍ لِظِئْرِهِ مِنْ أَهْلِ الْحِيرَةِ وَعَبَّاسٌ صَبِيٌّ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Yunus] telah menceritakan kepada kami [Abu Ishaq] bahwa ia menyaksikan [Syuraih] membolehkan wasiat Abbas bin Isma'il bin Martsad kepada ibu susunya dari penduduk Hirah, padahal Abbas masih kecil.\""},"2768":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا يُونُسُ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ قَالَ شُرَيْحٌ إِذَا اتَّقَى الصَّبِيُّ الرَّكِيَّةَ جَازَتْ وَصِيَّتُهُ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Yunus] telah menceritakan kepada kami [Abu Ishaq] ia berkata; [Syuraih] berkata, \"Jika seorang anak kecil dapat menghindari sumur, maka wasiatnya dibolehkan.\""},"2769":{"ar":" حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ أَنَّ غُلَامًا مِنْهُمْ حِينَ ثُغِرَ يُقَالُ لَهُ مَرْثَدٌ أَوْصَى لِظِئْرٍ لَهُ مِنْ أَهْلِ الْحِيرَةِ بِأَرْبَعِينَ دِرْهَمًا فَأَجَازَهُ شُرَيْحٌ وَقَالَ مَنْ أَصَابَ الْحَقَّ أَجَزْنَاهُ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] bahwa seorang anak dari mereka ketika telah tanggal giginya dipanggil Martsad, ia berwasiat kepada ibu susunya dari penduduk Hirah sebanyak empat puluh dirham. Dan [Syuraih] membolehkannya hal itu, ia katakan, \"Siapa saja yang sesuai dengan haknya maka kami membolehkannya.\""},"2770":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى أَنَّ أَبَا بَكْرِ بْنَ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَخْبَرَهُ أَنَّ غُلَامًا بِالْمَدِينَةِ حَضَرَهُ الْمَوْتُ وَوَرَثَتُهُ بِالشَّامِ وَأَنَّهُمْ ذَكَرُوا لِعُمَرَ أَنَّهُ يَمُوتُ فَسَأَلُوهُ أَنْ يُوصِيَ فَأَمَرَهُ عُمَرُ أَنْ يُوصِيَ فَأَوْصَى بِبِئْرٍ يُقَالُ لَهَا بِئْرُ جُشَمَ وَإِنَّ أَهْلَهَا بَاعُوهَا بِثَلَاثِينَ أَلْفًا ذَكَرَ أَبُو بَكْرٍ أَنَّ الْغُلَامَ كَانَ ابْنَ عَشْرِ سِنِينَ أَوْ ثِنْتَيْ عَشْرَةَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] bahwa [Abu Bakar bin Muhammad bin Amru bin Hazm] mengabarkan kepadanya, bahwa ada seorang anak di Madinah sedang menghadapi kematian sementara ahli warisnya berada di Syam. Mereka memberitahukan kepada Umar bahwa anak itu akan meninggal, lalu mereka meminta kepadanya agar ia berwasiat. Maka [Umar] menyuruhnya untuk berwasiat, ia pun berwasiat dengan sebuah sumur bernama sumur Jusyam dan pemiliknya menjual dengan harga tiga puluh ribu.\" Abu Bakar menyebutkan bahwa anak itu berumur sepuluh atau dua belas tahun."},"2771":{"ar":" حَدَّثَنَا يَزِيدُ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ يَجُوزُ وَصِيَّةُ الصَّبِيِّ فِي مَالِهِ فِي الثُّلُثِ فَمَا دُونَهُ وَإِنَّمَا يَمْنَعُهُ وَلِيُّهُ ذَلِكَ فِي الصِّحَّةِ رَهْبَةَ الْفَاقَةِ عَلَيْهِ فَأَمَّا عِنْدَ الْمَوْتِ فَلَيْسَ لَهُ أَنْ يَمْنَعَهُ","id":"Telah menceritakan kepada kami [Yazid] dari [Hisyam Ad Dastawa`i] dari [Hammad] dari [Ibrahim] ia berkata, \"Seorang anak kecil dibolehkan berwasiat dengan sepertiga dari hartanya atau kurang dari itu, walinya hanya boleh melarangnya berwasiat pada waktu sehat karena khawatir kemiskinan menimpanya. Adapun ketika (anak itu) akan meninggalnya maka walinya tidak berhak melarangnya.\""},"2772":{"ar":" حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ وَأَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّهُ أُتِيَ فِي جَارِيَةٍ أَوْصَتْ فَجَعَلُوا يُصَغِّرُونَهَا فَقَالَ مَنْ أَصَابَ الْحَقَّ أَجَزْنَاهُ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Khalid Al Hadzdza`] dan [Ayyub] dari [Ibnu Sirin] dari [Abdullah bin Utbah], bahwa pernah didatangkan kepadanya seorang anak perempuan yang masih kecil, anak tersebut ingin berwasiat (dengan hartanya), namun mereka menganggapnya masih kecil. Abdullah bin Utbah berkata, \"Jika mendapati kebenaran maka kami membolehkannya.\""},"2773":{"ar":" حَدَّثَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرٍ أَنَّ سُلَيْمًا الْغَسَّانِيَّ مَاتَ وَهُوَ ابْنُ عَشْرٍ أَوْ ثِنْتَيْ عَشْرَةَ سَنَةً فَأَوْصَى بِبِئْرٍ لَهُ قِيمَتُهَا ثَلَاثُونَ أَلْفًا فَأَجَازَهَا عُمَرُ بْنُ الْخَطَّابِ قَالَ أَبُو مُحَمَّد النَّاسُ يَقُولُونَ عَمْرُو بْنُ سُلَيْمٍ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنَيْهِ عَبْدِ اللَّهِ وَمُحَمَّدٍ ابْنَيْ أَبِي بَكْرٍ عَنْ أَبِيهِمَا مِثْلَ ذَلِكَ غَيْرَ أَنَّ أَحَدَهُمَا قَالَ ابْنُ ثَلَاثَ عَشْرَةَ وَقَالَ الْآخَرُ قَبْلَ أَنْ يَحْتَلِمَ قَالَ أَبُو مُحَمَّد عَنْ ابْنَيْهِ يَعْنِي ابْنَيْ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Yahya bin Sa'd] dari [Abu Bakar], bahwa Sulaim Al Ghassan meninggal pada umur sepuluh atau dua belas tahun, ia pun berwasiat dengan sumur miliknya yang bernilai tiga puluh ribu, [Umar bin Al Khaththab] pun membolehkannya.\" Abu Muhammad berkata, \"Orang-orang mengatakan, 'Ia adalah Amru bin Sulaim'.\" Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari kedua anaknya [Abdullah] dan [Muhammad] keduanya anak Abu Bakar dari [Ayah keduanya] seperti itu, hanya saja salah seorang dari keduanya berkata, \"Ia berumur tiga belas tahun.\" Yang lain berkata, \"Sebelum ia bermimpi junub.\" Abu Muhammad berkata, \"Dari kedua anaknya, yakni kedua anak Abu Bakar.\""},"2774":{"ar":" حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ أَنَّهُ كَانَ يَقُولُ وَصِيَّتُهُ لَيْسَتْ بِجَائِزَةٍ إِلَّا مَا لَيْسَ بِذِي بَالٍ يَعْنِي الْغُلَامَ قَبْلَ أَنْ يَحْتَلِمَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] bahwa ia berkata, \"Wasiatnya tidak dibolehkan kecuali jika ia sudah memiliki nalar, yakni anak yang belum bermimpi junub.\""},"2775":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ لَا يَجُوزُ طَلَاقُ الْغُلَامِ وَلَا وَصِيَّتُهُ وَلَا هِبَتُهُ وَلَا صَدَقَتُهُ وَلَا عَتَاقَتُهُ حَتَّى يَحْتَلِمَ","id":"Telah menceritakan kepada kami [Amru bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Yunus] dari [Al Hasan] ia berkata, \"Tidak sah talak anak kecil, wasiat, hibah, sedekah dan pemerdekaannya hingga ia bermimpi junub.\""},"2776":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَا يَجُوزُ طَلَاقُ الصَّبِيِّ وَلَا عِتْقُهُ وَلَا وَصِيَّتُهُ وَلَا شِرَاؤُهُ وَلَا بَيْعُهُ وَلَا شَيْءٌ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Hafsh bin Ghiyats] dari [Hajjaj] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Tidak sah talak anak kecil, pemerdekaan, wasiat, jual belinya dan selainnya.\" "},"2777":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ قَالَ لَا يَجُوزُ طَلَاقٌ وَلَا وَصِيَّةٌ إِلَّا فِي عَقْلٍ إِلَّا النَّشْوَانَ يَعْنِي السَّكْرَانَ فَإِنَّهُ يَجُوزُ طَلَاقُهُ وَيُضْرَبُ ظَهْرُهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Humaid bin Abdurrahman Al Himyari] ia berkata, \"Tidak sah talak dan wasiat kecuali telah berakal, selain An Nasywan, yaitu orang yang mabuk. Talaknya sah dan ia wajib dihukum dengan hukuman cambuk.\""},"2778":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ قَالَ سَأَلْتُ الْقَاسِمَ بْنَ عَبْدِ الرَّحْمَنِ وَمُعَاوِيَةَ بْنَ قُرَّةَ عَنْ رَجُلٍ قَالَ فِي وَصِيَّتِهِ كُلُّ مَمْلُوكٍ لِي حُرٌّ وَلَهُ مَمْلُوكٌ آبِقٌ فَقَالَا هُوَ حُرٌّ و قَالَ الْحَسَنُ وَإِيَاسٌ وَبَكْرُ بْنُ عَبْدِ اللَّهِ لَيْسَ بِحُرٍّ","id":"Telah menceritakan kepada kami [Amru bin 'Aun] dari [Khalid bin Abdullah] dari [Yahya bin Abu Ishaq] ia berkata, \"Aku bertanya kepada [Al Qasim bin Abdurrahman] dan [Mu'awiyah bin Qurrah] tentang seseorang yang berkata di dalam wasiatnya, 'Setiap budak milikku merdeka', dan ia memiliki seorang budak yang kabur?\" keduanya lalu menjawab, \"Budak yang kabur itu merdeka.\" Sedangkan [Al Hasan] dan [Iyas] dan [Bakar bin Abdullah] mengatakan, \"Ia tidak merdeka.\""},"2779":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ الْعُمَرِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ عُمَرَ أَوْصَى إِلَى حَفْصَةَ أُمِّ الْمُؤْمِنِينَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdullah Al Umari] dari [Nafi'] dari [Ibnu Umar] bahwa [Umar] pernah berwasiat kepada Hafshah Ummul Mukminin.\""},"2780":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ صَفِيَّةَ أَوْصَتْ لِنَسِيبٍ لَهَا يَهُودِيٍّ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Nafi'] dari [Ibnu Umar] bahwa [Shafiyah] telah berwasiat kepada seorang Yahudi yang bersamanya.\""},"2781":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ قَالَ أَوْصَى غُلَامٌ مِنْ الْحَيِّ يُقَالُ لَهُ عَبَّاسُ بْنُ مَرْثَدٍ ابْنُ سَبْعِ سِنِينَ لِظِئْرٍ لَهُ يَهُودِيَّةٍ مِنْ أَهْلِ الْحِيرَةِ بِأَرْبَعِينَ دِرْهَمًا فَقَالَ شُرَيْحٌ إِذَا أَصَابَ الْغُلَامُ فِي وَصِيَّتِهِ جَازَتْ وَإِنَّمَا أَوْصَى لِذِي حَقٍّ قَالَ أَبُو مُحَمَّد أَنَا أَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] ia berkata, \"Seorang anak dari suatu perkampungan, bernama Abbas bin Marsad yang berumur tujuh tahun, berwasiat kepada ibu susunya yang beragama Yahudi dari Al Hirah sebanyak empat puluh dirham. [Syuraih] lalu menjawab, \"Jika anak itu benar dalam wasiatnya maka dibolehkan. Hanyasanya ia berwasiat kepada orang yang berhak.\" Abu Muhammad berkata, \"Aku juga berpendapat seperti itu.\""},"2782":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ أَنَّ الزُّبَيْرَ جَعَلَ دُورَهُ صَدَقَةً عَلَى بَنِيهِ لَا تُبَاعُ وَلَا تُوَرَّثُ وَأَنَّ لِلْمَرْدُودَةِ مِنْ بَنَاتِهِ أَنْ تَسْكُنَ غَيْرَ مُضِرَّةٍ وَلَا مُضَارٍّ بِهَا فَإِنْ هِيَ اسْتَغْنَتْ بِزَوْجٍ فَلَا حَقَّ لَهَا","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] bahwa [Az Zubair] menjadikan beberapa rumahnya sebagai sedekah kepada anak-anaknya, tidak boleh dijual dan diwariskan. Dan bagi anak perempuannya yang dicerai oleh suami, boleh tinggal di rumah ayahnya tanpa mengganggu dan diganggu. Jika ia telah bersuami maka tidak ada lagi hak baginya untuk tinggal di rumah itu.\""},"2783":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا الْوَلِيدُ عَنْ حَفْصٍ عَنْ مَكْحُولٍ فِي الرَّجُلِ يُوصِي لِلرَّجُلِ بِدَنَانِيرَ فِي سَبِيلِ اللَّهِ فَيَمُوتُ الْمُوصَى لَهُ قَبْلَ أَنْ يَخْرُجَ بِهَا مِنْ أَهْلِهِ قَالَ هِيَ إِلَى أَوْلِيَاءِ الْمُتَوَفَّى الْمُوصِي يُنْفِذُونَهَا فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Al Walid] dari [Hafsh] dari [Makhul] tentang seorang laki-laki yang berwasiat kepada orang lain beberapa dinar di jalan Allah, lalu orang yang diberi wasiat tersebut meninggal sebelum ia keluarkan uang itu dari keluarganya. Makhul katakan, \"Uang itu beralih kepada para wali orang yang diberi wasiat yang meninggal dunia untuk digunakan di jalan Allah.\""},"2784":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ الْحَسَنِ فِي الرَّجُلِ يُوصِي لِلرَّجُلِ بِالْوَصِيَّةِ فَيَمُوتُ الْمُوصَى لَهُ قَبْلَ الْمُوصِي قَالَ هِيَ جَائِزَةٌ لِوَرَثَةِ الْمُوصَى لَهُ حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ أَبِي إِسْحَقَ السَّبِيعِيِّ قَالَ حُدِّثْتُ أَنَّ عَلِيًّا كَانَ يُجِيزُهَا مِثْلَ قَوْلِ الْحَسَنِ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Al Hasan] tentang seseorang yang berwasiat suatu wasiat kepada orang lain, lalu orang yang diberi wasiat itu meninggal sebelum orang yang berwasiat. Al Hasan katakan, \"Boleh dialihkan kepada ahli waris orang yang diberi wasiat.\" Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Abu Ishaq As Sabi'i] ia berkata, \" [Diceritakan kepadaku] bahwa [Ali] membolehkannya, seperti pendapat Al Hasan.\""},"2785":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ مُحَمَّدٍ عَنْ مُوسَى هُوَ ابْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ رَجُلًا جَاءَ إِلَى ابْنِ عُمَرَ فَقَالَ إِنَّ رَجُلًا أَوْصَى إِلَيَّ وَجَعَلَ نَاقَةً فِي سَبِيلِ اللَّهِ وَلَيْسَ هَذَا زَمَانًا يُخْرَجُ إِلَى الْغَزْوِ فَأَحْمِلُ عَلَيْهَا فِي الْحَجِّ فَقَالَ ابْنُ عُمَرَ الْحَجُّ وَالْعُمْرَةُ مِنْ سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Abdul Aziz] -yaitu Ibnu Muhammad- dari [Musa] -yaitu Ibnu Uqbah- dari [Nafi'], bahwa seorang laki-laki datang kepada Ibnu Umar seraya berkata, \"Seseorang berwasiat kepadaku dengan seekor unta untuk digunakan di jalan Allah, sementara sekarang bukan masa perang, lalu aku menggunakannya untuk berhaji?\" [Ibnu Umar] lalu menjawab, \"Haji dan umrah juga termasuk di jalan Allah.\""},"2786":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ وَاقِدِ بْنِ مُحَمَّدِ بْنِ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ رَجُلًا أَوْصَى بِمَالِهِ فِي سَبِيلِ اللَّهِ فَسَأَلَ الْوَصِيُّ عَنْ ذَلِكَ عُمَرَ فَقَالَ أَعْطِهِ عُمَّالَ اللَّهِ قَالَ وَمَنْ عُمَّالُ اللَّهِ قَالَ حَاجُّ بَيْتِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Musa bin Ubaidah] dari [Waqid bin Muhammad bin Zaid] dari [Abdullah bin Umar], bahwa ada seseorang yang ingin berwasiat dengan hartanya di jalan Allah, lalu orang itu bertanya kepada [Umar] tentang hal itu. Umar pun menjawab, \"Berikan kepada para pekerja Allah.\" Ia bertanya lagi, \"Siapakah para pekerja Allah itu?\" Umar menjawab, \"Orang yang berhaji ke Baitullah.\""},"2787":{"ar":" حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا جَرِيرٌ عَنْ قَابُوسَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ الَّذِي لَيْسَ فِي جَوْفِهِ مِنْ الْقُرْآنِ شَيْءٌ كَالْبَيْتِ الْخَرِبِ","id":"Telah menceritakan kepada kami [Amru bin Zurarah] telah menceritakan kepada kami [Jarir] dari [Qabus] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang laki-laki yang tidak ada sedikit pun bacaan Al Qur'an di dalam rongga mulutnya niscaya ia seperti rumah yang hancur.\""},"2788":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ خَالِدِ بْنِ حَازِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو سِنَانٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ إِنَّ هَذَا الْقُرْآنَ مَأْدُبَةُ اللَّهِ فَخُذُوا مِنْهُ مَا اسْتَطَعْتُمْ فَإِنِّي لَا أَعْلَمُ شَيْئًا أَصْفَرَ مِنْ خَيْرٍ مِنْ بَيْتٍ لَيْسَ فِيهِ مِنْ كِتَابِ اللَّهِ شَيْءٌ وَإِنَّ الْقَلْبَ الَّذِي لَيْسَ فِيهِ مِنْ كِتَابِ اللَّهِ شَيْءٌ خَرِبٌ كَخَرَابِ الْبَيْتِ الَّذِي لَا سَاكِنَ لَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Khalid bin Hazim] telah menceritakan kepada kami [Muhammad bin Salamah] telah menceritakan kepada kami [Abu Sinan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata, \"Sesungguhnya Al Qur'an ini adalah jamuan Allah, maka ambillah darinya semampu kalian. Sungguh, aku tidak mengetahui sesuatu yang lebih kosong dari kebaikan selain rumah yang di dalamnya tidak ada bacaan Al Qur'an. Sungguh, hati yang di dalamnya tidak ada bacaan Al Qur'an adalah hancur seperti hancurnya rumah yang tidak berpenghuni.\""},"2789":{"ar":" حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ حَدَّثَنَا يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ حَدَّثَنِي حَفْصُ بْنُ عِنَانٍ الْحَنَفِيُّ أَنَّ أَبَا هُرَيْرَةَ كَانَ يَقُولُ إِنَّ الْبَيْتَ لَيَتَّسِعُ عَلَى أَهْلِهِ وَتَحْضُرُهُ الْمَلَائِكَةُ وَتَهْجُرُهُ الشَّيَاطِينُ وَيَكْثُرُ خَيْرُهُ أَنْ يُقْرَأَ فِيهِ الْقُرْآنُ وَإِنَّ الْبَيْتَ لَيَضِيقُ عَلَى أَهْلِهِ وَتَهْجُرُهُ الْمَلَائِكَةُ وَتَحْضُرُهُ الشَّيَاطِينُ وَيَقِلُّ خَيْرُهُ أَنْ لَا يُقْرَأَ فِيهِ الْقُرْآنُ","id":"Telah menceritakan kepada kami [Mu'adz bin Hani`] telah menceritakan kepada kami [Harb bin Syaddad] telah menceritakan kepada kami [Yahya] -yaitu Ibnu Abu Katsir- telah menceritakan kepadaku [Hafsh bin 'Inan Al Hanafi] bahwa [Abu Hurairah] pernah berkata, \"Sesungguhnya rumah akan terasa luas bagi penghuninya, para malaikat akan mendatanginya, setan-setan akan menjauhi dan kebaikannya akan bertambah jika Al Qur'an dibaca di dalamnya. Dan rumah akan terasa sempit bagi penghuninya, para malaikat menjauhinya, setan-setan datang dan kebaikannya berkurang jika di dalamnya tidak dibacakan Al Qur'an.\""},"2790":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ مِشْرَحِ بْنِ هَاعَانَ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ جُعِلَ الْقُرْآنُ فِي إِهَابٍ ثُمَّ أُلْقِيَ فِي النَّارِ مَا احْتَرَقَ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Misyrah bin Ha'an] ia berkata; Aku mendengar [Uqbah bin Amir] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya Al Qur'an diletakkan pada sebuah kulit kemudian dilemparkan ke dalam api neraka niscaya ia tidak akan terbakar.\""},"2791":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ اقْرَءُوا الْقُرْآنَ فَإِنَّهُ نِعْمَ الشَّفِيعُ يَوْمَ الْقِيَامَةِ إِنَّهُ يَقُولُ يَوْمَ الْقِيَامَةِ يَا رَبِّ حَلِّهِ حِلْيَةَ الْكَرَامَةِ فَيُحَلَّى حِلْيَةَ الْكَرَامَةِ يَا رَبِّ اكْسُهُ كِسْوَةَ الْكَرَامَةِ فَيُكْسَى كِسْوَةَ الْكَرَامَةِ يَا رَبِّ أَلْبِسْهُ تَاجَ الْكَرَامَةِ يَا رَبِّ ارْضَ عَنْهُ فَلَيْسَ بَعْدَ رِضَاكَ شَيْءٌ","id":"Telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] dari [Ubaidullah bin Amru] dari [Zaid bin Abu Unaisah] dari ['Ashim] dari [Abu Shalih] ia berkata, \"Aku mendengar [Abu Hurairah] berkata, \"Bacalah Al Qur'an sebab ia adalah sebaik-baik pemberi syafaat pada hari kiamat, pada hari kiamat ia akan berkata 'Wahai Rabbku, hiasilah ia dengan hiasan kemuliaan, ' maka ia dihiasilah dengan hiasan kemuliaan. 'Wahai Rabbku, selimutilah ia dengan selimut kemuliaan, ' maka ia diselimuti dengan selimut kemuliaan. 'Wahai Rabbku, pakaikanlah padanya mahkota kemuliaan, wahai Rabbku ridlailah ia, sebab tidak ada sesuatu yang diharap lagi setelah ridla-Mu'.\""},"2792":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ الْفَزَارِيُّ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ أَبِي صَالِحٍ قَالَ الْقُرْآنُ يَشْفَعُ لِصَاحِبِهِ فَيُكْسَى حُلَّةَ الْكَرَامَةِ ثُمَّ يَقُولُ رَبِّ زِدْهُ فَيُكْسَى تَاجَ الْكَرَامَةِ قَالَ فَيَقُولُ رَبِّ زِدْهُ فَإِنَّهُ فَإِنَّهُ فَيَقُولُ رِضَائِي قَالَ أَبُو مُحَمَّد قَالَ وُهَيْبُ بْنُ الْوَرْدِ اجْعَلْ قِرَاءَتَكَ الْقُرْآنَ عِلْمًا وَلَا تَجْعَلْهُ عَمَلًا","id":"Telah menceritakan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Ibrahim bin Muhammad Al Fazari] dari [Al Hasan bin Ubaidullah] dari [Al Musayyab bin Rafi'] dari [Abu Shalih] ia berkata, \"Al Qur'an akan memberi syafaat kepada para pembacanya hingga ia pun dikenakan hiasan kemuliaan, kemudian Al-Qur'an berkata, 'Wahai Rabbku, tambahkan padanya, ' maka dipakaikan mahkota kemuliaan padanya. Al-Qur'an berkata lagi, 'Wahai Rabbku, tambahkan padanya, berilah ia, berilah ia.' Maka Allah pun menjawab: 'Keridlaan-Ku.'\" Abu Muhammad berkata; Wuhaib Ibnu Al Wardi berkata, \"Jadikanlah bacaan Al Qur'anmu sebagai ilmu dan jangan engkau jadikan ia sebagai amal.\""},"2793":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا إِبْرَاهِيمُ الْفَزَارِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُحِبُّ أَحَدُكُمْ إِذَا أَتَى أَهْلَهُ أَنْ يَجِدَ ثَلَاثَ خَلِفَاتٍ سِمَانٍ قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ فَثَلَاثُ آيَاتٍ يَقْرَؤُهُنَّ أَحَدُكُمْ خَيْرٌ لَهُ مِنْهُنَّ","id":"Telah menceritakan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Ibrahim Al Fazari] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah salah seorang dari kalian senang jika menemui keluarganya ia mendapatkan tiga ekor unta hamil lagi gemuk?\" Mereka menjawab, \"Tentu wahai Rasulullah.\" Beliau bersabda: \"Tiga ayat yang dibaca oleh salah seorang dari kalian itu lebih baik baginya dari unta tersebut.\""},"2794":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا أَبُو حَيَّانَ عَنْ يَزِيدَ بْنِ حَيَّانَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا خَطِيبًا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّمَا أَنَا بَشَرٌ يُوشِكُ أَنْ يَأْتِيَنِي رَسُولُ رَبِّي فَأُجِيبَهُ وَإِنِّي تَارِكٌ فِيكُمْ الثَّقَلَيْنِ أَوَّلُهُمَا كِتَابُ اللَّهِ فِيهِ الْهُدَى وَالنُّورُ فَتَمَسَّكُوا بِكِتَابِ اللَّهِ وَخُذُوا بِهِ فَحَثَّ عَلَيْهِ وَرَغَّبَ فِيهِ ثُمَّ قَالَ وَأَهْلَ بَيْتِي أُذَكِّرُكُمْ اللَّهَ فِي أَهْلِ بَيْتِي ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Abu Hayyan] dari [Yazid bin Hayyan] dari [Zaid bin Arqam] ia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah berdiri khutbah, beliau memuji Allah dan memuja-Nya kemudian bersabda: \"Wahai manusia, aku hanyalah seorang manusia, hampir tiba masanya utusan Rabbku datang padaku hingga aku pun harus memenuhi-Nya. Dan sesungguhnya aku tinggalkan kepada kalian dua perkara yang berat. Pertama adalah Kitabullah yang mengandung di dalamnya petunjuk dan cahaya maka berpegang teguhlah dengan Kitabullah dan ambillah ia.\" Maka beliau mendorong dan menganjurkan untuk berpegang teguh kepadanya. Kemudian beliau bersabda: 'Aku ingatkan kalian akan Allah pada Ahlu baitku.' Beliau mengatakan tiga kali.\""},"2795":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِ إِنَّ هَذَا الصِّرَاطَ مُحْتَضَرٌ تَحْضُرُهُ الشَّيَاطِينُ يُنَادُونَ يَا عَبْدَ اللَّهِ هَذَا الطَّرِيقُ فَاعْتَصِمُوا بِحَبْلِ اللَّهِ فَإِنَّ حَبْلَ اللَّهِ الْقُرْآنُ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Al A'masy] dari [Abu Wa`il] ia berkata; [Abdullah] berkata, \"Sesungguhnya jalan ini dipenuhi dengan setan-setan yang selalu datang sambil berseru, 'Hai hamba Allah, ini adalah jalanmu.' Oleh karena itu berpegang teguhlah kalian dengan tali Allah, sesungguhnya tali Allah adalah Al Qur'an.\""},"2796":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ إِنَّ قَارِئَ الْقُرْآنِ وَالْمُتَعَلِّمَ تُصَلِّي عَلَيْهِمْ الْمَلَائِكَةُ حَتَّى يَخْتِمُوا السُّورَةَ فَإِذَا أَقْرَأَ أَحَدُكُمْ السُّورَةَ فَلْيُؤَخِّرْ مِنْهَا آيَتَيْنِ حَتَّى يَخْتِمَهَا مِنْ آخِرِ النَّهَارِ كَيْ مَا تُصَلِّي الْمَلَائِكَةُ عَلَى الْقَارِئِ وَالْمُقْرِئِ مِنْ أَوَّلِ النَّهَارِ إِلَى آخِرِهِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami ['Abdah] dari [Khalid bin Ma'dan] ia berkata, \"Sesungguhnya pembaca Al Qur'an dan yang mempelajari Al Qur'an akan didoakan oleh para malaikat hingga mereka menyelesaikan satu surat, jika salah seorang dari kalian membacakan suatu surat maka hendaklah ia menunda membaca dua ayat dari surat tersebut hingga ia dapat menyelesaikannya di akhir siang, agar para malaikat mendoakan orang yang membaca dan orang yang dibacakan dari awal sampai akhir siang.\""},"2797":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ حَدَّثَنَا النُّعْمَانُ بْنُ سَعْدٍ عَنْ عَلِيٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Abdurrahman bin Ishaq] telah menceritakan kepada kami [An Nu'man bin Sa'd] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah orang yang mempelajari Al Qur'an dan mengajarkannya.\""},"2798":{"ar":" حَدَّثَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ قَالَ سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ خَيْرَكُمْ مَنْ عَلَّمَ الْقُرْآنَ أَوْ تَعَلَّمَهُ قَالَ أَقْرَأَ أَبُو عَبْدِ الرَّحْمَنِ فِي إِمْرَةِ عُثْمَانَ حَتَّى كَانَ الْحَجَّاجُ قَالَ ذَاكَ أَقْعَدَنِي مَقْعَدِي هَذَا","id":"Telah menceritakan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku ['Alqamah bin Martsad] ia berkata; Aku pernah mendengar [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya sebaik-baik kalian adalah orang yang mengajarkan Al Qur'an atau mempelajarinya.\" Ia berkata; Abu Abdurrahman pernah membacakan Al Qur'an pada masa pemerintahan Utsman hingga Al Hajjaj pernah berkata; Orang itu membuatku terduduk di tempat dudukku ini."},"2799":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِيَارُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَ الْقُرْآنَ قَالَ فَأَخَذَ بِيَدِي فَأَقْعَدَنِي هَذَا الْمَقْعَدَ أُقْرِئُ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Al Harits bin Nabhan] telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Mush'ab bin Sa'd] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah orang yang mempelajari dan mengajarkan Al Qur`an.\" Ia berkata; Lalu beliau meraih tanganku dan mendudukanku di tempat duduk ini lalu dibacakan Al Qur'an kepadaku."},"2800":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عِيسَى عَنْ رَجُلٍ عَنْ سَعْدِ بْنِ عُبَادَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ رَجُلٍ يَتَعَلَّمُ الْقُرْآنَ ثُمَّ يَنْسَاهُ إِلَّا لَقِيَ اللَّهَ يَوْمَ الْقِيَامَةِ وَهُوَ أَجْذَمُ قَالَ أَبُو مُحَمَّد عِيسَى هُوَ ابْنُ فَائِدٍ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Yazid bin Abu Ziyad] dari [Isa] dari [seseorang] dari [Sa'd bin Ubadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang mempelajari Al Qur'an kemudian melupakannya kecuali ia akan bertemu dengan Allah pada hari kiamat dalam keadaan terputus tangannya.\" Abu Muhammad berkata; Isa adalah Ibnu Fa`id."},"2801":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ نَاجِيَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَ أَكْثِرُوا تِلَاوَةَ الْقُرْآنِ قَبْلَ أَنْ يُرْفَعَ قَالُوا هَذِهِ الْمَصَاحِفُ تُرْفَعُ فَكَيْفَ بِمَا فِي صُدُورِ الرِّجَالِ قَالَ يُسْرَى عَلَيْهِ لَيْلًا فَيُصْبِحُونَ مِنْهُ فُقَرَاءَ وَيَنْسَوْنَ قَوْلَ لَا إِلَهَ إِلَّا اللَّهُ وَيَقَعُونَ فِي قَوْلِ الْجَاهِلِيَّةِ وَأَشْعَارِهِمْ وَذَلِكَ حِينَ يَقَعُ عَلَيْهِمْ الْقَوْلُ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Musa bin Ubaid] dari [Shafwan bin Sulaim] dari [Najiyah bin Abdullah bin Utbah] dari [ayahnya] dari [Abdullah] ia berkata; Perbanyaklah membaca Al Qur'an sebelum ia akan diangkat. Mereka bertanya; Apakah lembaran-lembaran (mushaf) ini akan diangkat? Bagaimana dengan yang ada di dalam dada (dihafal) manusia? Ia menjawab; Akan berlalu satu malam lalu pada pagi harinya mereka menjadi fakir dan melupakan ucapan LA ILAAHA ILLALLAH. Mereka juga terjebak dalam perkataan jahiliyah dan syair-syair mereka. Hal ini terjadi ketika keputusan telah ditetapkan atas mereka."},"2802":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا سَلَّامٌ يَعْنِي ابْنَ أَبِي مُطِيعٍ قَالَ كَانَ قَتَادَةُ يَقُولُ اعْمُرُوا بِهِ قُلُوبَكُمْ وَاعْمُرُوا بِهِ بُيُوتَكُمْ قَالَ أُرَاهُ يَعْنِي الْقُرْآنَ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Sallam] yakni Ibnu Abu Muthi', ia berkata; [Qatadah] pernah berkata; Makmurkanlah hati kalian dan makmurkanlah rumah kalian dengannya. Ia berkata; Menurutku yang dimaksudkan adalah Al Qur`an."},"2803":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ ابْنِ مَسْعُودٍ قَالَ لَيُسْرَيَنَّ عَلَى الْقُرْآنِ ذَاتَ لَيْلَةٍ فَلَا يُتْرَكُ آيَةٌ فِي مُصْحَفٍ وَلَا فِي قَلْبِ أَحَدٍ إِلَّا رُفِعَتْ","id":"Telah menceritakan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [Zirr] dari [Ibnu Mas'ud] ia berkata; Sungguh akan berlalu suatu malam atas Al Qur'an, sehingga tidak ada satu ayat pun dalam lembaran serta dalam hati (hafalan) seseorang, kecuali telah diangkat."},"2804":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ وَاقِدٍ عَنْ قَتَادَةَ قَالَ مَا جَالَسَ الْقُرْآنَ أَحَدٌ فَقَامَ عَنْهُ إِلَّا بِزِيَادَةٍ أَوْ نُقْصَانٍ ثُمَّ قَرَأَ { وَنُنَزِّلُ مِنْ الْقُرْآنِ مَا هُوَ شِفَاءٌ وَرَحْمَةٌ لِلْمُؤْمِنِينَ وَلَا يَزِيدُ الظَّالِمِينَ إِلَّا خَسَارًا }","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Abdullah bin Waqid] dari [Qatadah] ia berkata; Tidaklah seseorang duduk (dalam majlis) Al Qur'an lalu berdiri darinya kecuali dengan keadaan bertambah atau berkurang. Kemudian ia membaca: (Dan Kami turunkan dari Al Qur'an suatu yang menjadi penawar dan rahmat bagi orang-orang yang beriman dan Al Qur'an itu tidaklah menambah kepada orang-orang yang zhalim selain kerugian)."},"2805":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا رِفْدَةُ الْغَسَّانِيُّ حَدَّثَنَا ثَابِتُ بْنُ عَجْلَانَ الْأَنْصَارِيُّ قَالَ كَانَ يُقَالُ إِنَّ اللَّهَ لَيُرِيدُ الْعَذَابَ بِأَهْلِ الْأَرْضِ فَإِذَا سَمِعَ تَعْلِيمَ الصِّبْيَانِ الْحِكْمَةَ صَرَفَ ذَلِكَ عَنْهُمْ قَالَ مَرْوَانُ يَعْنِي بِالْحِكْمَةِ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Rifdah Al Ghassani] telah menceritakan kepada kami [Tsabit bin 'Ajlan Al Anshari] ia berkata; Dikatakan; Sesungguhnya Allah berkehendak untuk memberikan adzab kepada penduduk bumi, namun ketika Dia mendengarkan beberapa anak kecil mempelajari Al Hikmah, Dia memalingkan adzab tersebut dari mereka. Marwan berkata; Yang dimaksud dengan Al Hikmah adalah Al Qur`an."},"2806":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ عَنْ ابْنِ جَابِرٍ حَدَّثَنَا شَيْخٌ يُكَنَّى أَبَا عَمْرٍو عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ سَيَبْلَى الْقُرْآنُ فِي صُدُورِ أَقْوَامٍ كَمَا يَبْلَى الثَّوْبُ فَيَتَهَافَتُ يَقْرَءُونَهُ لَا يَجِدُونَ لَهُ شَهْوَةً وَلَا لَذَّةً يَلْبَسُونَ جُلُودَ الضَّأْنِ عَلَى قُلُوبِ الذِّئَابِ أَعْمَالُهُمْ طَمَعٌ لَا يُخَالِطُهُ خَوْفٌ إِنْ قَصَّرُوا قَالُوا سَنَبْلُغُ وَإِنْ أَسَاءُوا قَالُوا سَيُغْفَرُ لَنَا إِنَّا لَا نُشْرِكُ بِاللَّهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Shadaqah bin Khalid] dari [Ibnu Jabir] telah menceritakan kepada kami seorang syaikh yang dijuluki [Abu Amr] dari [Mu'adz bin Jabal] ia berkata; Al Qur'an akan usang di dalam dada beberapa kaum sebagaimana usangnya pakaian. Mereka berlomba membacanya namun mereka tidak merasakan kenikmatan dan kelezatan membacanya. Mereka ibarat orang yang mengenakan pakaian dari kulit domba namun berhati serigala, amalan mereka hanya ketamakan tanpa tercampuri rasa takut jika mereka melakukan kelalaian. Mereka berkata; Kami pasti akan sampai, sekalipun mereka berbuat jahat. Mereka berkata; Kami pasti akan diampuni, karena sesungguhnya kami tidak menyekutukan Allah dengan sesuatu pun."},"2807":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِئْسَمَا لِأَحَدِكُمْ أَنْ يَقُولَ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ وَاسْتَذْكِرُوا الْقُرْآنَ فَإِنَّهُ أَسْرَعُ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ مِنْ عُقُلِهَا","id":"Telah menceritakan kepada kami [Ubaidullah bin Abdul Majid] dari [Syu'bah] dari [Manshur] ia berkata; Aku mendengar [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Alangkah buruknya bagi salah seorang dari kalian jika mengatakan; Aku lupa ayat ini dan itu, tetapi ia dilupakan. Hendaklah kalian selalu mengingat Al Qur`an, karena ia lebih cepat lepasnya dari dada (hafalan) seseorang dari pada lepasnya seekor unta dari ikatannya.\""},"2808":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ عُلَيٍّ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ تَعَلَّمُوا كِتَابَ اللَّهِ وَتَعَاهَدُوهُ وَتَغَنَّوْا بِهِ وَاقْتَنُوهُ فَوَالَّذِي نَفْسِي بِيَدِهِ أَوْ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَهُوَ أَشَدُّ تَفَلُّتًا مِنْ الْمَخَاضِ فِي الْعُقُلِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Musa] yakni Ibnu 'Ulayyin ia berkata; Aku mendengar [ayahku] berkata; Aku mendengar [Uqbah bin Amir] berkata; Pelajarilah Kitabullah, jagalah, lantunkanlah dengan suara yang indah dan perhatikan ia. Maka demi Dzat yang jiwaku berada di tanganNya atau demi Dzat yang jiwa Muhammad berada di tanganNya, sungguh ia lebih cepat lepasnya dari pada unta bunting pada ikatannya."},"2809":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي مُوسَى عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَلَّمُوا كِتَابَ اللَّهِ تَعَالَى وَتَعَاهَدُوهُ وَاقْتَنُوهُ وَتَغَنَّوْا بِهِ فَوَالَّذِي نَفْسِي بِيَدِهِ لَهُوَ أَشَدُّ تَفَلُّتًا مِنْ الْمَخَاضِ فِي الْعُقُلِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] ia berkata; Telah menceritakan kepadaku [Musa] dari [ayahnya] dari [Uqbah bin Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelajarilah Kitabullah Ta'ala, jagalah, perhatikan dan lantunkanlah ia dengan suara yang indah. Maka demi Dzat yang jiwaku berada di tangannya, sungguh ia lebih cepat lepasnya dari pada unta bunting pada ikatannya.\""},"2810":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا ثَابِتٌ قَالَ كَانَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى إِذَا صَلَّى الصُّبْحَ قَرَأَ الْمُصْحَفَ حَتَّى تَطْلُعَ الشَّمْسُ قَالَ وَكَانَ ثَابِتٌ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Tsabit] ia berkata; [Abdurrahman bin Abu Laila] jika telah shalat Shubuh, ia membaca mushaf hingga terbit matahari. Ia berkata lagi; Tsabit juga melakukannya."},"2811":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ عَنْ يَزِيدَ بْنِ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ قَالَ { فَأَمَّا الَّذِينَ آمَنُوا فَيَعْلَمُونَ أَنَّهُ الْحَقُّ مِنْ رَبِّهِمْ } قَالَ أَيْ يَعْلَمُونَ أَنَّهُ كَلَامُ الرَّحْمَنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] dari [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah] ia berkata tentang firmanNya: (Adapun orang-orang yang beriman maka mereka yakin bahwa perumpamaan itu benar dari Rabb mereka). ia berkata; Maksudnya, mereka yakin bahwa itu adalah kalam Rabb Yang Maha Pengasih."},"2812":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ عَطِيَّةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ كَلَامٍ أَعْظَمُ عِنْدَ اللَّهِ مِنْ كَلَامِهِ وَمَا رَدَّ الْعِبَادُ إِلَى اللَّهِ كَلَامًا أَحَبَّ إِلَيْهِ مِنْ كَلَامِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] dari [Mu'awiyah bin Shalih] dari [Abu Bakr bin Abu Maryam] dari ['Athiyyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada satu perkataan pun yang lebih agung di sisi Allah dari pada perkataanNya dan tidak ada perkataan yang diucapkan oleh seorang hamba kepada Allah yang lebih disukaiNya daripada perkataanNya.\""},"2813":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ حَدَّثَنَا عُثْمَانُ بْنُ الْمُغِيرَةِ الثَّقَفِيُّ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُ نَفْسَهُ فِي الْمَوْسِمِ عَلَى النَّاسِ فِي الْمَوْقِفِ فَيَقُولُ هَلْ مِنْ رَجُلٍ يَحْمِلُنِي إِلَى قَوْمِهِ فَإِنَّ قُرَيْشًا مَنَعُونِي أَنْ أُبَلِّغَ كَلَامَ رَبِّي","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Isra`il] telah menceritakan kepada kami [Utsman bin Al Mughirah Ats Tsaqafi] dari [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menampakkan diri pada musim haji di hadapan orang-orang di padang Arafah, lalu beliau bersabda: \"Adakah seseorang yang akan membawaku kepada kaumnya, karena kaum Quraisy telah mencegahku untuk menyampaikan kalam Rabbku.\""},"2814":{"ar":" حَدَّثَنَا إِسْحَقُ حَدَّثَنَا جَرِيرٌ عَنْ لَيْثٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي الزَّعْرَاءِ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ إِنَّ هَذَا الْقُرْآنَ كَلَامُ اللَّهِ فَلَا أَعْرِفَنَّكُمْ فِيمَا عَطَفْتُمُوهُ عَلَى أَهْوَائِكُمْ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Jarir] dari [Laits] dari [Salamah bin Kuhail] dari [Abu Az Za'ra`] ia berkata; [Umar bin Al Khaththab] berkata; Sesungguhnya Al Qur'an ini adalah Kalamullah, maka janganlah kalian tertipu untuk melakukan perubahan padanya atas dasar hawa nafsu kalian."},"2815":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ التَّرْجُمَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ الْهَمْدَانِيُّ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَغَلَهُ قِرَاءَةُ الْقُرْآنِ عَنْ مَسْأَلَتِي وَذِكْرِي أَعْطَيْتُهُ أَفْضَلَ ثَوَابِ السَّائِلِينَ وَفَضْلُ كَلَامِ اللَّهِ عَلَى سَائِرِ الْكَلَامِ كَفَضْلِ اللَّهِ عَلَى خَلْقِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Ibrahim At Tarjumani] telah menceritakan kepada kami [Muhammad bin Al Hasan Al Hamdani] dari [Amr bin Qais] dari ['Athiyyah] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang disibukkan membaca Al Qur'an hingga lupa meminta dan berdzikir kepadaKu, maka Aku akan memberikan kepadanya sebaik-baik pahala orang-orang yang meminta (kepadaKu). Keutamaan Kalamullah atas seluruh perkataan lainnya seperti keutamaan Allah atas seluruh makhlukNya.\""},"2816":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَشْعَثَ الْحُدَّانِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضْلُ كَلَامِ اللَّهِ عَلَى كَلَامِ خَلْقِهِ كَفَضْلِ اللَّهِ عَلَى خَلْقِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Asy'ats Al Huddani] dari [Syahr bin Hausyab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keutamaan Kalamullah atas seluruh perkataan makhlukNya seperti keutamaan Allah atas makhlukNya.\""},"2817":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ رَجُلٍ مِنْ شُيُوخِ مِصْرَ أَنَّهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْقُرْآنُ أَحَبُّ إِلَى اللَّهِ مِنْ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Yahya bin Ayyub] dari [Ubaidullah bin Abu Ja'far] dari [seseorang syaikh Mesir] bahwa ia menceritakan dari [Abdullah bin Amr] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Al Qur'an lebih disukai Allah dari pada langit dan bumi beserta isinya.\""},"2818":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هَارُونُ الْأَعْوَرُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ جُنْدُبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفْتُمْ عَلَيْهِ فَإِذَا اخْتَلَفْتُمْ فِيهِ فَقُومُوا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Harun Al A'war] dari [Abu Imran Al Jauni] dari [Jundub] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur'an selama kalian bersepakat atasnya (dalam memahami maknanya), namun jika kalian berselisih di dalamnya, maka berdirilah (untuk menghindari terjadinya perselisihan yang dapat berakibat buruk).\" "},"2819":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ جُنْدُبِ بْنِ عَبْدِ اللَّهِ قَالَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ عَلَيْهِ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فِيهِ فَقُومُوا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Jundub bin Abdullah] ia berkata; (Nabi shallallahu 'alaihi wasallam bersabda); \"Bacalah Al Qur'an selama hati kalian bersatu atasnya, namun jika kalian berselisih di dalamnya maka berdirilah.\""},"2820":{"ar":" حَدَّثَنَا أَبُو غَسَّانَ مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو قُدَامَةَ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ جُنْدُبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ عَلَيْهِ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فِيهِ فَقُومُوا","id":"Telah menceritakan kepada kami [Abu Ghassan, Malik bin Isma'il] telah menceritakan kepada kami [Abu Qudamah] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Jundub] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur'an selama hati kalian bersatu atasnya, namun jika kalian berselisih di dalamnya maka berdirilah.\""},"2821":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ مِنْ النَّاسِ مَنْ يُؤْتَى الْإِيمَانَ وَلَا يُؤْتَى الْقُرْآنَ وَمِنْهُمْ مَنْ يُؤْتَى الْقُرْآنَ وَلَا يُؤْتَى الْإِيمَانَ وَمِنْهُمْ مَنْ يُؤْتَى الْقُرْآنَ وَالْإِيمَانَ وَمِنْهُمْ مَنْ لَا يُؤْتَى الْقُرْآنَ وَلَا الْإِيمَانَ ثُمَّ ضَرَبَ لَهُمْ مَثَلًا قَالَ فَأَمَّا مَنْ أُوتِيَ الْإِيمَانَ وَلَمْ يُؤْتَ الْقُرْآنَ فَمَثَلُهُ مَثَلُ التَّمْرَةِ حُلْوَةُ الطَّعْمِ لَا رِيحَ لَهَا وَأَمَّا مَثَلُ الَّذِي أُوتِيَ الْقُرْآنَ وَلَمْ يُؤْتَ الْإِيمَانَ فَمَثَلُ الْآسَةِ طَيِّبَةُ الرِّيحِ مُرَّةُ الطَّعْمِ وَأَمَّا الَّذِي أُوتِيَ الْقُرْآنَ وَالْإِيمَانَ فَمَثَلُ الْأُتْرُجَّةِ طَيِّبَةُ الرِّيحِ حُلْوَةُ الطَّعْمِ وَأَمَّا الَّذِي لَمْ يُؤْتَ الْقُرْآنَ وَلَا الْإِيمَانَ فَمَثَلُهُ مَثَلُ الْحَنْظَلَةِ مُرَّةُ الطَّعْمِ لَا رِيحَ لَهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Al Harits] dari [Ali] radliallahu 'anhu, ia berkata; Di antara manusia ada yang hanya diberi iman dan tidak diberi Al Qur`an. Di antara mereka ada yang hanya diberi Al Qur'an dan tidak diberi iman. Di antara mereka ada yang diberi Al Qur'an dan iman. Di antara mereka juga ada yang tidak diberi Al Qur'an dan tidak pula iman. Kemudian ia membuat perumpamaan bagi mereka, ia berkata; Adapun orang yang hanya diberi iman dan tidak diberi Al Qur'an seperti buah kurma yang rasanya manis namun tidak berbau harum, orang yang hanya diberi Al Qur'an dan tidak diberi iman seperti tanaman Asah yang harum namun rasanya pahit. Orang yang diberi Al Qur'an dan iman seperti buah utrujah yang harum baunya dan rasanya manis. Sedangkan orang yang tidak diberi Al Qur'an dan tidak pula iman seperti tanaman hanzhalah yang rasanya pahit lagi tanpa bau harum."},"2822":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ مَثَلُ التَّمْرَةِ طَعْمُهَا حُلْوٌ وَلَيْسَ لَهَا رِيحٌ وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ مَثَلُ الْحَنْظَلَةِ لَيْسَ لَهَا رِيحٌ وَطَعْمُهَا مُرٌّ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan orang mukmin yang membaca Al Qur'an seperti buah utrujah yang harum baunya dan rasanya enak, perumpaman orang mukmin yang tidak membaca Al Qur'an seperti buah kurma yang rasanya manis namun tidak berbau harum, perumpamaan orang munafik yang membaca Al Qur'an seperti tanaman Raihanah yang berbau harum namun rasanya pahit, sedangkan perumpamaan orang munafik yang tidak membaca Al Qur'an seperti tanaman hanzhalah yang tidak berbau lagi rasanya pahit.\""},"2823":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَ مَثَلُ الَّذِي أُوتِيَ الْإِيمَانَ وَلَمْ يُؤْتَ الْقُرْآنَ مَثَلُ التَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الَّذِي أُوتِيَ الْقُرْآنَ وَلَمْ يُؤْتَ الْإِيمَانَ مَثَلُ الرَّيْحَانَةِ الْآسَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الَّذِي أُوتِيَ الْقُرْآنَ وَالْإِيمَانَ مَثَلُ الْأُتْرُجَّةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا طَيِّبٌ وَمَثَلُ الَّذِي لَمْ يُؤْتَ الْإِيمَانَ وَلَا الْقُرْآنَ مَثَلُ الْحَنْظَلَةِ رِيحُهَا خَبِيثٌ وَطَعْمُهَا خَبِيثٌ","id":"Telah mengabarkan kepada kami [Ubaidullah] dari [Isra`il] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; Perumpamaan orang yang hanya diberi iman dan tidak diberi Al Qur'an seperti buah kurma yang rasanya manis namun tidak berbau harum, perumpamaan orang yang hanya diberi Al Qur'an dan tidak diberi iman seperti tanaman Rahanah Asah yang berbau harum namun rasanya pahit, perumpamaan orang yang diberi Al Qur'an dan iman seperti buah Utrujah yang harum baunya lagi rasanya enak, sedangkan perumpamaan orang yang tidak diberi Al Qur'an dan tidak pula iman seperti tanaman Hanzhalah yang berbau busuk lagi rasanya tidak enak."},"2824":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ حَدَّثَنِي عَامِرُ بْنُ وَاثِلَةَ أَنَّ نَافِعَ بْنَ عَبْدِ الْحَارِثِ لَقِيَ عُمَرَ بْنَ الْخَطَّابِ بِعُسْفَانَ وَكَانَ عُمَرُ اسْتَعْمَلَهُ عَلَى أَهْلِ مَكَّةَ فَسَلَّمَ عَلَى عُمَرَ فَقَالَ لَهُ عُمَرُ مَنْ اسْتَخْلَفْتَ عَلَى أَهْلِ الْوَادِي فَقَالَ نَافِعٌ اسْتَخْلَفْتُ عَلَيْهِمْ ابْنَ أَبْزَى فَقَالَ عُمَرُ وَمَنْ ابْنُ أَبْزَى فَقَالَ مَوْلًى مِنْ مَوَالِينَا فَقَالَ عُمَرُ فَاسْتَخْلَفْتَ عَلَيْهِمْ مَوْلًى فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّهُ قَارِئٌ لِكِتَابِ اللَّهِ عَالِمٌ بِالْفَرَائِضِ فَقَالَ عُمَرُ أَمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَرْفَعُ بِهَذَا الْكِتَابِ أَقْوَامًا وَيَضَعُ بِهِ آخَرِينَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah menceritakan kepadaku [Amir bin Watsilah] bahwa Nafi' bin Abdul Harits menemui [Umar bin Al Khaththab] di 'Usfan. Ketika Umar itu telah mengangkatnya sebagai gubernur Makkah. Lalu ia memberi salam kepada Umar, Umar pun berkata kepadanya; Siapa yang memimpin penduduk lembah? Nafi' menjawab; Aku mengangkat Ibnu Abza sebagai pimpinan mereka. Umar pun bertanya; Siapa Ibnu Abza itu? Ia menjawab; Ia adalah salah seorang mantan budak yang telah kami merdekakan. Umar berkata; Lalu engkau menjadikan seorang mantan budak untuk memimpin mereka? Ia menjawab; Wahai Amirul Mukminin, sesungguhnya ia orang yang selalu membaca Al Qur'an lagi menguasai faraidl (hukum waris). Umar berkata; Ketahuilah sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah akan mengangkat derajat beberapa kaum dengan kitab ini (Al Qur`an) dan menghinakan beberapa kaum lainnya dengannya pula.\""},"2825":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ إِنَّ الَّذِي يَقْرَأُ الْقُرْآنَ لَهُ أَجْرٌ وَإِنَّ الَّذِي يَسْتَمِعُ لَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdah] dari [Khalid bin Ma'dan] ia berkata; Sesungguhnya orang yang membaca Al Qur'an mendapatkan satu pahala dan orang yang mendengarkannya mendapatkan dua pahala."},"2826":{"ar":" حَدَّثَنَا رَزِينُ بْنُ عَبْدِ اللَّهِ بْنِ حُمَيْدٍ عَنْ عَبْدِ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَنْ اسْتَمَعَ إِلَى آيَةٍ مِنْ كِتَابِ اللَّهِ كَانَتْ لَهُ نُورًا","id":"Telah menceritakan kepada kami [Razin bin Abdullah bin Humaid] dari [Abdurrazaq] dari [Ibnu Juraij] dari ['Atha`] dari [Ibnu Abbas] ia berkata; Barangsiapa yang mendengarkan satu ayat dari Kitabullah, maka ayat itu akan menjadi cahaya baginya."},"2827":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ وَهَمَّامٌ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي يَقْرَأُ الْقُرْآنَ وَهُوَ مَاهِرٌ بِهِ فَهُوَ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَؤُهُ وَهُوَ يَشْتَدُّ عَلَيْهِ فَلَهُ أَجْرَانِ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dan [Hammam] keduanya berkata; Telah menceritakan kepada kami [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari [A`isyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang membaca Al Qur'an dan mahir membacanya bersama para malaikat yang mulia lagi berbakti (taat). Sedangkan orang yang membacanya dengan bersusah payah, maka ia mendapatkan dua pahala.\""},"2828":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ عَبْدِ الْعَزِيزِ عَنْ إِسْمَعِيلَ بْنِ عُبَيْدِ اللَّهِ عَنْ وَهْبٍ الذِّمَارِيِّ قَالَ مَنْ آتَاهُ اللَّهُ الْقُرْآنَ فَقَامَ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَعَمِلَ بِمَا فِيهِ وَمَاتَ عَلَى الطَّاعَةِ بَعَثَهُ اللَّهُ يَوْمَ الْقِيَامَةِ مَعَ السَّفَرَةِ وَالْأَحْكَامِ قَالَ سَعِيدٌ السَّفَرَةُ الْمَلَائِكَةُ وَالْأَحْكَامُ الْأَنْبِيَاءُ قَالَ وَمَنْ كَانَ حَرِيصًا وَهُوَ يَتَفَلَّتُ مِنْهُ وَهُوَ لَا يَدَعُهُ أُوتِيَ أَجْرَهُ مَرَّتَيْنِ وَمَنْ كَانَ عَلَيْهِ حَرِيصًا وَهُوَ يَتَفَلَّتُ مِنْهُ وَمَاتَ عَلَى الطَّاعَةِ فَهُوَ مِنْ أَشْرَافِهِمْ وَفُضِّلُوا عَلَى النَّاسِ كَمَا فُضِّلَتْ النُّسُورُ عَلَى سَائِرِ الطَّيْرِ وَكَمَا فُضِّلَتْ مَرْجَةٌ خَضْرَاءُ عَلَى مَا حَوْلَهَا مِنْ الْبِقَاعِ فَإِذَا كَانَ يَوْمُ الْقِيَامَةِ قِيلَ أَيْنَ الَّذِينَ كَانُوا يَتْلُونَ كِتَابِي لَمْ يُلْهِهِمْ اتِّبَاعُ الْأَنْعَامِ فَيُعْطَى الْخُلْدَ وَالنَّعِيمَ فَإِنْ كَانَ أَبَوَاهُ مَاتَا عَلَى الطَّاعَةِ جُعِلَ عَلَى رُءُوسِهِمَا تَاجُ الْمُلْكِ فَيَقُولَانِ رَبَّنَا مَا بَلَغَتْ هَذَا أَعْمَالُنَا فَيَقُولُ بَلَى إِنَّ ابْنَكُمَا كَانَ يَتْلُو كِتَابِي","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Abdul Aziz, dari [Isma'il bin Ubaidullah] dari [Wahb Adz Dzimari] ia berkata; Barangsiapa yang diberikan Al Qur'an oleh Allah, lalu ia membaca Al Qur'an itu di ujung malam dan di ujung siang serta mengamalkan isinya dan ia meninggal dalam ketaatan (kepada Allah), niscaya Allah akan membangkitkannya pada hari kiamat bersama para malaikat yang mulia dan para hakim. Sa'id berkata; Safarah adalah para malaikat dan ahkam adalah para nabi. Ia melanjutkan; Barangsiapa yang menjaga Al Qur'an namun ia tetap lepas dari hafalannya, padahal ia tidak pernah meninggalkannya, maka ia diberi pahala dua kali. Barangsiapa yang menjaga Al Qur'an namun ia tetap lepas dari hafalannya, sedangkan ia meninggal dalam ketaatan (kepada Allah), maka ia termasuk manusia yang paling mulia dan diutamakan dari manusia lainnya sebagaimana burung elang yang diutamakan atas seluruh burung, juga tanah hijau yang dipenuhi rerumputan lebih disukai dari tanah-tanah di sekitarnya. Maka jika hari kiamat telah tiba, dikatakan; Dimanakah orang-orang yang membaca kitabku? Mereka tidak dilenakan oleh mengejar kenikmatan. Lalu diberikan kepada mereka keabadian dan kenikmatan. Jika kedua orang tuanya meninggal dalam ketaatan (kepada Allah), maka diletakkan di atas kepala orang tuanya itu mahkota kerajaan. Lalu keduanya pun berkata; Wahai Rabb kami, amal kami tidak mungkin membawa kami kepada derajat ini. Dia menjawab: Tentu, sesungguhnya anak kalian berdua yang selalu membaca kitabKu."},"2829":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي فَاتِحَةِ الْكِتَابِ شِفَاءٌ مِنْ كُلِّ دَاءٍ","id":"Telah mengabarkan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Abdul Malik bin Umair] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Surat Al Fatihah adalah penawar dari segala penyakit.\""},"2830":{"ar":" حَدَّثَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى الْأَنْصَارِيِّ قَالَ مَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ { يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ } قَالَ أَلَا أُعَلِّمُكَ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ فَلَمَّا أَرَادَ أَنْ يَخْرُجَ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَهِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُمْ","id":"Telah menceritakan kepada kami [Bisyr bin Umar Az Zahrani] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Sa'id bin Al Mu'alla Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah lewati di hadapanku, lalu beliau bersabda: \"Bukankah Allah 'azza wajalla telah berfirman: (Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu).\" Beliau melanjutkan: \"Maukah aku ajarkan kepadamu surat yang paling agung di dalam Al Qur'an sebelum aku keluar dari masjid?\" Ketika beliau hendak keluar, beliau bersabda: \"Alhamdulillahi rabbil 'alamin, ia adalah sab'ul matsani dan Al Qur'an yang agung yang diberikan kepada kalian.\" "},"2831":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتِحَةُ الْكِتَابِ هِيَ السَّبْعُ الْمَثَانِي","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dari [Ubay bin Ka'b] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Fatihatul Kitab adalah sab'ul matsani.\" "},"2832":{"ar":" حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أُنْزِلَتْ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ وَالزَّبُورِ وَالْقُرْآنِ مِثْلُهَا يَعْنِي أُمَّ الْقُرْآنِ وَإِنَّهَا لَسَبْعٌ مِنْ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُعْطِيتُ","id":"Telah menceritakan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Ala` bin Abdurrahman] dair [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak pernah diturunkan dalam Taurat, Injil, Zabur dan Al Qur'an yang sepertinya, yakni ummul Qur'an (surat Al Fatihah). Sesungguhnya ia adalah sab'ul matsani dan Al Qur'an yang agung yang diberikan kepadaku.\""},"2833":{"ar":" أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنِي ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَمْدُ لِلَّهِ أُمُّ الْقُرْآنِ وَأُمُّ الْكِتَابِ وَالسَّبْعُ الْمَثَانِي","id":"Telah mengabarkan kepada kami [Abu Ali bin Al Hanafi] telah menceritakan kepadaku [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Alhamdulillah (surat Al Fatihah) adalah ummul Qur'an, ummul kitab dan sab'ul matsani.\""},"2834":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَا مِنْ بَيْتٍ يُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ إِلَّا خَرَجَ مِنْهُ الشَّيْطَانُ وَلَهُ ضَرِيطٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Tidak ada satu rumah pun yang di dalamnya dibaca surat Al Baqarah kecuali setan keluar darinya dengan terkentut-kentut."},"2835":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ سُورَةُ الْبَقَرَةِ تَعْلِيمُهَا بَرَكَةٌ وَتَرْكُهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُ وَهِيَ فُسْطَاطُ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdah] dari [Khalid bin Ma'dan] ia berkata; Mengajarkan surat Al Baqarah adalah keberkahan dan meninggalkannya adalah kerugian. Para penyihir pun tidak akan sanggup menghadapinya. Ia adalah penyempurna Al Qur'an."},"2836":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَ إِنَّ لِكُلِّ شَيْءٍ سَنَامًا وَإِنَّ سَنَامَ الْقُرْآنِ سُورَةُ الْبَقَرَةِ وَإِنَّ لِكُلِّ شَيْءٍ لُبَابًا وَإِنَّ لُبَابَ الْقُرْآنِ الْمُفَصَّلُ قَالَ أَبُو مُحَمَّد اللُّبَابُ الْخَالِصُ","id":"Telah menceritakan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [Abu Al Ahwash] dari [Abdullah] bahwa ia berkata; Sesungguhnya setiap sesuatu memiliki pemimpin, sesungguhnya pemimpin Al Qur'an adalah surat Al Baqarah. Dan sesungguhnya setiap sesuatu memiliki inti dan inti Al Qur'an adalah Al Mufashshal. [Abu Muhammad] berkata; Lubab berarti inti. "},"2837":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ قَالَ مَنْ قَرَأَ سُورَةَ الْبَقَرَةِ تُوِّجَ بِهَا تَاجًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] dari [Muhammad bin Thalhah] dari [Zubaid] dari [Abdurrahman bin Al Aswad] ia berkata; Barangsiapa yang membaca surat Al Baqarah, maka ia akan diberi mahkota kelak di dalam surga."},"2838":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي الْأَحْوَصِ قَالَ قَالَ عَبْدُ اللَّهِ إِنَّ الشَّيْطَانَ إِذَا سَمِعَ سُورَةَ الْبَقَرَةِ تُقْرَأُ فِي بَيْتٍ خَرَجَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syu'bah] dari dari [Salamah bin Kuhail] dari [Abu Al Ahwash] ia berkata; [Abdullah] berkata; Sesungguhnya jika setan mendengar surat Al Baqarah dibaca di dalam sebuah rumah, ia pasti akan keluar darinya."},"2839":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنِي أَيْفَعُ بْنُ عَبْدٍ الْكَلَاعِيُّ قَالَ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ سُورَةِ الْقُرْآنِ أَعْظَمُ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ قَالَ فَأَيُّ آيَةٍ فِي الْقُرْآنِ أَعْظَمُ قَالَ آيَةُ الْكُرْسِيِّ { اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ } قَالَ فَأَيُّ آيَةٍ يَا نَبِيَّ اللَّهِ تُحِبُّ أَنْ تُصِيبَكَ وَأُمَّتَكَ قَالَ خَاتِمَةُ سُورَةِ الْبَقَرَةِ فَإِنَّهَا مِنْ خَزَائِنِ رَحْمَةِ اللَّهِ مِنْ تَحْتِ عَرْشِهِ أَعْطَاهَا هَذِهِ الْأُمَّةَ لَمْ تَتْرُكْ خَيْرًا مِنْ خَيْرِ الدُّنْيَا وَالْآخِرَةِ إِلَّا اشْتَمَلَتْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] telah menceritakan kepadaku [Aifa' bin Abdul Kala'i] ia berkata; Ada seorang bertanya; Wahai Rasulullah, surat Al Qur'an mana yang paling agung? Beliau menjawab: \"QUL HUWALLAHU AHAD (surat Al Ikhlas).\" Ia bertanya lagi; Lalu ayat apa lagi yang paling agung di dalam Al Qur'an? Beliau menjawab: \"Ayat Kursi: ALLAHU LAAILAAHA ILLA HUWAL HAYYUL QAYYUM (Allah tidak ada Ilah melainkan Dia Yang Hidup kekal lagi terus menerus mengurus (makhlukNya)).\" Ia bertanya lagi; Ayat mana wahai Nabiyullah, yang engkau dan juga umatmu inginkan untuk mendapatkannya? Beliau menjawab: \"Ayat penutup surat Al Baqarah, sebab sesungguhnya ia termasuk perbendaharaan rahmat Allah dari bawah ArasyNya. Dia memberikannya kepada umat ini. Tidak ada satu kebaikan pun dari pada kebaikan dunia dan akhirat kecuali telah dikandung olehnya.\" "},"2840":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو عَاصِمٍ الثَّقَفِيُّ حَدَّثَنَا الشَّعْبِيُّ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ لَقِيَ رَجُلٌ مِنْ أَصْحَابِ مُحَمَّدٍ رَجُلًا مِنْ الْجِنِّ فَصَارَعَهُ فَصَرَعَهُ الْإِنْسِيُّ فَقَالَ لَهُ الْإِنْسِيُّ إِنِّي لَأَرَاكَ ضَئِيلًا شَخِيتًا كَأَنَّ ذُرَيِّعَتَيْكَ ذُرَيِّعَتَا كَلْبٍ فَكَذَلِكَ أَنْتُمْ مَعْشَرَ الْجِنِّ أَمْ أَنْتَ مِنْ بَيْنِهِمْ كَذَلِكَ قَالَ لَا وَاللَّهِ إِنِّي مِنْهُمْ لَضَلِيعٌ وَلَكِنْ عَاوِدْنِي الثَّانِيَةَ فَإِنْ صَرَعْتَنِي عَلَّمْتُكَ شَيْئًا يَنْفَعُكَ قَالَ نَعَمْ قَالَ تَقْرَأُ { اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ } قَالَ نَعَمْ قَالَ فَإِنَّكَ لَا تَقْرَؤُهَا فِي بَيْتٍ إِلَّا خَرَجَ مِنْهُ الشَّيْطَانُ لَهُ خَبَجٌ كَخَبَجِ الْحِمَارِ ثُمَّ لَا يَدْخُلُهُ حَتَّى يُصْبِحَ قَالَ أَبُو مُحَمَّد الضَّئِيلُ الدَّقِيقُ وَالشَّخِيتُ الْمَهْزُولُ وَالضَّلِيعُ جَيِّدُ الْأَضْلَاعِ وَالْخَبَجُ الرِّيحُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu 'Ashim Ats Tsaqafi] telah menceritakan kepada kami [Asy Sya'bi] ia berkata; [Abdullah bin Mas'ud] berkata; Seorang sahabat Muhammad bertemu seseorang dari bangsa jin. Lalu ia bergulat dengannya dan ternyata seseorang dari bangsa manusia dapat mengalahkannya. Lalu seseorang dari bangsa manusia berkata kepadanya; Sesungguhnya aku melihatmu begitu lemah lagi kurus, seakan-akan kedua lenganmu seperti lengan anjing. Seperti itulah kalian hai bangsa jin. Apakah kamu di antara jin-jin lain seperti itu? Ia menjawab; Tidak demi Allah, sesungguhnya aku termasuk yang kuat dari mereka, tetapi temuilah aku kedua kalinya. Jika kamu dapat mengalahkanku lagi, maka aku akan mengajarkan sesuatu yang bermanfaat bagimu. Ia berkata; Baik. Ia berkata; Kamu membaca ayat: ALLAHU LAAILAAHA ILLA HUWAL HAYYUL QAYYUM (Allah tidak ada Ilah melainkan Dia Yang Maha Hidup kekal lagi terus menerus mengurus (makhlukNya). Ia berkata; Baik. Ia melanjutkan; Sesungguhnya tidaklah kamu membacanya di sebuah rumah kecuali setan akan keluar dari rumah itu sambil mengeluarkan angin seperti suara keledai. Kemudian ia tidak akan masuk memasukinya hingga pagi hari. Abu Muhammad berkata; Ia berkata; Adl Dla`il berarti lemah, Asy Syakhit berarti kuat dan Al Khabaj berarti angin."},"2841":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا أَبُو الْعُمَيْسِ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَبْدُ اللَّهِ مَنْ قَرَأَ عَشْرَ آيَاتٍ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ لَمْ يَدْخُلْ ذَلِكَ الْبَيْتَ شَيْطَانٌ تِلْكَ اللَّيْلَةَ حَتَّى يُصْبِحَ أَرْبَعًا مِنْ أَوَّلِهَا وَآيَةُ الْكُرْسِيِّ وَآيَتَانِ بَعْدَهَا وَثَلَاثٌ خَوَاتِيمُهَا أَوَّلُهَا { لِلَّهِ مَا فِي السَّمَوَاتِ }","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Abu Al 'Umais] dari [Asy Sya'bi] ia berkata; [Abdullah] berkata; Barangsiapa yang membaca sepuluh ayat dari surat Al Baqarah pada malam hari, niscaya setan tidak akan masuk ke dalam rumahnya pada malam itu hingga pagi hari. Yaitu empat ayat dari awal surat, ayat kursi dan dua ayat setelahnya, serta tiga ayat penutup surat, yaitu mulai dari ayat: LILLAAHI MAA FIS SAMAAWAATI… (Kepunyaan Allahlah segala apa yang ada di langit…) "},"2842":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ مَسْعُودٍ قَالَ مَنْ قَرَأَ أَرْبَعَ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَآيَةَ الْكُرْسِيِّ وَآيَتَانِ بَعْدَ آيَةِ الْكُرْسِيِّ وَثَلَاثًا مِنْ آخِرِ سُورَةِ الْبَقَرَةِ لَمْ يَقْرَبْهُ وَلَا أَهْلَهُ يَوْمَئِذٍ شَيْطَانٌ وَلَا شَيْءٌ يَكْرَهُهُ وَلَا يُقْرَأْنَ عَلَى مَجْنُونٍ إِلَّا أَفَاقَ","id":"Telah mengabarkan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Asy Sya'bi] dari [Ibnu Mas'ud] ia berkata; Barangsiapa yang membaca empat ayat dari awal surat Al Baqarah, ayat kursi, dua ayat setelahnya dan tiga ayat terakhir dari surat al Baqarah, maka tidak ada satu setan pun yang mendekati dirinya dan keluarganya pada hari itu, serta tidak ada pula sesuatu pun yang ia benci (mendatangkan madharat baginya). Tidaklah dibacakan ayat-ayat tersebut kepada orang gila, kecuali ia pasti sadar."},"2843":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَمَّنْ سَمِعَ عَلِيًّا يَقُولُ مَا كُنْتُ أَرَى أَنَّ أَحَدًا يَعْقِلُ يَنَامُ حَتَّى يَقْرَأَ هَؤُلَاءِ الْآيَاتِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَإِنَّهُنَّ لَمِنْ كَنْزٍ تَحْتَ الْعَرْشِ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Abu Ishaq] dari [orang yang mendengar] [Ali] berkata; Aku tidak melihat seorang berakal tidur hingga ia membaca ayat-ayat terakhir surat Al Baqarah. Sesungguhnya ayat-ayat tersebut termasuk perbendaharaan (rahmat Allah) di bawah 'Arasy."},"2844":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي سِنَانٍ عَنْ الْمُغِيرَةِ بْنِ سُبَيْعٍ وَكَانَ مِنْ أَصْحَابِ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ عَشْرَ آيَاتٍ مِنْ الْبَقَرَةِ عِنْدَ مَنَامِهِ لَمْ يَنْسَ الْقُرْآنَ أَرْبَعُ آيَاتٍ مِنْ أَوَّلِهَا وَآيَةُ الْكُرْسِيِّ وَآيَتَانِ بَعْدَهَا وَثَلَاثٌ مِنْ آخِرِهَا قَالَ إِسْحَقُ لَمْ يَنْسَ مَا قَدْ حَفِظَ قَالَ أَبُو مُحَمَّد مِنْهُمْ مَنْ يَقُولُ الْمُغِيرَةُ بْنُ سُمَيْعٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Abu Al Ahwash] dari [Abu Sinan] dari [Al Mughirah bin Subai'], ia termasuk sahabat Abdullah, ia berkata; Barangsiapa yang membaca sepuluh ayat dari surat Al Baqarah ketika hendak tidur, maka ia tidak akan lupa Al Qur'an. Yaitu empat ayat dari awal surat, ayat kursi, dua ayat setelahnya dan tiga ayat terakhir. Ishaq berkata; Ia tidak akan lupa ayat-ayat Al Qur'an yang telah dihafalnya. Abu Muhammad berkata; Di antara mereka yang mengatakan adalah Al Mughirah bin Sumai'."},"2845":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ أَبِي مُعَاوِيَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الْمُلَيْكِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ آيَةَ الْكُرْسِيِّ وَفَاتِحَةَ حم الْمُؤْمِنِ إِلَى قَوْلِهِ { إِلَيْهِ الْمَصِيرُ } لَمْ يَرَ شَيْئًا يَكْرَهُهُ حَتَّى يُمْسِيَ وَمَنْ قَرَأَهَا حِينَ يُمْسِي لَمْ يَرَ شَيْئًا يَكْرَهُهُ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Abu Mu'awiyah] dari [Abdurahman bin Abu Bakr Al Mulaiki] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca ayat kursi dan ayat pembuka surat Al Mukmin (yakni) HAAMIIM sampai firmanNya WA ILAIHIL MASHIIR (Dan hanya kepadaNyalah kembali (semua makhluk)), maka ia tidak akan melihat sesuatu yang dibenci hingga sore. Barangsiapa yang membacanya ketika berada di waktu sore maka ia tidak akan melihat sesuatu yang dibenci hingga pagi hari.\""},"2846":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَشْعَثُ بْنُ عَبْدِ الرَّحْمَنِ الْجَرْمِيُّ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ كِتَابًا قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ بِأَلْفَيْ عَامٍ فَأَنْزَلَ مِنْهُ آيَتَيْنِ خَتَمَ بِهِمَا سُورَةَ الْبَقَرَةِ وَلَا تُقْرَأَانِ فِي دَارٍ ثَلَاثَ لَيَالٍ فَيَقْرَبُهَا شَيْطَانٌ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Asy'ats bin Abdurrahman Al Jarmi] dari [Abu Qilabah] dari [Abu Al Asy'ats Ash Shan'ani] dari [An Nu'man bin Basyir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah menulis sebuah kitab dua ribu tahun sebelum Dia menciptakan langit dan bumi. Lalu Dia menurunkan dua ayat dari kitab tersebut, Dia menutup surat Al Baqarah dengan kedua ayat itu. Dan jika dua ayat itu dibaca di sebuah rumah selama tiga malam, maka setan tidak dapat mendekatinya.\""},"2847":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ الْآخِرَتَيْنِ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka kedua ayat itu telah mencukupinya.\""},"2848":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ { اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ } { وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ubaidullah bin Abu Ziyad] dari [Syahr bin Hausyab] dari [Asma` bintu Yazid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nama Allah yang paling agung terdapat dalam dua ayat ini: LAA ILAAHA ILLA HUWAL HAYYUL QAYYUM (Allah tidak ada Ilah melainkan Dia Yang Hidup kekal lagi terus menerus mengurus (makhlukNya)) dan WA ILAAHUKUM ILAAHUN WAHID (Rabb kalian adalah Rabb Yang Maha Esa).\""},"2849":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرٌ هُوَ ابْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُ ثُمَّ سَكَتَ سَاعَةً ثُمَّ قَالَ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ وَآلِ عِمْرَانَ فَإِنَّهُمَا الزَّهْرَاوَانِ وَإِنَّهُمَا تُظِلَّانِ صَاحِبَهُمَا يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ غَيَايَتَانِ أَوْ فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ وَإِنَّ الْقُرْآنَ يَلْقَى صَاحِبَهُ يَوْمَ الْقِيَامَةِ حِينَ يَنْشَقُّ عَنْهُ الْقَبْرُ كَالرَّجُلِ الشَّاحِبِ فَيَقُولُ لَهُ هَلْ تَعْرِفُنِي فَيَقُولُ مَا أَعْرِفُكَ فَيَقُولُ أَنَا صَاحِبُكَ الْقُرْآنُ الَّذِي أَظْمَأْتُكَ فِي الْهَوَاجِرِ وَأَسْهَرْتُ لَيْلَكَ وَإِنَّ كُلَّ تَاجِرٍ مِنْ وَرَاءِ تِجَارَتِهِ وَإِنَّكَ الْيَوْمَ مِنْ وَرَاءِ كُلِّ تِجَارَةٍ فَيُعْطَى الْمُلْكَ بِيَمِينِهِ وَالْخُلْدَ بِشِمَالِهِ وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ وَيُكْسَى وَالِدَاهُ حُلَّتَيْنِ لَا يُقَوَّمُ لَهُمَا الدُّنْيَا فَيَقُولَانِ بِمَ كُسِينَا هَذَا وَيُقَالُ لَهُمَا بِأَخْذِ وَلَدِكُمَا الْقُرْآنَ ثُمَّ يُقَالُ لَهُ اقْرَأْ وَاصْعَدْ فِي دَرَجِ الْجَنَّةِ وَغُرَفِهَا فَهُوَ فِي صُعُودٍ مَا دَامَ يَقْرَأُ هَذًّا كَانَ أَوْ تَرْتِيلًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir] ia adalah Ibnu Al Muhajir telah menceritakan kepadaku [Abdullah bin Buraidah] dari [ayahnya] ia berkata; Aku pernah duduk di sebelah Nabi shallallahu 'alaihi wasallam, aku mendengar beliau bersabda: \"Pelajarilah surat Al Baqarah sebab mempelajarinya adalah keberkahan dan meninggalkannya adalah kerugian. Para penyihir tidak mampu mengalahkannya.\" Kemudian beliau diam sesaat, lalu bersabda: \"Pelajarilah surah Al Baqarah dan surah Ali Imran, sesungguhnya kedua surat itu dinamakan 'az zahrawan' dan kedua surat itu juga akan menaungi pembacanya pada hari kiamat. Seakan-akan kedua surat itu seperti dua buah awan atau dua benda yang biasa menaungi manusia atau dua kelompok burung yang membentangkan sayapnya. Sesungguhnya Al Qur'an akan menemui pembacanya pada hari kiamat ketika kubur terbelah seperti seorang laki-laki pucat karena takut. Ia berkata kepada pembacanya; Apakah engkau mengenalku? Ia menjawab; Aku tidak mengenalmu. Ia berkata; Aku adalah temanmu, Al Qur'an, yang menghilangkan haus pada siang hari yang panas dan membuatmu begadang di malam hari. Sesungguhnya setiap pedagang akan mendapatkan laba dari perdagangannya. Sesungguhnya hari ini engkau mendapatkan pahala dari setiap perdagangan (yang telah engkau lakukan). Lalu kerajaan diberikan di tangan kanan pembaca Al Qur'an itu dan keabadian di tangan kirinya, serta diletakkan mahkota ketenangan di kepalanya. Sementara kedua orang tuanya diberi dua perhiasan yang tidak ternilai harganya di dunia. Kedua orang tuanya berkata; Karena apa kami diberi perhiasan ini? Dikatakan kepada keduanya; Karena anak kalian mempelajari Al Qur'an. Kemudian dikatakan kepadanya; Bacalah dan naiklah ke tangga-tangga surga dan kamar-kamarnya. Maka ia pun terus naik selama ia membaca, baik secara cepat maupun secara lambat.\" "},"2850":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ أَبِي يَحْيَى سُلَيْمِ بْنِ عَامِرٍ أَنَّهُ سَمِعَ أَبَا أُمَامَةَ يَقُولُ إِنَّ أَخًا لَكُمْ أُرِيَ فِي الْمَنَامِ أَنَّ النَّاسَ يَسْلُكُونَ فِي صَدْعِ جَبَلٍ وَعْرٍ طَوِيلٍ وَعَلَى رَأْسِ الْجَبَلِ شَجَرَتَانِ خَضْرَاوَانِ تَهْتِفَانِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ الْبَقَرَةِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ آلِ عِمْرَانَ فَإِذَا قَالَ الرَّجُلُ نَعَمْ دَنَتَا بِأَعْذَاقِهِمَا ��َتَّى يَتَعَلَّقَ بِهِمَا فَتَخْطِرَانِ بِهِ الْجَبَلَ قَالَ أَبُو مُحَمَّد الْأَعْذَاقُ الْأَغْصَانُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu'awiyah] dari [Abu Yahya Sulaim bin Amir] bahwa ia mendengar [Abu Umamah] berkata; Sesungguhnya ada seorang saudara kalian yang diperlihatkan dalam mimpi bahwa manusia berjalan di jalan setapak sebuah gunung yang tidak rata lagi panjang. Di puncak gunung itu ada dua batang pohon hijau yang bersuara; Apakah di antara kalian ada orang yang membaca surah Al Baqarah? Apakah di antara kalian ada orang yang membaca surah Ali Imran? Tiba-tiba ada seseorang menjawab; Ya, maka kedua pohon itu mendekatkan dahannya hingga orang itu dapat meraihnya. Lalu kedua pohon itu membawanya melewati gunung. Abu Muhammad berkata; Al A'dzaq berarti dahan pohon."},"2851":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدٍ عَنْ جَابِرٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَرَأَ رَجُلٌ عِنْدَ عَبْدِ اللَّهِ الْبَقَرَةَ وَآلَ عِمْرَانَ فَقَالَ قَرَأْتَ سُورَتَيْنِ فِيهِمَا اسْمُ اللَّهِ الْأَعْظَمُ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ وَإِذَا سُئِلَ بِهِ أَعْطَى","id":"Telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] dari [Ubaidullah bin Amr] dari [Zaid] dari [Jabir] dari [Abu Adl Dluha] dari [Masruq] dari [Abdullah] ia berkata; Ada seseorang membaca surat Al Baqarah dan surat Ali Imran di samping Abdullah, lalu ia pun berkata; Engkau telah membaca dua surat yang di dalamnya terdapat nama Allah yang paling agung, yang apabila digunakan ketika berdoa pasti diperkenankan dan apabila digunakan ketika meminta pasti dikabulkan."},"2852":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عَطَّافٍ عَنْ كَعْبٍ قَالَ مَنْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ جَاءَتَا يَوْمَ الْقِيَامَةِ تَقُولَانِ رَبَّنَا لَا سَبِيلَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Al Jurairi] dari [Abu 'Aththaf] dari [Ka'b] ia berkata; Barangsiapa yang membaca surat Al Baqarah dan surat Ali Imran, maka kedua surat itu akan datang pada hari kiamat seraya berkata; Wahai Rabb kami, tidak ada alasan untuk mencelakainya."},"2853":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ سُلَيْمِ بْنِ حَنْظَلَةَ الْبَكْرِيِّ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ مَنْ قَرَأَ آلَ عِمْرَانَ فَهُوَ غَنِيٌّ وَالنِّسَاءُ مُحَبِّرَةٌ قَالَ أَبُو مُحَمَّد مُحَبِّرَةٌ مُزَيِّنَةٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Sulaim bin Hanzhalah Al Bakri] ia berkata; [Abdullah bin Mas'ud] berkata; Barangsiapa yang membaca surat Ali Imran maka ia adalah orang kaya, sedangkan jika ia seorang perempuan maka ia adalah orang yang berhias. [Abu Muhammad] berkata; Muhabbirah berarti perempuan yang berhias."},"2854":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ ابْنِ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَ مَنْ قَرَأَ آخِرَ آلِ عِمْرَانَ فِي لَيْلَةٍ كُتِبَ لَهُ قِيَامُ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Utsman bin 'Affan] ia berkata; Barangsiapa yang membaca akhir surat Ali Imran pada malam hari, maka ditulis baginya pahala shalat malam."},"2855":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ مَكْحُولٍ قَالَ مَنْ قَرَأَ سُورَةَ آلِ عِمْرَانَ يَوْمَ الْجُمُعَةِ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ إِلَى اللَّيْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Shadaqah bin Khalid] dari [Yahya bin Al Harits] dari [Makhul] ia berkata; Barangsiapa yang membaca surat Ali Imran pada hari Jum'at, maka para malaikat mendo'akan untuknya sampai tiba malam hari."},"2856":{"ar":" حَدَّثَنَا الْقَاسِمُ بْنُ سَلَّامٍ أَبُو عُبَيْدٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ حَدَّثَنِي مِسْعَرٌ حَدَّثَنِي جَابِرٌ قَبْلَ أَنْ يَقَعَ فِيمَا وَقَعَ فِيهِ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَبْدُ اللَّهِ نِعْمَ كَنْزُ الصُّعْلُوكِ سُورَةُ آلِ عِمْرَانَ يَقُومُ بِهَا فِي آخِرِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Al Qasim bin Sallam Abu Ubaid] ia berkata; Telah menceritakan kepadaku [Ubaidullah Al Asyja'i] telah menceritakan kepadaku [Mis'ar] telah menceritakan kepadaku [Jabir] sebelum terjadi sesuatu padanya, dari [Asy Sya'bi] ia berkata; [Abdullah] berkata; Sebaik-baik perbendaharaan orang fakir adalah surat Ali Imran yang ia baca ketika melakukan shalat di akhir malam."},"2857":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ قَالَ أَصَابَ رَجُلٌ دَمًا قَالَ فَأَوَى إِلَى وَادِي مَجَنَّةٍ وَادٍ لَا يُمْسِي فِيهِ أَحَدٌ إِلَّا أَصَابَتْهُ حَيَّةٌ وَعَلَى شَفِيرِ الْوَادِي رَاهِبَانِ فَلَمَّا أَمْسَى قَالَ أَحَدُهُمَا لِصَاحِبِهِ هَلَكَ وَاللَّهِ الرَّجُلُ قَالَ فَافْتَتَحَ سُورَةَ آلِ عِمْرَانَ قَالَا فَقَرَأَ سُورَةً طَيِّبَةً لَعَلَّهُ سَيَنْجُو قَالَ فَأَصْبَحَ سَلِيمًا قَالَ أَبُو مُحَمَّد أَبُو السَّلِيلِ ضُرَيْبُ بْنُ نُقَيْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam] dari [Al Jurairi] dari [Abu As Salil] ia berkata; Ada seseorang terluka mengeluarkan darah. Ia melanjutkan; Lalu orang itu singgah di lembah Majannah, sebuah lembah yang tidak seorang pun berada di waktu sore kecuali menjadi gila, sementara di tepi lembah ada dua orang pendeta. Ketika orang itu berada di waktu sore, salah seorang pendeta berkata kepada temannya; Demi Allah, celakalah orang itu. Ia melanjutkan; Lalu orang itu membaca awal surat Ali Imran, maka kedua pendeta tersebut berkata; Ia telah membaca sebuah surat yang baik, semoga ia selamat. Ia berkata lagi; Maka selamatlah orang itu. [Abu Muhammad] berkata; Abu As Salil adalah Dluraib bin Nuqair. "},"2858":{"ar":" حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ حَدَّثَنَا عَاصِمٌ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ قَالَ قَالَ عَبْدُ اللَّهِ السَّبْعُ الطُّوَلُ مِثْلُ التَّوْرَاةِ وَالْمِئِينَ مِثْلُ الْإِنْجِيلِ وَالْمَثَانِي مِثْلُ الزَّبُورِ وَسَائِرُ الْقُرْآنِ بَعْدُ فَضْلٌ","id":"Telah menceritakan kepada kami [Mu'adz bin Hani`] telah menceritakan kepada kami [Ibrahim bin Thahman] telah menceritakan kepada kami ['Ashim] dari [Al Musayyab bin Rafi'] ia berkata; [Abdullah] berkata; As Sab'u ath Thuwal seperti Taurat, Al Mi`in (Al Mi`un) seperti Injil, Al Matsaani seperti Zabur, dan seluruh surat Al Qur'an lainnya memiliki keutamaan. "},"2859":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ خَلِيفَةَ عَنْ عُمَرَ قَالَ الْأَنْعَامُ مِنْ نَوَاجِبِ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abdullah bin Khalifah] dari [Umar] ia berkata; Surat Al An'am termasuk surat Al Qur'an yang berharga."},"2860":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ كَعْبٍ قَالَ فَاتِحَةُ التَّوْرَاةِ الْأَنْعَامُ وَخَاتِمَتُهَا هُودٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] dari [Abu Imran Al Jauni] dari [Abdullah bin Rabah] dari [Ka'b] ia berkata; Pembuka Taurat adalah surat Al An'am dan penutupnya adalah surat Hud."},"2861":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْرَءُوا سُورَةَ هُودٍ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dari [Abu Imran Al Jauni] dari [Abdullah bin Rabah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bacalah surat Hud pada hari Jum'at.\""},"2862":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ كَعْبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا سُورَةَ هُودٍ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Abdullah bin Rabah] dari [Ka'b] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah surat Hud pada hari Jum'at.\""},"2863":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَتْنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ مَنْ قَرَأَ عَشْرَ آيَاتٍ مِنْ الْكَهْفِ لَمْ يَخَفْ الدَّجَّالَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdah] dari [Khalid bin Ma'dan] ia berkata; Barangsiapa yang membaca sepuluh ayat dari surat Al Kahfi, maka ia tidak akan takut terhadap Dajjal."},"2864":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ عَبْدَةَ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَ مَنْ قَرَأَ آخِرَ سُورَةِ الْكَهْفِ لِسَاعَةٍ يُرِيدُ يَقُومُ مِنْ اللَّيْلِ قَامَهَا قَالَ عَبْدَةُ فَجَرَّبْنَاهُ فَوَجَدْنَاهُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Abdah] dari [Zirr bin Hubaisy] ia berkata; Barangsiapa yang membaca akhir surat Al Kahfi karena ingin bangun pada malam hari, maka ia terbangun. [Abdah] berkata; Maka kami membuktikannya, ternyata kami mendapatkan seperti itu."},"2865":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ مَنْ قَرَأَ سُورَةَ الْكَهْفِ لَيْلَةَ الْجُمُعَةِ أَضَاءَ لَهُ مِنْ النُّورِ فِيمَا بَيْنَهُ وَبَيْنَ الْبَيْتِ الْعَتِيقِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin Ubad] dari [Abu Sa'id Al Khudri] ia berkata; Barangsiapa yang membaca surat Al Kahfi pada malam Jum'at maka ia akan diterangi oleh cahaya yang terangnya mencapai jarak antara dirinya dan Baitul 'Atiq."},"2866":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَتْنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ اقْرَءُوا الْمُنَجِّيَةَ وَهِيَ الم تَنْزِيلُ فَإِنَّهُ بَلَغَنِي أَنَّ رَجُلًا كَانَ يَقْرَؤُهَا مَا يَقْرَأُ شَيْئًا غَيْرَهَا وَكَانَ كَثِيرَ الْخَطَايَا فَنَشَرَتْ جَنَاحَهَا عَلَيْهِ وَقَالَتْ رَبِّ اغْفِرْ لَهُ فَإِنَّهُ كَانَ يُكْثِرُ قِرَاءَتِي فَشَفَّعَهَا الرَّبُّ فِيهِ وَقَالَ اكْتُبُوا لَهُ بِكُلِّ خَطِيئَةٍ حَسَنَةً وَارْفَعُوا لَهُ دَرَجَةً","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami ['Abdah] dari [Khalid bin Ma'dan], ia berkata; Bacalah Al Munajjiyah, yaitu ALIF LAAM MIIM TANZIIL (surat As Sajdah). Sebab, aku mendapat kabar bahwa ada seorang laki-laki yang hanya membacanya dan tidak ada surat lain yang dibacanya, padahal dia orang yang banyak kesalahan, maka sayap surat itu terbentang untuknya dan berkata, Wahai Tuhanku, ampunilah dia, sebab dia sering sekali membacaku. Maka, Tuhan memberi izin kepada surat itu untuk menolongnya serya berfirman, \"Tuliskan untuknya setiap kesalahan menjadi satu kebaikan dan angkat satu derajat baginya.\" "},"2867":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَبُو الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ ضَمْرَةَ عَنْ كَعْبٍ قَالَ مَنْ قَرَأَ تَنْزِيلُ السَّجْدَةَ وَ تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ كُتِبَ لَهُ سَبْعُونَ حَسَنَةً وَحُطَّ عَنْهُ بِهَا سَبْعُونَ سَيِّئَةً وَرُفِعَ لَهُ بِهَا سَبْعُونَ دَرَجَةً","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Abu Az Zubair] dari [Abdullah bin Dlamrah] dari [Ka'b] ia berkata; Barangsiapa yang membaca ALIF LAAM MIIM TANZIIL (surat As Sajdah) dan TABAARAKALLADZI BIYADIHIL MULKU (surat Al Mulk), maka akan ditulis baginya tujuh puluh kebaikan dan dihapuskan darinya tujuh puluh keburukan, serta dengan surat itu diangkat baginya tujuh puluh derajat."},"2868":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ أَنَّهُ سَمِعَ أَبَا خَالِدٍ عَامِرَ بْنَ جَشِيبٍ وَبَحِيرَ بْنَ سَعْدٍ يُحَدِّثَانِ أَنَّ خَالِدَ بْنَ مَعْدَانَ قَالَ إِنَّ الم تَنْزِيلُ تُجَادِلُ عَنْ صَاحِبِهَا فِي الْقَبْرِ تَقُولُ اللَّهُمَّ إِنْ كُنْتُ مِنْ كِتَابِكَ فَشَفِّعْنِي فِيهِ وَإِنْ لَمْ أَكُنْ مِنْ كِتَابِكَ فَامْحُنِي عَنْهُ وَإِنَّهَا تَكُونُ كَالطَّيْرِ تَجْعَلُ جَنَاحَهَا عَلَيْهِ فَيُشْفَعُ لَهُ فَتَمْنَعُهُ مِنْ عَذَابِ الْقَبْرِ وَفِي تَبَارَكَ مِثْلَهُ فَكَانَ خَالِدٌ لَا يَبِيتُ حَتَّى يَقْرَأَ بِهِمَا","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu'awiyah bin Shalih] bahwa ia mendengar [Abu Khalid Amir bin Jasyib] dan [Bahir bin Sa'd] keduanya menceritakan bahwa [Khalid bin Ma'dan] berkata; Sesungguhnya ALIF LAAM MIIM TANZIIL (surat As Sajdah) akan membela pembacanya di dalam kubur. Surat itu berkata; Ya Allah, jika aku termasuk dari kitabMu maka izinkan aku memberi syafaat padanya, namun jika aku tidak termasuk dari kitabMu maka hapuslah aku dari kitabMu. Sesungguhnya surat itu akan menjadi seperti burung yang membentangkan sayapnya di atas pembacanya, lalu memberi syafaat kepadanya. Ia menghalangi pembacanya dari siksa kubur. Demikian pula dengan TABAARAKALLADZI BIYADIHIL MULKU (surat Al Mulk) seperti itu. Khalid tidak pernah tidur malam hingga ia membaca kedua surat tersebut."},"2869":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنَامُ حَتَّى يَقْرَأَ تَنْزِيلُ السَّجْدَةَ وَتَبَارَكَ","id":"Telah mengabarkan kepada kami [Abu An Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Abu Az Zubair] dari [Jabir] ia berkata; Nabi shallallahu 'alaihi wasallam tidak tidur hingga membaca ALIF LAAM MIIM TANZIIL (surat As Sajdah) dan TABAARAKALLADZI BIYADIHIL MULKU (surat Al Mulk)."},"2870":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ لَيْثٍ عَنْ طَاوُسٍ قَالَ فُضِّلَتَا عَلَى كُلِّ سُورَةٍ فِي الْقُرْآنِ بِسِتِّينَ حَسَنَةً","id":"Telah menceritakan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir] dari [Laits] dari [Thawus] ia berkata; Kedua surat itu (surat As Sajdah dan Al Mulk) diberi keutamaan dari semua surat dalam Al Qur'an dengan enam puluh kebaikan."},"2871":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ مُرَّةَ يَقُولُ أُتِيَ رَجُلٌ فِي قَبْرِهِ فَأُتِيَ جَانِبُ قَبْرِهِ فَجَعَلَتْ سُورَةٌ مِنْ الْقُرْآنِ ثَلَاثُونَ آيَةً تُجَادِلُ عَنْهُ حَتَّى قَالَ فَنَظَرْنَا أَنَا وَمَسْرُوقٌ فَلَمْ نَجِدْ فِي الْقُرْآنِ سُورَةً ثَلَاثِينَ آيَةً إِلَّا تَبَارَكَ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Amr bin Murrah] ia berkata; Aku mendengar [Murrah] berkata; Ada seseorang dimasukkan ke dalam kuburnya, lalu ia ditemui dari sisi kuburnya ternyata sebuah surat dari Al Qur'an yang berjumlah tiga puluh ayat membelanya, hingga ia berkata; Lalu aku dan Masruq melihat isi Al Qur'an, namun kami tidak menemukan di dalam Al Qur'an sebuah surat yang berjumlah tiga puluh ayat kecuali TABAARAKA (surat Al Mulk)."},"2872":{"ar":" حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُهَاجِرِ بْنِ الْمِسْمَارِ عَنْ عُمَرَ بْنِ حَفْصِ بْنِ ذَكْوَانَ عَنْ مَوْلَى الْحُرَقَةِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَرَأَ طه وْ يس قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ بِأَلْفِ عَامٍ فَلَمَّا سَمِعَتْ الْمَلَائِكَةُ الْقُرْآنَ قَالَتْ طُوبَى لِأُمَّةٍ يَنْزِلُ هَذَا عَلَيْهَا وَطُوبَى لِأَجْوَافٍ تَحْمِلُ هَذَا وَطُوبَى لِأَلْسِنَةٍ تَتَكَلَّمُ بِهَذَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Ibrahim bin Al Muhajir bin Al Mismar] dari [Umar bin Hafsh bin Dzakwan] dari [mantan budak Al Huraqah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Tabaraka wa Ta'ala membaca surat Thaha dan surat Yasin seribu tahun sebelum menciptakan langit dan bumi. Ketika para malaikat mendengar Al Qur'an, mereka berkata; Beruntunglah umat yang diturunkan surat itu padanya, beruntunglah rongga yang mengandung surat itu, dan beruntunglah lidah yang berbicara dengan surat itu."},"2873":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ بَلَغَنِي عَنْ الْحَسَنِ قَالَ مَنْ قَرَأَ يس فِي لَيْلَةٍ ابْتِغَاءَ وَجْهِ اللَّهِ أَوْ مَرْضَاةِ اللَّهِ غُفِرَ لَهُ وَقَالَ بَلَغَنِي أَنَّهَا تَعْدِلُ الْقُرْآنَ كُلَّهُ","id":"Telah menceritakan kepada kami [Abu Al Walid Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] ia berkata; Telah sampai berita kepadaku dari [Al Hasan] ia berkata; Barangsiapa yang membaca surat Yasin pada malam hari karena mengharap wajah Allah atau mengharap keridlaan Allah niscaya ia akan diampuni. Ia berkata lagi; Telah sampai berita kepadaku bahwa surat itu menyamai Al Qur'an seluruhnya."},"2874":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ هَارُونَ أَبِي مُحَمَّدٍ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ شَيْءٍ قَلْبًا وَإِنَّ قَلْبَ الْقُرْآنِ يس مَنْ قَرَأَهَا فَكَأَنَّمَا قَرَأَ الْقُرْآنَ عَشْرَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Humaid bin Abdurrahman] dari [Al Hasan bin Shalih] dari [Harun Abu Muhammad] dari [Muqatil bin Hayyan] dari [Qatadah] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap sesuatu memiliki hati dan sesungguhnya hati Al Qur'an adalah surat Yasin. Barangsiapa yang membacanya, maka ia seakan-akan telah membaca Al Qur'an sebanyak sepuluh kali.\""},"2875":{"ar":" حَدَّثَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنِي أَبِي حَدَّثَنِي زِيَادُ بْنُ خَيْثَمَةَ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ يس فِي لَيْلَةٍ ابْتِغَاءَ وَجْهِ اللَّهِ غُفِرَ لَهُ فِي تِلْكَ اللَّيْلَةِ","id":"Telah menceritakan kepada kami [Al Walid bin Syuja'] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ziyad bin Khaitsamah] dari [Muhammad bin Juhadah] dari [Al Hasan] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca surat Yasin pada malam hari karena mengharap wajah Allah niscaya ia akan diampuni pada malam hari tersebut.\""},"2876":{"ar":" حَدَّثَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنِي أَبِي حَدَّثَنِي زِيَادُ بْنُ خَيْثَمَةَ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَ بَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ يس فِي صَدْرِ النَّهَارِ قُضِيَتْ حَوَائِجُهُ","id":"Telah menceritakan kepada kami [Al Walid bin Syuja'] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ziyad bin Khaitsamah] dari [Muhammad bin Juhadah] dari ['Atha` bin Abu Rabah] ia berkata; Telah sampai berita kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca surat Yasin pada awal siang niscaya akan terpenuhi semua kebutuhannya.\""},"2877":{"ar":" حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا رَاشِدٌ أَبُو مُحَمَّدٍ الْحِمَّانِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَ قَالَ ابْنُ عَبَّاسٍ مَنْ قَرَأَ يس حِينَ يُصْبِحُ أُعْطِيَ يُسْرَ يَوْمِهِ حَتَّى يُمْسِيَ وَمَنْ قَرَأَهَا فِي صَدْرِ لَيْلِهِ أُعْطِيَ يُسْرَ لَيْلَتِهِ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Amr bin Zurarah] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Rasyid Abu Muhammad Al Himmani] dari [Syahr bin Hausyab] ia berkata; [Ibnu Abbas] berkata; Barangsiapa yang membaca surat Yasin ketika berada di waktu pagi niscaya diberikan kepadanya kemudahan hari itu hingga ia berada di waktu sore, dan barangsiapa yang membacanya pada awal malam niscaya diberikan kepadanya kemudahan malam itu hingga ia berada di waktu pagi."},"2878":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى قَالَ أُخْبِرْتُ أَنَّهُ مَنْ قَرَأَ حم الدُّخَانَ لَيْلَةَ الْجُمُعَةِ إِيمَانًا وَتَصْدِيقًا بِهَا أَصْبَحَ مَغْفُورًا لَهُ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari [Abdullah bin Isa] ia berkata; Telah dikabarkan kepadaku bahwa barangsiapa yang membaca HAA MIIM (surat Ad Dukhan) pada malam Jum'at karena keimanan dan membenarkan surat tersebut niscaya ia berada di waktu pagi dalam keadaan telah diampuni."},"2879":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ أَبِي رَافِعٍ قَالَ مَنْ قَرَأَ الدُّخَانَ فِي لَيْلَةِ الْجُمُعَةِ أَصْبَحَ مَغْفُورًا لَهُ وَزُوِّجَ مِنْ الْحُورِ الْعِينِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Shadaqah bin Khalid] dari [Yahya bin Al Harits] dari [Abu Rafi'] ia berkata; Barangsiapa yang membaca surat Ad Dukhan pada malam Jum'at niscaya ia berada di waktu pagi dalam keadaan telah diampuni dan ia akan dikawinkan dengan bidadari."},"2880":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ مِسْعَرٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ كُنَّ الْحَوَامِيمُ يُسَمَّيْنَ الْعَرَائِسَ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Mis'ar] dari [Sa'd bin Ibrahim] ia berkata; Surat-surat yang diawali dengan (bacaan) HAA MIIM dinamakan dengan Al 'Ara`is (para pengantin)."},"2881":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ مَنْ قَرَأَ ثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ إِذَا أَصْبَحَ فَمَاتَ مِنْ يَوْمِهِ ذَلِكَ طُبِعَ بِطَابَعِ الشُّهَدَاءِ وَإِنْ قَرَأَ إِذَا أَمْسَى فَمَاتَ مِنْ لَيْلَتِهِ طُبِعَ بِطَابَعِ الشُّهَدَاءِ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Hisyam] dari [Al Hasan] ia berkata; Barangsiapa yang membaca tiga ayat dari akhir surat Al Hasyr ketika berada di waktu pagi, lalu ia meninggal di hari itu maka ia dicap sebagai syahid. jika ia membacanya ketika berada di waktu sore, lalu ia meninggal pada malam itu maka ia dicap sebagai syahid."},"2882":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ مَعْنٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ الْمُسَبِّحَاتِ عِنْدَ النَّوْمِ وَيَقُولُ إِنَّ فِيهِنَّ آيَةً تَعْدِلُ أَلْفَ آيَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Ma'n] dari [Mu'awiyah bin Shalih] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari Nabi shallallahu 'alaihi wasallam bahwa beliau selalu membaca surat-surat yang diawali dengan tasbih ketika hendak tidur. Beliau bersabda: \"Sesungguhnya pada surat-surat itu ada satu ayat yang menyamai seribu ayat.\""},"2883":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَرَجِ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا خَالِدُ بْنُ طَهْمَانَ أَبُو الْعَلَاءِ الْخَفَّافُ حَدَّثَنِي نَافِعُ بْنُ أَبِي نَافِعٍ عَنْ مَعْقِلِ بْنِ يَسَارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يُصْبِحُ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ وَثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَكَّلَ اللَّهُ بِهِ سَبْعِينَ أَلْفَ مَلَكٍ يُصَلُّونَ عَلَيْهِ حَتَّى يُمْسِيَ وَإِنْ قَالَهَا مَسَاءً فَمِثْلُ ذَلِكَ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Faraj Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Abdullah bin Az Zubair] telah menceritakan kepada kami [Khalid bin Thahman Abu Al 'Ala` Al Khaffaf] telah menceritakan kepadaku [Nafi' bin Abu Nafi'] dari [Ma'qil bin Yasar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang mengucapkan ketika berada di waktu pagi; A'UDZUBILLAHIS SAMI'IL 'ALIM MINASY SYAITHANIR RAJIM dan tiga ayat dari akhir surat Al Hasyr, maka Allah akan menugaskan tujuh puluh ribu malaikat untuk memintakan ampun untuknya hingga ia berada di waktu sore. Dan jika ia membacanya di waktu sore, maka Allah akan menugaskan tujuh puluh ribu malaikat untuk memintakan ampun untuknya juga hingga ia berada di waktu pagi.\""},"2884":{"ar":" حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْحَسَنِ مُهَاجِرٍ قَالَ جَاءَ رَجُلٌ زَمَنَ زِيَادٍ إِلَى الْكُوفَةِ فَسَمِعْتُهُ يُحَدِّثُ أَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ قَالَ وَرُكْبَتِي تُصِيبُ أَوْ تَمَسُّ رُكْبَتَهُ فَسَمِعَ رَجُلًا يَقْرَأُ قُلْ يَا أَيُّهَا الْكَافِرُونَ قَالَ بَرِئَ مِنْ الشِّرْكِ وَسَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ قَالَ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Abu Al Hasan Muhajir] ia berkata; [Ada seorang laki-laki] datang ke Kufah pada masa pemerintahan Ziyad. Lalu aku mendengar orang itu menceritakan bahwa ia pernah bersama Rasulullah shallallahu 'alaihi wasallam pada sebuah perjalanan. Ia berkata; Lututku mengenai atau menyentuh lutut beliau, lalu beliau mendengar seseorang membaca; QUL YA AYYUHAL KAFIRUN (surat Al Kafirun). Beliau bersabda: \"Ia bebas dari syirik.\" Dan beliau mendengar seseorang membaca; QUL HUWALLAHU AHAD (surat Al Ikhlas). Beliau bersabda: \"Ia telah diampuni.\""},"2885":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَجِيءٌ مَا جَاءَ بِكَ قَالَ جِئْتُ لِتُعَلِّمَنِي شَيْئًا أَقُولُهُ عِنْدَ مَنَامِي قَالَ فَإِذَا أَخَذْتَ مَضْجَعَكَ فَاقْرَأْ قُلْ يَا أَيُّهَا الْكَافِرُونَ ثُمَّ نَمْ عَلَى خَاتِمَتِهَا فَإِنَّهَا بَرَاءَةٌ مِنْ الشِّرْكِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Farwah bin Naufal] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah bertanya: \"Apa yang membuatmu datang ke sini?\" Ia menjawab; Aku datang agar engkau mengajariku sesuatu yang harus aku baca ketika hendak tidur. Beliau menjawab: \"Jika engkau telah berada di tempat pembaringan maka bacalah; \"QUL YA AYYUHAL KAFIRUN (surat Al Kafirun) kemudian tidurlah setelah selesai membacanya, sebab surat itu merupakan jaminan kebebasan dari syirik.\""},"2886":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنَا إِيَاسٌ الْبِكَالِيُّ عَنْ نَوْفٍ الْبِكَالِيِّ قَالَ إِنَّ اللَّهَ جَزَّأَ الْقُرْآنَ عَلَى ثَلَاثَةِ أَجْزَاءٍ فَجَعَلَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] telah menceritakan kepada kami [Iyas Al Bikali] dari [Nauf Al Bikali] ia berkata; Sesungguhnya Allah telah membagi Al Qur'an menjadi tiga bagian, lalu Dia menjadikan QUL HUWALLAHU AHAD (surat Al Ikhlas) sepertiga dari Al Qur'an."},"2887":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي أَبُو عَقِيلٍ أَنَّهُ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ عَشْرَ مَرَّاتٍ بُنِيَ لَهُ بِهَا قَصْرٌ فِي الْجَنَّةِ وَمَنْ قَرَأَ عِشْرِينَ مَرَّةً بُنِيَ لَهُ بِهَا قَصْرَانِ فِي الْجَنَّةِ وَمَنْ قَرَأَهَا ثَلَاثِينَ مَرَّةً بُنِيَ لَهُ بِهَا ثَلَاثَةُ قُصُورٍ فِي الْجَنَّةِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ وَاللَّهِ يَا رَسُولَ اللَّهِ إِذَنْ لَتَكْثُرَنَّ قُصُورُنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَوْسَعُ مِنْ ذَلِكَ قَالَ أَبُو مُحَمَّد أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ وَزَعَمُوا أَنَّهُ كَانَ مِنْ الْأَبْدَالِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] ia berkata; telah mengabarkan kepadaku [Abu 'Aqil] bahwa ia mendengar [Sa'id bin Al Musayyab] berkata; Sesungguhnya Nabiyullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa yang membaca QUL HUWALLAHU AHAD (surat Al Ikhlas) sepuluh kali, niscaya akan dibangunkan sebuah istana untuknya di surga, barangsiapa yang membacanya dua puluh kali, niscaya akan dibangunkan dua buah istana untuknya di surga dan barangsiapa yang membacanya tiga puluh kali, niscaya akan dibangunkan tiga buah istana untuknya di surga.\" Lalu Umar bin Al Khaththab bertanya; Demi Allah, wahai Rasulullah, kalau begitu kami dapat memperbanyak istana kami? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Allah lebih luas kekayaannya dari itu.\" Abu Muhammad berkata; Abu 'Aqil adalah Zuhrah bin Ma'bad dan mereka menganggap bahwa ia termasuk abdal. "},"2888":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ عَنْ عُتْبَةَ بْنِ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ أَبِيهِ أَنَّهُ كَانَ إِذَا قَرَأَ سُورَةً فَخَتَمَهَا أَتْبَعَهَا بِقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] dari [Utbah bin Dlamrah bin Habib] dari [ayahnya] bahwa jika ia membaca suatu surat dan menyelesaikannya, maka ia selalu mengiringinya dengan membaca QUL HUWALLAHU AHAD (surat Al Ikhlas)."},"2889":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ عَنْ أَبَانَ بْنِ يَزِيدَ الْعَطَّارِ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الدَّرْدَاءِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَعْجِزُ أَحَدُكُمْ أَنْ يَقْرَأَ فِي لَيْلَةٍ ثُلُثَ الْقُرْآنِ قَالُوا نَحْنُ أَعْجَزُ وَأَضْعَفُ مِنْ ذَلِكَ فَقَالَ إِنَّ اللَّهَ جَزَّأَ الْقُرْآنَ ثَلَاثَةَ أَجْزَاءٍ فَجَعَلَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] dari [Aban bin Yazid Al 'Aththar] telah menceritakan kepada kami [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Abu Ad Darda`] ia berkata; Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah salah seorang dari kalian tidak sanggup untuk membaca sepertiga Al Qur'an di malam hari?\" Mereka menjawab; Kami tidak sanggup dan lebih lemah melakukan hal itu. Maka beliau bersabda: \"Sesungguhnya Allah membagi Al Qur'an menjadi tiga bagian, maka Dia menjadikan QUL HUWALLAHU AHAD (surat Al Ikhlas) sepertiga Al Qur'an.\""},"2890":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ بْنِ مُجَمِّعٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ أَنَّ أَبَا هُرَيْرَةَ كَانَ يَقُولُ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] dari [Ibrahim bin Isma'il bin Mujammi'] ia berkata; Telah mengabarkan kepadaku [Ibnu Syihab] bahwa [Humaid bin Abdurrahman] menceritakan kepadanya bahwa [Abu Hurairah] pernah berkata; QUL HUWALLAHU AHAD (surat Al Ikhlas) menyamai sepertiga Al Qur'an."},"2891":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ عَنْ سَلَّامِ بْنِ أَبِي مُطِيعٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin Asad] dari [Sallam bin Abu Muthi'] dari ['Ashim] dari [Zirr] dari [Abdullah] ia berkata; QUL HUWALLAHU AHAD (surat Al Ikhlas) menyamai sepertiga Al Qur'an. Telah menceritakan kepada kami [Amr bin 'Ashim] dari [Hammad bin Salamah] dari ['Ashim] dari [Zirr] dari [Abdullah] seperti itu."},"2892":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُبَارَكُ بْنُ فَضَالَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ أَنَّ رَجُلًا قَالَ وَاللَّهِ إِنِّي لَأُحِبُّ هَذِهِ السُّورَةَ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُبُّكَ إِيَّاهَا أَدْخَلَكَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Mubarak bin Fadlalah] telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa seseorang berkata; Demi Allah, sesungguhnya aku cinta kepada surat ini: QUL HUWALLAHU AHAD (surat Al Ikhlas). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cintamu kepadanya (surat Al Ikhlas) akan memasukkanmu ke dalam surga.\""},"2893":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ ثُلُثُ الْقُرْآنِ أَوْ تَعْدِلُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Muhammad bin Abdullah bin Muslim] dari [Muhammad bin Syihab] dari [Humaid bin Abdurrahman] dari [ibunya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang QUL HUWALLAHU AHAD (surat Al Ikhlas), beliau menjawab: \"(Kedudukannya) sepertiga Al Qur'an atau menyamainya.\""},"2894":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ هِلَالٍ عَنْ الرَّبِيعِ بْنِ خُثَيْمٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ امْرَأَةٍ مِنْ الْأَنْصَارِ عَنْ أَبِي أَيُّوبَ قَالَ أَتَاهَا فَقَالَ أَلَا تَرَيْنَ إِلَى مَا جَاءَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ رُبَّ خَيْرٍ قَدْ أَتَانَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا هُوَ قَالَ قَالَ لَنَا أَيَعْجِزُ أَحَدُكُمْ أَنْ يَقْرَأَ ثُلُثَ الْقُرْآنِ فِي لَيْلَةٍ قَالَ فَأَشْفَقْنَا أَنْ يُرِيدَنَا عَلَى أَمْرٍ نَعْجِزُ عَنْهُ فَلَمْ نَرْجِعْ إِلَيْهِ شَيْئًا حَتَّى قَالَهَا ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ أَمَا يَسْتَطِيعُ أَحَدُكُمْ أَنْ يَقْرَأَ اللَّهُ الْوَاحِدُ الصَّمَدُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Manshur] dari [Hilal] dari [Ar Rabi' bin Khutsaim] dari [Amr bin Maimun] dari [Abdurrahman bin Abu Laila] dari [seorang wanita Anshar] dari [Abu Ayyub], ia berkata; Dengan menemui wanita itu, ia berkata; Maukah engkau diperlihatkan kepada sesuatu yang dibawa oleh Rasulullah shallallahu 'alaihi wasallam? Wanita itu menjawab; Berapa banyak kebaikan yang dibawa oleh Rasulullah shallallahu 'alaihi wasallam kepada kami, apakah itu? Ia menjawab; Beliau mengatakan kepada kami: \"Apakah salah seorang dari kalian tidak sanggup membaca sepertiga Al Qur'an pada malam hari?\" Ia melanjutkan; Maka kami meminta belas kasih jika beliau menginginkan kami melakukan perintah yang kami tidak sanggup melakukannya, namun kami tidak menjawab pertanyaan itu sedikit pun hingga beliau mengatakannya sebanyak tiga kali. Kemudian beliau bersabda: \"Tidak adakah salah seorang dari kalian yang sanggup membaca QUL HUWALLAHU AHAD ALLAAHUSH SHAMMAD (surah Al Ikhlas).\""},"2895":{"ar":" حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ عَنْ نُوحِ بْنِ قَيْسٍ عَنْ مُحَمَّدٍ الْعَطَّارِ عَنْ أُمِّ كَثِيرٍ الْأَنْصَارِيَّةِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ خَمْسِينَ مَرَّةً غَفَرَ اللَّهُ لَهُ ذُنُوبَ خَمْسِينَ سَنَةً","id":"Telah menceritakan kepada kami [Nashr bin Ali] dari [Nuh bin Qais] dari [Muhammad Al 'Aththar] dari [Ummu Katsir Al Anshariyah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca QUL HUWALLAHU AHAD (surat Al Ikhlas) sebanyak lima puluh kali, niscaya Allah akan mengampuni dosanya selama lima puluh tahun.\""},"2896":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا سَمِعْنَا يَزِيدَ بْنَ أَبِي حَبِيبٍ يَقُولُ حَدَّثَنِي أَبُو عِمْرَانَ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ تَعَلَّقْتُ بِقَدَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرِئْنِي سُورَةَ هُودٍ وَسُورَةَ يُوسُفَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُقْبَةُ إِنَّكَ لَنْ تَقْرَأَ مِنْ الْقُرْآنِ سُورَةً أَحَبَّ إِلَى اللَّهِ وَلَا أَبْلَغَ عِنْدَهُ مِنْ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ قَالَ يَزِيدُ فَلَمْ يَكُنْ أَبُو عِمْرَانَ يَدَعُهَا كَانَ لَا يَزَالُ يَقْرَؤُهَا فِي صَلَاةِ الْمَغْرِبِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] dan [Ibnu Lahi'ah] keduanya berkata; Kami mendengar [Yazid bin Abu Habib] berkata; Telah menceritakan kepadaku [Abu Imran] bahwa ia mendengar [Uqbah bin Amir] berkata; Aku pernah memegang kaki Rasulullah shallallahu 'alaihi wasallam lalu aku katakan; Wahai Rasulullah, bacakan kepadaku surat Hud dan surat Yusuf. Lalu Rasulullah shallallahu 'alaihi wasallam mengatakan kepadaku; \"Wahai Uqbah, sesungguhnya engkau tidak akan pernah membaca surat dari Al Qur'an yang lebih Allah cintai dan lebih bermanfaat di sisiNya daripada QUL A'UUDZU BI RABBIL FALAQ (surat Al Falaq).\" Yazid berkata; Abu Imran tidak pernah meninggalkannya, ia selalu membacanya pada shalat Maghrib."},"2897":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ أَنَّ عُقْبَةَ بْنَ عَامِرٍ قَالَ مَشَيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي قُلْ يَا عُقْبَةُ فَقُلْتُ أَيَّ شَيْءٍ أَقُولُ قَالَ فَسَكَتَ عَنِّي ثُمَّ قَالَ يَا عُقْبَةُ قُلْ فَقُلْتُ أَيَّ شَيْءٍ أَقُولُ قَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ فَقَرَأْتُهَا حَتَّى جِئْتُ عَلَى آخِرِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ مَا سَأَلَ سَائِلٌ وَلَا اسْتَعَاذَ مُسْتَعِيذٌ بِمِثْلِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Laits] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id Al Maqburi] bahwa [Uqbah bin Amir] berkata; Aku pernah berjalan bersama Nabi shallallahu 'alaihi wasallam, lalu beliau mengatakan kepadaku: \"Bacalah, wahai Uqbah.\" Aku pun bertanya; Apa yang harus aku baca? Ia berkata; Lalu beliau diam tidak menjawabku. Kemudian beliau bersabda: \"Wahai Uqbah, bacalah.\" Aku bertanya: Apa yang harus aku baca? Beliau menjawab: \"(Bacalah) QUL A'UDZU BIRABBIL FALAQ (surat Al Falaq).\" Maka aku pun membacanya hingga akhir surat. Lalu, pada saat itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah sama permintaan orang yang meminta dan perlindungan orang yang meminta perlindungan seperti orang yang meminta dan berlindung dengan membacanya (membaca surat Al Falaq).\""},"2898":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ أَبِي خَالِدٍ عَنْ قَيْسٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ أُنْزِلَ عَلَيَّ آيَاتٌ لَمْ أَرَ أَوْ لَمْ يُرَ مِثْلَهُنَّ يَعْنِي الْمُعَوِّذَتَيْنِ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] ia adalah Ibnu Abu Khalid, dari [Qais] dari [Uqbah bin Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sungguh telah diturunkan kepadaku beberapa ayat yang aku tidak pernah melihat.\" Atau: \"Tidak pernah diperlihatkan sepertinya, yakni mu'awwidzatain.\""},"2899":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِسْطَامَ عَنْ يَحْيَى بْنِ حَمْزَةَ حَدَّثَنِي يَحْيَى بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ تَمِيمٍ الدَّارِيِّ ح وَحَدَّثَنِي عُثْمَانُ بْنُ مُسْلِمٍ عَنْ الْعَبَّاسِ بْنِ مَيْمُونٍ عَنْ تَمِيمٍ الدَّارِيِّ قَالَ مَنْ قَرَأَ عَشْرَ آيَاتٍ فِي لَيْلَةٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] dari [Yahya bin Hamzah] telah menceritakan kepadaku [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Tamim Ad Dari], diganti dengan jalur riwayat, telah menceritakan kepadaku [Utsman bin Muslim] dari [Al Abbas bin Maimun] dari [Tamim Ad Dari] berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia tidak akan dicatat termasuk golongan orang-orang yang lalai."},"2900":{"ar":" حَدَّثَنَا يَ��ْيَى بْنُ بِسْطَامَ عَنْ يَحْيَى بْنِ حَمْزَةَ حَدَّثَنِي يَحْيَى بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ تَمِيمٍ الدَّارِيِّ وَفَضَالَةَ بْنِ عُبَيْدٍ قَالَا مَنْ قَرَأَ بِعَشْرِ آيَاتٍ فِي لَيْلَةٍ كُتِبَ مِنْ الْمُصَلِّينَ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] dari [Yahya bin Hamzah] telah menceritakan kepadaku [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Tamim Ad Dari] dan [Fadlalah bin Ubaid] berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia akan dicatat termasuk golongan orang-orang yang melakukan shalat."},"2901":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ ابْنِ عُمَرَ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ بِعَشْرِ آيَاتٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Abu Uwais] dari [Musa bin Uqbah] dari [Muhammad bin Ka'b Al Qurazhi] dari [Ibnu Umar] ia berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia tidak dicatat termasuk golongan orang-orang yang lalai."},"2902":{"ar":" حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الْمُغِيرَةِ بْنِ عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ ابْنِ عُمَرَ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ بِعَشْرِ آيَاتٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Al Mughirah bin Abdullah Al Jadali] dari [Ibnu Umar] ia berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia tidak dicatat termasuk golongan orang-orang yang lalai."},"2903":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ بِخَمْسِينَ آيَةً لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Barangsiapa yang membaca lima puluh ayat pada malam hari, maka ia tidak dicatat termasuk golongan orang-orang yang lalai."},"2904":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِسْطَامَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ تَمِيمٍ الدَّارِيِّ وَفَضَالَةَ بْنِ عُبَيْدٍ قَالَا مَنْ قَرَأَ بِخَمْسِينَ آيَةً فِي لَيْلَةٍ كُتِبَ مِنْ الْحَافِظِينَ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Tamim Ad Dari] dan [Fadlalah bin Ubaid] keduanya berkata; Barangsiapa yang membaca lima puluh ayat pada malam hari, maka ia tidak dicatat termasuk golongan orang-orang yang menjaga."},"2905":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ يُحَنَّسَ مَوْلَى الزُّبَيْرِ عَنْ سَالِمٍ أَخِي أُمِّ الدَّرْدَاءِ فِي اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ بِمِائَةِ آيَةٍ فِي لَيْلَةٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ قَالَ أَبُو مُحَمَّد مِنْهُمْ مَنْ يَقُولُ مَكَانَ سَالِمٍ رَاشِدُ بْنُ سَعْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Qasim] telah menceritakan kepada kami [Musa bin Ubaidah] dari [Muhammad bin Ibrahim] dari [Yuhannas] mantan budak Az Zubair dari [Salim] saudara Ummu Ad Darda` karena Allah dari [Ummu Ad Darda`] dari [Abu Ad Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca seratus ayat pada malam hari, maka ia tidak dicatat termasuk golongan orang-orang yang lalai.\" [Abu Muhammad] berkata; Di antara mereka ada yang mengatakan; Di tempat [Salim], [Rasyid bin Sa'ad]."},"2906":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ ابْنِ عُمَرَ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ بِمِائَةِ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Abu Uwais] dari [Musa bin Uqbah] dari [Muhammad bin Ka'b Al Qurazhi] dari [Ibnu Umar] ia berkata; Barangsiapa yang membaca seratus ayat pada malam hari, maka ia dicatat termasuk golongan orang-orang yang taat."},"2907":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِسْطَامَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي زَيْدُ بْنُ وَاقِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ تَمِيمٍ الدَّارِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ بِمِائَةِ آيَةٍ فِي لَيْلَةٍ كُتِبَ لَهُ قُنُوتُ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepadaku [Zaid bin Waqid] dari [Sulaiman bin Musa] dari [Katsir bin Murrah] dari [Tamim Ad Dari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca seratus ayat pada malam hari, maka dicatat baginya ketaatan sepanjang malam.\""},"2908":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ قَالَ قَالَ كَعْبٌ مَنْ قَرَأَ مِائَةَ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Al A'masy] dari [Abu Shalih] ia berkata; [Ka'ab] berkata; Barangsiapa yang membaca seratus ayat, maka ia dicatat termasuk golongan orang-orang yang taat."},"2909":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِسْطَامَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي يَحْيَى بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ تَمِيمٍ الدَّارِيِّ وَفَضَالَةَ بْنِ عُبَيْدٍ قَالَا مَنْ قَرَأَ بِمِائَةِ آيَةٍ فِي لَيْلَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepadaku [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Tamim Ad Dari] dan [Fadlalah bin Ubaid] keduanya berkata; Barangsiapa yang membaca seratus ayat pada malam hari, maka ia dicatat termasuk golongan orang-orang yang taat."},"2910":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ بِمِائَةِ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Barangsiapa yang membaca seratus ayat, maka ia dicatat termasuk golongan orang-orang yang taat."},"2911":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ حَبِيبِ بْنِ عُبَيْدٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُ مَنْ قَرَأَ بِمِائَةِ آيَةٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Hariz bin Utsman] dari [Habib bin Ubaid] ia berkata; Aku mendengar [Abu Umamah] berkata; Barangsiapa yang membaca seratus ayat, maka ia tidak dicatat termasuk golongan orang-orang yang lalai."},"2912":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا حَرِيزٌ عَنْ حَبِيبِ بْنِ عُبَيْدٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُ مَنْ قَرَأَ مِائَتَيْ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Hariz] dari [Habib bin Ubaid] ia berkata; Aku mendengar [Abu Umamah] berkata; Barangsiapa yang membaca dua ratus ayat, maka ia dicatat termasuk golongan orang-orang yang taat."},"2913":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ يُحَنَّسَ مَوْلَى الزُّبَيْرِ عَنْ سَالِمٍ أَخِي أُمِّ الدَّرْدَاءِ فِي اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ مِائَتَيْ آيَةٍ فِي لَيْلَةٍ كُتِبَ مِنْ الْقَانِتِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Qasim] telah menceritakan kepada kami [Musa bin Ubaidah] dari [Muhammad bin Ibrahim] dari [Yuhannas] mantan budak Az Zubair dari [Salim] saudara Ummu Ad Darda` karena Allah, dari [Ummu Ad Darda`] dari [Abu Ad Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca dua ratus ayat pada malam hari, maka ia dicatat termasuk golongan orang-orang yang taat.\""},"2914":{"ar":" حَدَّثَنَا أَبُو غَسَّانَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الْمُغِيرَةِ بْنِ عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ ابْنِ عُمَرَ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ عَشْرَ آيَاتٍ لَمْ يُكْتَبْ مِنْ الْغَافِلِينَ وَمَنْ قَرَأَ فِي لَيْلَةٍ بِمِائَةِ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ وَمَنْ قَرَأَ بِمِائَتَيْ آيَةٍ كُتِبَ مِنْ الْفَائِزِينَ","id":"Telah menceritakan kepada kami [Abu Ghassan] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Al Mughirah bin Abdullah Al Jadali] dari [Ibnu Umar] ia berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia tidak dicatat termasuk orang-orang yang lalai. Dan barangsiapa membaca dua ratus ayat, maka ia dicatat termasuk orang-orang yang beruntung."},"2915":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ عَشْرَ آيَاتٍ كُتِبَ مِنْ الذَّاكِرِينَ وَمَنْ قَرَأَ بِمِائَةِ آيَةٍ كُتِبَ مِنْ الْقَانِتِينَ وَمَنْ قَرَأَ بِخَمْسِ مِائَةِ آيَةٍ إِلَى الْأَلْفِ أَصْبَحَ وَلَهُ قِنْطَارٌ مِنْ الْأَجْرِ قِيلَ وَمَا الْقِنْطَارُ قَالَ مِلْءُ مَسْكِ الثَّوْرِ ذَهَبًا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Sa'id Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id Al Hudri] ia berkata; Barangsiapa yang membaca sepuluh ayat pada malam hari, maka ia tidak dicatat termasuk orang-orang yang berdzikir, dan barangsiapa yang membaca seratus ayat, maka ia dicatat termasuk orang-orang yang taat, serta barangsiapa yang membaca lima ratus sampai seribu ayat maka pagi harinya ia akan mendapatkan satu qinthar pahala. Ditanyakan; Berapa satu qinthar itu? Ia menjawab; Emas sepenuh (wadah sebesar) kulit sapi jantan."},"2916":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ عَنْ يُونُسَ عَنْ الْحَسَنِ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ مِائَةَ آيَةٍ لَمْ يُحَاجَّهُ الْقُرْآنُ تِلْكَ اللَّيْلَةَ وَمَنْ قَرَأَ فِي لَيْلَةٍ مِائَتَيْ آيَةٍ كُتِبَ لَهُ قُنُوتُ لَيْلَةٍ وَمَنْ قَرَأَ فِي لَيْلَةٍ خَمْسَ مِائَةِ آيَةٍ إِلَى الْأَلْفِ أَصْبَحَ وَلَهُ قِنْطَارٌ فِي الْآخِرَةِ قَالُوا وَمَا الْقِنْطَارُ قَالَ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Wuhaib] dari [Yunus] dari [Al Hasan] bahwa Nabiyullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca seratus ayat pada malam hari, maka Al Qur'an tidak mencelanya pada malam itu, dan barangsiapa yang membaca dua ratus ayat pada malam hari maka dicatat baginya ketaatan sepanjang malam, serta barangsiapa yang membaca lima ratus sampai seribu ayat pada malam hari maka pagi harinya ia akan mendapatkan satu qinthar di akhirat.\" Mereka bertanya; Berapa satu qinthar itu? Beliau menjawab: \"Dua belas ribu.\""},"2917":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ فِي لَيْلَةٍ ثَلَاثَ مِائَةِ آيَةٍ كُتِبَ لَهُ قِنْطَارٌ وَمَنْ قَرَأَ سَبْعَ مِائَةِ آيَةٍ لَا أَدْرِي أَيَّ شَيْءٍ قَالَ فِيهَا أَبُو نُعَيْمٍ بِقَوْلِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Barangsiapa yang membaca tiga ratus ayat pada malam hari maka dicatat baginya satu qinthar. Sedangkan tentang (perkataan); Barangsiapa yang membaca tujuh ratus ayat, maka aku tidak tahu apa yang dikatakan oleh [Abu Nu'aim] tentangnya."},"2918":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا حَرِيزٌ عَنْ حَبِيبِ بْنِ عُبَيْدٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُ مَنْ قَرَأَ أَلْفَ آيَةٍ كُتِبَ لَهُ قِنْطَارٌ مِنْ الْأَجْرِ وَالْقِيرَاطُ مِنْ ذَلِكَ الْقِنْطَارِ لَا يَفِي بِهِ دُنْيَاكُمْ يَقُولُ لَا يَعْدِلُهُ دُنْيَاكُمْ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Hariz] dari [Habib bin Ubaid] ia berkata; Aku mendengar [Abu Umamah] berkata; Barangsiapa yang membaca seribu ayat maka dicatat baginya satu qinthar pahala, dan qirath dari qinthar itu tidak dapat ditebus oleh dunia kalian. Ia berkata; Tidak dapat disamai oleh dunia kalian."},"2919":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِسْطَامَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ تَمِيمٍ الدَّارِيِّ وَفَضَالَةَ بْنِ عُبَيْدٍ قَالَا مَنْ قَرَأَ أَلْفَ آيَةٍ فِي لَيْلَةٍ كُتِبَ لَهُ قِنْطَارٌ وَالْقِيرَاطُ مِنْ الْقِنْطَارِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاكْتَنَزَ مِنْ الْأَجْرِ مَا شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Bistham] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Tamim Ad Dari] dan [Fadlalah bin Ubaid] keduanya berkata; Barangsiapa yang membaca seribu ayat pada malam hari maka dicatat baginya satu qinthar, sedangkan satu qirath dari qinthar tersebut lebih baik dari dunia dan seisinya, serta akan mendapat pahala yang disimpan sesuai dengan apa yang dikehendaki oleh Allah."},"2920":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ يُحَنَّسَ مَوْلَى الزُّبَيْرِ عَنْ سَالِمٍ أَخِي أُمِّ الدَّرْدَاءِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ أَلْفَ آيَةٍ إِلَى خَمْسِ مِائَةٍ كُتِبَ لَهُ قِنْطَارٌ مِنْ الْأَجْرِ الْقِيرَاطُ مِنْهُ مِثْلُ التَّلِّ الْعَظِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Qasim] telah menceritakan kepada kami [Musa bin Ubaidah] dari [Muhammad bin Ibrahim] dari [Yuhannas] mantan budak Az Zubair, dari [Salim] saudara Ummu Ad Darda`, dari [Ummu Ad Darda`] dari [Abu Ad Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca lima ratus sampai seribu ayat maka dicatat baginya satu qinthar pahala. Satu qirath dari qinthar tersebut seperti sebuah bukit yang besar.\""},"2921":{"ar":" حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبَانُ الْعَطَّارُ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ الْقِنْطَارُ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [Aban Al 'Aththar] dan [Hammad bin Salamah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Satu qinthar adalah dua belas ribu."},"2922":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ أَبِي الْأَشْهَبِ عَنْ أَبِي نَضْرَةَ الْعَبْدِيِّ قَالَ الْقِنْطَارُ مِلْءُ مَسْكِ ثَوْرٍ ذَهَبًا","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Abu Al Asyhab] dari [Abu Nadlrah Al 'Abdi] ia berkata; Satu qinthar seperti emas sepenuh (wadah sebesar) kulit sapi jantan."},"2923":{"ar":" حَدَّثَنَا إِسْحَقُ عَنْ هُشَيْمٍ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ الْقِنْطَارُ أَرْبَعُونَ أَلْفًا","id":"Telah menceritakan kepada kami [Ishaq] dari [Husyaim] dari [Ali bin Zaid] dari [Sa'id bin Al Musayyab] ia berkata; Satu qinthar adalah empat puluh ribu."},"2924":{"ar":" حَدَّثَنَا إِسْحَقُ عَنْ مُبَارَكٍ عَنْ الْحَسَنِ قَالَ الْقِنْطَارُ دِيَةُ أَحَدِكُمْ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Ishaq] dari [Mubarak] dari [Al Hasan] ia berkata; Satu qinthar adalah diyat salah seorang dari kalian, yakni dua belas ribu."},"2925":{"ar":" حَدَّثَنَا إِسْحَقُ عَنْ مُسْلِمٍ هُوَ الزَّنْجِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ الْقِنْطَارُ سَبْعُونَ أَلْفَ دِينَارٍ","id":"Telah menceritakan kepada kami [Ishaq] dari [Muslim] ia adalah Az Zanji, dari [Ibnu Abu Najih] dari [Mujahid] ia berkata; Satu qinthar adalah tujuh puluh ribu dinar."},"2926":{"ar":" حَدَّثَنَا إِسْحَقُ عَنْ أَبِي بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ الْقِنْطَارُ أَلْفُ أُوقِيَّةٍ وَمِائَتَا أُوقِيَّةٍ","id":"Telah menceritakan kepada kami [Ishaq] dari [Abu Bakr] dari [Abu Hashin] dari [Salim bin Abu Al Ja'd] dari [Mu'adz bin Jabal] ia berkata; Satu qinthar adalah seribu dua ratus uqiyah. "},"2927":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ قَالَ الْقِنْطَارُ سَبْعُونَ أَلْفَ مِثْقَالٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Laits] dari [Mujahid] ia berkata; Satu qinthar adalah tujuh puluh ribu mitsqal. "},"2928":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا صَالِحٌ الْمُرِّيُّ عَنْ قَتَادَةَ قَالَ كَانَ رَجُلٌ يَقْرَأُ فِي مَسْجِدِ الْمَدِينَةِ وَكَانَ ابْنُ عَبَّاسٍ قَدْ وَضَعَ عَلَيْهِ الرَّصَدَ فَإِذَا كَانَ يَوْمُ خَتْمِهِ قَامَ فَتَحَوَّلَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Shalih Al Murri] dari [Qatadah] ia berkata; Ada seseorang yang membaca Al Qur'an di dalam masjid Madinah. Ketika itu [Ibnu Abbas] menempatkan seseorang untuk mengawasinya. Tatkala hari pengkhataman tiba, ia berdiri lalu berada bersamanya."},"2929":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا صَالِحٌ عَنْ ثَابِتٍ الْبُنَانِيِّ قَالَ كَانَ أَنَسُ بْنُ مَالِكٍ إِذَا أَشْفَى عَلَى خَتْمِ الْقُرْآنِ بِاللَّيْلِ بَقَّى مِنْهُ شَيْئًا حَتَّى يُصْبِحَ فَيَجْمَعَ أَهْلَهُ فَيَخْتِمَهُ مَعَهُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Shalih] dari [Tsabit Al Bunani] ia berkata; Apabila [Anas bin Malik] hampir mengkhatamkan Al Qur'an di malam hari, ia menyisakan sedikit dari Al Qur'an hingga waktu pagi. Lalu ia mengumpulkan keluarganya, kemudian ia mengkhatamkan Al Qur'an bersama mereka."},"2930":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدَةَ قَالَ إِذَا خَتَمَ الرَّجُلُ الْقُرْآنَ بِنَهَارٍ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُمْسِيَ وَإِنْ فَرَغَ مِنْهُ لَيْلًا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Abdah] ia berkata; Apabila seseorang mengkhatamkan Al Qur'an pada siang hari maka para malaikat bershalawat untuknya hingga waktu sore dan jika ia menyelesaikan bacaan Al Qur'an pada malam hari maka para malaikat bershalawat untuknya hingga waktu pagi."},"2931":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ صَالِحٍ الْمُرِّيِّ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْعَمَلِ أَفْضَلُ قَالَ الْحَالُّ الْمُرْتَحِلُ قِيلَ وَمَا الْحَالُّ الْمُرْتَحِلُ قَالَ صَاحِبُ الْقُرْآنِ يَضْرِبُ مِنْ أَوَّلِ الْقُرْآنِ إِلَى آخِرِهِ وَمِنْ آخِرِهِ إِلَى أَوَّلِهِ كُلَّمَا حَلَّ ارْتَحَلَ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Shalih Al Murri] dari [Qatadah] dari [Zurarah bin Aufa] bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya; Amalan apa yang paling utama? Beliau menjawab: \"Al Haallu Al Murtahil.\" Ditanyakan; Apa maksud Al Haallu Al Murtahil? Beliau menjawab: \"Pembaca Al Qur'an yang membaca (mengkhatamkan) dari awal Al Qur'an sampai akhir dan dari akhir Al Qur'an sampai awalnya, setiap kali selesai (pengkhatamannya), ia langsung pergi.\""},"2932":{"ar":" حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ جَرِيرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ إِذَا قَرَأَ الرَّجُلُ الْقُرْآنَ نَهَارًا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُمْسِيَ وَإِنْ قَرَأَهُ لَيْلًا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُصْبِحَ قَالَ سُلَيْمَانُ فَرَأَيْتُ أَصْحَابَنَا يُعْجِبُهُمْ أَنْ يَخْتِمُوهُ أَوَّلَ النَّهَارِ وَأَوَّلَ اللَّيْلِ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ مِثْلَهُ إِلَّا أَنَّهُ لَيْسَ فِيهِ قَوْلُ سُلَيْمَانَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] dari [Jarir] dari [Al A'masy] dari [Ibrahim] ia berkata; Jika seseorang membaca Al Qur'an pada siang hari, maka para malaikat akan bershalawat untuknya sampai sore, jika ia membacanya di malam hari maka para malaikat akan bershalawat untuknya sampai pagi. [Sulaiman] berkata; Aku melihat para sahabat kami lebih suka mengkhatamkan Al Qur'an di awal siang dan di awal malam. Telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyabi] dari [Sufyan] dari [Al A'masy] dari [Ibrahim] seperti itu, hanya saja tidak terdapat perkataan [Sulaiman]."},"2933":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ طَلْحَةَ وَعَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ قَالَا مَنْ قَرَأَ الْقُرْآنَ لَيْلًا أَوْ نَهَارًا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ إِلَى اللَّيْلِ وَقَالَ الْآخَرُ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam] dari [Yazid bin Abdurrahman] dari [Thalhah] dan [Abdurrahman bin Al Aswad] keduanya berkata; Barangsiapa yang membaca Al Qur'an pada malam atau siang hari, maka para malaikat akan bershalawat untuknya sampai malam hari. Yang lain berkata; Maka ia diampuni."},"2934":{"ar":" حَدَّثَنَا عَمْرُو بْنُ حَمَّادٍ حَدَّثَنَا قَزَعَةُ بْنُ سُوَيْدٍ عَنْ حُمَيْدٍ الْأَعْرَجِ قَالَ مَنْ قَرَأَ الْقُرْآنَ ثُمَّ دَعَا أَمَّنَ عَلَى دُعَائِهِ أَرْبَعَةُ آلَافِ مَلَكٍ","id":"Telah menceritakan kepada kami [Amr bin Hammad] telah menceritakan kepada kami [Faza'ah bin Suwaid] dari [Humaid Al A'raj] ia berkata; Barangsiapa yang membaca Al Qur'an kemudian ia berdoa, maka doanya akan diamini oleh empat ribu malaikat."},"2935":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا هَارُونُ عَنْ عَنْبَسَةَ عَنْ لَيْثٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَ إِذَا وَافَقَ خَتْمُ الْقُرْآنِ أَوَّلَ اللَّيْلِ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُصْبِحَ وَإِنْ وَافَقَ خَتْمُهُ آخِرَ اللَّيْلِ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يُمْسِيَ فَرُبَّمَا بَقِيَ عَلَى أَحَدِنَا الشَّيْءُ فَيُؤَخِّرَهُ حَتَّى يُمْسِيَ أَوْ يُصْبِحَ قَالَ أَبُو مُحَمَّد هَذَا حَسَنٌ عَنْ سَعْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Harun] dari ['Anbasah] dari [Laits] dari [Thalhah bin Musharrif] dari [Mush'ab bin Sa'd] dari [Sa'd] ia berkata; Jika pengkhataman Al Qur'an bertepatan dengan awal malam maka para malaikat akan bershalawat untuknya sampai pagi. Dan jika pengkhatamannya bertepatan dengan akhir malam maka para malaikat akan bershalawat untuknya sampai sore. Terkadang salah seorang dari kami menyisakan sedikit dari Al Qur'an dan mengakhirkannya sampai sore atau pagi. Abu Muhammad berkata; Riwayat ini hasan dari Sa'd."},"2936":{"ar":" حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا مَعْنٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُهَاجِرِ بْنِ مِسْمَارٍ ابْنِ أَخِي بُكَيْرِ بْنِ مِسْمَارٍ حَدَّثَنِي صَفْوَانُ بْنُ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ قَالَ حَمَلَةُ الْقُرْآنِ عُرَفَاءُ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Ma'n] telah menceritakan kepada kami [Ibrahim bin Muhajir bin Mismar] ia adalah anak saudaraku Bukair bin Mismar, telah menceritakan kepadaku [Shafwan bin Sulaim] dari ['Atha` bin Yasar] ia berkata; Para penghafal Al Qur'an akan menjadi pengatur perkara dan kemaslahatan penduduk surga."},"2937":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ كَانَ يَخْتِمُ الْقُرْآنَ كُلَّ لَيْلَتَيْنِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik] dari [Sa'id bin Jubair] bahwa ia selalu mengkhatamkan Al Qur'an setiap dua malam."},"2938":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ ابْنِ أَبِي نَهِيكٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ لَمْ يَتَغَنَّ بِالْقُرْآنِ قَالَ أَبُو مُحَمَّد النَّاسُ يَقُولُونَ عُبَيْدُ اللَّهِ بْنُ أَبِي نَهِيكٍ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepada kami [Ibnu Abu Mulaikah] dari [Ibnu Abu Nahik] dari [Sa'd bin Abu Waqqash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak termasuk golongan kami orang yang tidak melantunkan Al Qur'an dengan suara indah.\" Abu Muhammad berkata; Orang-orang mengatakan; Ubaidullah bin Nahik."},"2939":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ كَانَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْذَنْ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ و قَالَ صَاحِبٌ لَهُ زَادَ يَجْهَرُ بِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah menceritakan kepadaku [Abu Salamah] dari [Abu Hurairah], bahwa ia pernah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak pernah mengizinkan sesuatu seperti Dia mengizinkan kepada Nabi untuk melantunkan Al Qur'an dengan suara yang indah.\" Ada seorang sahabat beliau menambahkan: \"Dan mengeraskan bacaan Al Qur'an.\""},"2940":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَ مَا أَذِنَ اللَّهُ لِشَيْءٍ كَمَا أَذِنَ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepada kami [Abu Salamah] bahwa [Abu Hurairah] ia berkata; Allah tidak mengizinkan sesuatu seperti Dia mengizinkan Nabi untuk melantunkan Al Qur'an dengan suara yang indah."},"2941":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لِأَبِي مُوسَى وَكَانَ حَسَنَ الصَّوْتِ بِالْقُرْآنِ لَقَدْ أُوتِيَ هَذَا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada [Abu Musa], ia adalah seorang yang bagus suaranya saat membaca Al Qur'an: \"Sungguh, orang ini telah diberi suara seperti (suara) seruling dari seruling-seruling keluarga Dawud.\" "},"2942":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِبْرَاهِيمُ الْهَجَرِيُّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَضَعُ إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى يَتَغَنَّى وَيَدَعُ أَنْ يَقْرَأَ سُورَةَ الْبَقَرَةِ فَإِنَّ الشَّيْطَانَ يَفِرُّ مِنْ الْبَيْتِ يُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ وَإِنَّ أَصْفَرَ الْبُيُوتِ الْجَوْفُ يَصْفَرُ مِنْ كِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Ibrahim Al Hajari] dari [Abu Al Ahwash] dari [Abdullah] berkata; Sungguh, aku tidak akan menemui salah seorang dari kalian yang meletakkan salah satu kaki di atas kaki lainnya sambil melantunkan Al Qur'an namun ia meninggalkan membaca surat Al Baqarah, karena sesungguhnya setan akan lari dari rumah yang dibacakan surat Al Baqarah di dalamnya. Dan sesungguhnya rumah yang paling kosong adalah rumah yang kosong dari (bacaan) kitab Allah."},"2943":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ حَدَّثَنِي بَعْضُ آلِ سَالِمِ بْنِ عَبْدِ اللَّهِ قَالَ قَدِمَ سَلَمَةُ الْبَيْذَقُ الْمَدِينَةَ فَقَامَ يُصَلِّي بِهِمْ فَقِيلَ لِسَالِمٍ لَوْ جِئْتَ فَسَمِعْتَ قِرَاءَتَهُ فَلَمَّا كَانَ بِبَابِ الْمَسْجِدِ سَمِعَ قِرَاءَتَهُ رَجَعَ فَقَالَ غِنَاءٌ غِنَاءٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] ia berkata; Telah menceritakan kepadaku [sebagian keluarga Salim bin Abdullah] berkata; Salamah Al Baidzaq datang ke Madinah, lalu ia berdiri melakukan shalat bersama mereka. Maka dikatakan kepada [Salim]; Seandainya engkau datang maka engkau akan mendengarkan bacaannya? Ketika berada di pintu masjid, ia mendengar bacaannya, ia pun langsung kembali seraya berkata; Ini adalah nyanyian, ini adalah nyanyian."},"2944":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَذِنَ اللَّهُ لِشَيْءٍ كَأَذَنِهِ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad] ia adalah Ibnu Amr, dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak mengizinkan sesuatu seperti izinNya kepada Nabi untuk melantunkan Al Qur'an dengan suara yang indah sambil mengeraskan bacaannya.\""},"2945":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ أُوتِيَ أَبُو مُوسَى مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah menceritakan kepada kami [Utsman bin Umar] dari [Malik bin Mighwal] dari [Ibnu Buraidah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh, Abu Musa telah diberi suara seperti seruling dari seruling-seruling keluarga Dawud.\" "},"2946":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَ قِرَاءَةَ رَجُلٍ فَقَالَ مَنْ هَذَا قِيلَ عَبْدُ اللَّهِ بْنُ قَيْسٍ قَالَ لَقَدْ أُوتِيَ هَذَا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam masuk, beliau mendengar bacaan seorang laki-laki. Beliau pun bertanya: \"Siapa orang ini?\" Dikatakan; Abdullah bin Qais. Beliau bersabda: \"Sungguh, orang ini telah diberi suara seperti seruling dari seruling-seruling keluarga Dawud.\" "},"2947":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا صَدَقَةُ بْنُ أَبِي عِمْرَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ زَاذَانَ أَبِي عُمَرَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حَسِّنُوا الْقُرْآنَ بِأَصْوَاتِكُمْ فَإِنَّ الصَّوْتَ الْحَسَنَ يَزِيدُ الْقُرْآنَ حُسْنًا","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] telah menceritakan kepada kami [Shadaqah bin Abu Imran] dari ['Alqamah bin Martsad] dari [Zadzan Abu Umar] dari [Al Bara` bin 'Azib] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Baguskanlah Al Qur'an dengan suara-suara kalian, sesungguhnya suara yang indah dapat menambah keindahan Al Qur'an.\""},"2948":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ إِدْرِيسَ عَنْ الْأَعْمَشِ قَالَ قَرَأَ رَجُلٌ عِنْدَ أَنَسٍ بِلَحْنٍ مِنْ هَذِهِ الْأَلْحَانِ فَكَرِهَ ذَلِكَ أَنَسٌ قَالَ أَبُو مُحَمَّد و قَالَ غَيْرُهُ قَرَأَ غُورَكُ بْنُ أَبِي الْخِضْرِمِ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] dari [Abdullah bin Idris] dari [Al A'masy] ia berkata; Suatu ketika ada seseorang membaca Al Qur'an di samping [Anas] dengan salah satu dari lahn ini, lalu Anas membenci hal itu. Abu Muhammad dan yang lainnya berkata; Yang membaca adalah Ghaurak bin Abu Al Khidlrim. "},"2949":{"ar":" حَدَّثَنَا الْعَبَّاسُ بْنُ سُفْيَانَ عَنْ ابْنِ عُلَيَّةَ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ كَانُوا يَرَوْنَ هَذِهِ الْأَلْحَانَ فِي الْقُرْآنِ مُحْدَثَةً","id":"Telah menceritakan kepada kami [Al Abbas bin Sufyan] dari [Abu 'Ullayah] dari [Ibnu Aun] dari [Muhammad] berkata; mereka berpendapat bahwa lahn yang dilakukan pada alqur'an adalah sesuatu yang baru. "}};
